    // --- Brush Studio Preview Canvas ---
    let brushStudioPreviewCanvas = null;

    function renderBrushStudioPreview() {
        if (!brushStudioPreviewCanvas) {
            // Create preview canvas if it doesn't exist
            brushStudioPreviewCanvas = document.createElement('canvas');
            brushStudioPreviewCanvas.className = 'brush-studio-preview';
            brushStudioPreviewCanvas.width = 200;
            brushStudioPreviewCanvas.height = 80;
            // Insert after the brush studio sliders
            const studioPanel = document.getElementById('brush-studio-panel') || brushSpacingSlider?.closest('.panel, div');
            if (studioPanel) {
                const lastRow = studioPanel.querySelector('[style*="margin-bottom"]') || studioPanel.lastElementChild;
                if (lastRow) lastRow.parentNode.insertBefore(brushStudioPreviewCanvas, lastRow.nextSibling);
                else studioPanel.appendChild(brushStudioPreviewCanvas);
            }
        }

        const ctx = brushStudioPreviewCanvas.getContext('2d');
        const w = 200, h = 80;
        ctx.clearRect(0, 0, w, h);
        ctx.fillStyle = '#1a1a1a';
        ctx.fillRect(0, 0, w, h);

        const s = brushStudio[currentBrush];
        const size = Math.min(brushSize, 20);
        const spacing = Math.max(1, s.spacing);
        const scatter = s.scatter;
        const jitter = s.jitter;
        const rotation = s.rotation;

        ctx.fillStyle = brushColor;
        ctx.globalAlpha = brushOpacity;

        // Draw a sample stroke with current settings
        let x = 10;
        const y = h / 2;
        let angle = 0;
        while (x < w - 10) {
            // Jitter
            const jx = (Math.random() - 0.5) * jitter * 0.5;
            const jy = (Math.random() - 0.5) * jitter * 0.5;
            // Scatter
            const sx = (Math.random() - 0.5) * scatter * 0.3;
            const sy = (Math.random() - 0.5) * scatter * 0.3;
            // Rotation
            if (rotation > 0) angle += rotation * 0.05;

            ctx.save();
            ctx.translate(x + jx + sx, y + jy + sy);
            ctx.rotate(angle * Math.PI / 180);

            // Draw brush dot
            if (currentBrush === 'calligraphy') {
                ctx.beginPath();
                ctx.ellipse(0, 0, size * 0.5, size * 0.15, 0, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.beginPath();
                ctx.arc(0, 0, size * 0.5, 0, Math.PI * 2);
                ctx.fill();
            }
            ctx.restore();

            x += spacing * size * 0.1 + size * 0.3;
        }
        ctx.globalAlpha = 1;
    }

