    const pressureCurvePoints = [[0, 0], [128, 128], [255, 255]]; // identity

    const brushTextureFile = document.getElementById('brush-texture-file');
    const brushTextureName = document.getElementById('brush-texture-name');
    const brushTextureIntensitySlider = document.getElementById('brush-texture-intensity');
    const brushTextureScaleSlider = document.getElementById('brush-texture-scale');
