    // --- Vanishing Point Dragging on Guide Overlay ---
    guidesOverlay.addEventListener('pointerdown', (e) => {
        if (currentGuide !== 'perspective-1' && currentGuide !== 'perspective-2') return;
        const rect = guidesOverlay.getBoundingClientRect();
        const mx = (e.clientX - rect.left) * (logicalWidth / rect.width);
        const my = (e.clientY - rect.top) * (logicalHeight / rect.height);
        draggingVP = -1;
        vanishingPoints.forEach((vp, i) => {
            const dx = mx - vp.x, dy = my - vp.y;
            if (Math.sqrt(dx * dx + dy * dy) < 15) draggingVP = i;
        });
        if (draggingVP >= 0) {
            e.preventDefault();
            guidesOverlay.setPointerCapture(e.pointerId);
        }
    });
    guidesOverlay.addEventListener('pointermove', (e) => {
        if (draggingVP < 0) return;
        const rect = guidesOverlay.getBoundingClientRect();
        const mx = (e.clientX - rect.left) * (logicalWidth / rect.width);
        const my = (e.clientY - rect.top) * (logicalHeight / rect.height);
        vanishingPoints[draggingVP].x = Math.max(0, Math.min(logicalWidth, mx));
        vanishingPoints[draggingVP].y = Math.max(0, Math.min(logicalHeight, my));
        drawGuidesOverlay();
    });

