    // --- Magic Wand Tool ---
    const btnMagicWand = document.getElementById('btn-magic-wand');
    const magicWandTolSlider = document.getElementById('magic-wand-tolerance');
    const magicWandTolVal = document.getElementById('magic-wand-tol-val');

    function magicWandSelect(x, y, tolerance) {
        const layer = getActiveLayer();
        if (!layer) return;
        const dprLocal = window.devicePixelRatio || 1;
        const w = layer.canvas.width;
        const h = layer.canvas.height;
        const sx = Math.floor(x * dprLocal);
        const sy = Math.floor(y * dprLocal);
        if (sx < 0 || sx >= w || sy < 0 || sy >= h) return;

        const ctx = layer.ctx;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const imageData = ctx.getImageData(0, 0, w, h);
        ctx.restore();
        const data = imageData.data;

        const startIdx = (sy * w + sx) * 4;
        const startR = data[startIdx];
        const startG = data[startIdx + 1];
        const startB = data[startIdx + 2];
        const startA = data[startIdx + 3];

        const tol = tolerance * tolerance * 3;
        const visited = new Uint8Array(w * h);
        const maskCanvas = document.createElement('canvas');
        maskCanvas.width = w;
        maskCanvas.height = h;
        const maskCtx = maskCanvas.getContext('2d');
        const maskData = maskCtx.createImageData(w, h);
        const md = maskData.data;

        const stack = [[sx, sy]];
        while (stack.length > 0) {
            const [cx, cy] = stack.pop();
            const pi = cy * w + cx;
            if (cx < 0 || cx >= w || cy < 0 || cy >= h) continue;
            if (visited[pi]) continue;
            const idx = pi * 4;
            const dr = data[idx] - startR;
            const dg = data[idx + 1] - startG;
            const db = data[idx + 2] - startB;
            const da = data[idx + 3] - startA;
            if ((dr * dr + dg * dg + db * db + da * da) > tol) continue;

            visited[pi] = 1;
            md[idx] = 255;
            md[idx + 1] = 255;
            md[idx + 2] = 255;
            md[idx + 3] = 255;

            stack.push([cx + 1, cy], [cx - 1, cy], [cx, cy + 1], [cx, cy - 1]);
        }

        maskCtx.putImageData(maskData, 0, 0);

        // Compute bounding box from mask
        let minX = w, minY = h, maxX = 0, maxY = 0;
        let found = false;
        for (let my = 0; my < h; my++) {
            for (let mx = 0; mx < w; mx++) {
                if (visited[my * w + mx]) {
                    if (mx < minX) minX = mx;
                    if (mx > maxX) maxX = mx;
                    if (my < minY) minY = my;
                    if (my > maxY) maxY = my;
                    found = true;
                }
            }
        }
        if (!found) return;

        selectionRect = {
            x: minX / dprLocal,
            y: minY / dprLocal,
            w: (maxX - minX + 1) / dprLocal,
            h: (maxY - minY + 1) / dprLocal
        };

        selectionData = document.createElement('canvas');
        selectionData.width = w;
        selectionData.height = h;
        selectionData.getContext('2d').drawImage(maskCanvas, 0, 0);

        selectionActive = true;
        selectionType = 'freeform';
        selectionFeatherSlider.value = 0;
        selectionFeatherVal.textContent = '0';
        drawSelectionOverlay();
        drawTransformOverlay();
    }

