    // --- NEW: Text Tool ---
    const btnText = document.getElementById('btn-text');
    const textPanel = document.getElementById('text-panel');
    const textInput = document.getElementById('text-input');
    const textFontSelect = document.getElementById('text-font-select');
    const textSizeSlider = document.getElementById('text-size-slider');
    const textSizeLabel = document.getElementById('text-size-label');
    const btnTextBold = document.getElementById('btn-text-bold');
    const btnTextItalic = document.getElementById('btn-text-italic');
    const btnTextUnderline = document.getElementById('btn-text-underline');
    const btnTextAlignLeft = document.getElementById('btn-text-align-left');
    const btnTextAlignCenter = document.getElementById('btn-text-align-center');
    const btnTextAlignRight = document.getElementById('btn-text-align-right');
    const btnTextConfirm = document.getElementById('btn-text-confirm');
    const btnTextCancel = document.getElementById('btn-text-cancel');
    const textLetterSpacingSlider = document.getElementById('text-letter-spacing');
    const textLetterSpacingLabel = document.getElementById('text-letter-spacing-label');
    const textLineHeightSlider = document.getElementById('text-line-height');
    const textLineHeightLabel = document.getElementById('text-line-height-label');

    function enterTextMode() {
        textMode = true;
        currentMode = 'text';
        textContent = '';
        textPosition = { x: logicalWidth / 2, y: logicalHeight / 2 };
        textPanel.classList.remove('hidden');
        textInput.value = '';
        textInput.focus();
        updateActiveTool(btnText);
        scheduleCompositeRender();
    }

    function exitTextMode() {
        textMode = false;
        currentMode = 'brush';
        textPanel.classList.add('hidden');
        textContent = '';
        scheduleCompositeRender();
    }

    function getFontString() {
        let style = '';
        if (textItalic) style += 'italic ';
        if (textBold) style += 'bold ';
        return `${style}${textSize}px ${textFont}`;
    }

    function renderTextPreview() {
        if (!textMode || !textContent) { scheduleCompositeRender(); return; }
        renderComposite();
        const ctx = compositeCtx;
        ctx.save();
        ctx.font = getFontString();
        ctx.fillStyle = brushColor;
        ctx.textBaseline = 'middle';
        const lines = textContent.split('\n');
        const lineHeight = textSize * textLineHeight;
        const totalHeight = lines.length * lineHeight;
        let startY = textPosition.y - totalHeight / 2 + lineHeight / 2;

        // Calculate max line width for justify
        let maxLineWidth = 0;
        if (textParagraphAlign === 'justify') {
            lines.forEach(line => {
                let w = 0;
                for (let ci = 0; ci < line.length; ci++) {
                    w += ctx.measureText(line[ci]).width;
                    if (ci < line.length - 1) w += textLetterSpacing + textKerning;
                }
                if (w > maxLineWidth) maxLineWidth = w;
            });
        }

        lines.forEach((line, i) => {
            const y = startY + i * lineHeight;
            const isLastLine = i === lines.length - 1;
            const useJustify = textParagraphAlign === 'justify' && !isLastLine && line.length > 1;

            if (useJustify || textLetterSpacing > 0 || textKerning !== 0) {
                // Draw each character with letter spacing and kerning
                const chars = line.split('');
                let totalWidth = 0;
                const charWidths = chars.map(ch => ctx.measureText(ch).width);
                for (let ci = 0; ci < chars.length; ci++) {
                    totalWidth += charWidths[ci];
                    if (ci < chars.length - 1) totalWidth += textLetterSpacing + textKerning;
                }

                let cx = textPosition.x;
                if (textParagraphAlign === 'center' || useJustify) cx -= totalWidth / 2;
                else if (textParagraphAlign === 'right') cx -= totalWidth;

                // Calculate extra spacing for justify
                let extraSpacing = 0;
                if (useJustify && maxLineWidth > 0) {
                    extraSpacing = (maxLineWidth - totalWidth) / (chars.length - 1 || 1);
                }

                chars.forEach((ch, ci) => {
                    ctx.fillText(ch, cx, y);
                    cx += charWidths[ci] + textLetterSpacing + textKerning + extraSpacing;
                });
            } else {
                ctx.textAlign = textParagraphAlign === 'center' ? 'center' : textParagraphAlign === 'right' ? 'right' : 'left';
                let drawX = textPosition.x;
                ctx.fillText(line, drawX, y);
                ctx.textAlign = 'left';
            }
            if (textUnderline) {
                let uw = 0;
                for (let ci = 0; ci < line.length; ci++) {
                    uw += ctx.measureText(line[ci]).width;
                    if (ci < line.length - 1) uw += textLetterSpacing + textKerning;
                }
                let ux = textPosition.x;
                if (textParagraphAlign === 'center') ux -= uw / 2;
                else if (textParagraphAlign === 'right') ux -= uw;
                ctx.beginPath();
                ctx.moveTo(ux, y + textSize * 0.15);
                ctx.lineTo(ux + uw, y + textSize * 0.15);
                ctx.strokeStyle = brushColor;
                ctx.lineWidth = Math.max(1, textSize / 30);
                ctx.stroke();
            }
        });
        ctx.restore();
    }

    function rasterizeText() {
        if (!textContent) { exitTextMode(); return; }
        const layer = getActiveLayer();
        if (!layer || !layer.visible) { exitTextMode(); return; }
        // If re-editing a text layer, clear old text pixels first
        if (layer.textData) {
            layer.ctx.save();
            layer.ctx.setTransform(1, 0, 0, 1, 0, 0);
            layer.ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
            layer.ctx.restore();
        }
        layer.ctx.save();
        layer.ctx.font = getFontString();
        layer.ctx.fillStyle = brushColor;
        layer.ctx.textAlign = textAlign === 'left' ? 'start' : textAlign === 'right' ? 'end' : 'center';
        layer.ctx.textBaseline = 'middle';
        const lines = textContent.split('\n');
        const lineHeight = textSize * textLineHeight;
        const totalHeight = lines.length * lineHeight;
        let startY = textPosition.y - totalHeight / 2 + lineHeight / 2;
        lines.forEach((line, i) => {
            const y = startY + i * lineHeight;
            if (textLetterSpacing > 0 && line.length > 0) {
                const chars = line.split('');
                let totalWidth = 0;
                const charWidths = chars.map(ch => { const w = layer.ctx.measureText(ch).width; totalWidth += w; return w; });
                totalWidth += textLetterSpacing * (chars.length - 1);
                let cx = textPosition.x;
                if (textAlign === 'center') cx -= totalWidth / 2;
                else if (textAlign === 'right') cx -= totalWidth;
                chars.forEach((ch, ci) => {
                    layer.ctx.fillText(ch, cx, y);
                    cx += charWidths[ci] + textLetterSpacing;
                });
            } else {
                layer.ctx.fillText(line, textPosition.x, y);
            }
            if (textUnderline) {
                const metrics = layer.ctx.measureText(line);
                let ux = textPosition.x;
                const lineW = textLetterSpacing > 0 ? metrics.width + textLetterSpacing * (line.length - 1) : metrics.width;
                if (textAlign === 'center') ux -= lineW / 2;
                else if (textAlign === 'right') ux -= lineW;
                layer.ctx.beginPath();
                layer.ctx.moveTo(ux, y + textSize * 0.15);
                layer.ctx.lineTo(ux + lineW, y + textSize * 0.15);
                layer.ctx.strokeStyle = brushColor;
                layer.ctx.lineWidth = Math.max(1, textSize / 30);
                layer.ctx.stroke();
            }
        });
        layer.ctx.restore();
        layer.textData = {
            content: textContent,
            font: textFont,
            size: textSize,
            bold: textBold,
            italic: textItalic,
            underline: textUnderline,
            align: textAlign,
            color: brushColor,
            position: { ...textPosition },
            letterSpacing: textLetterSpacing,
            lineHeight: textLineHeight
        };
        saveState();
        exitTextMode();
    }

    function editTextLayer(layer) {
        if (!layer || !layer.textData) return;
        textMode = true;
        currentMode = 'text';
        const td = layer.textData;
        textContent = td.content;
        textFont = td.font;
        textSize = td.size;
        textBold = td.bold;
        textItalic = td.italic;
        textUnderline = td.underline;
        textAlign = td.align;
        textPosition = { ...td.position };
        brushColor = td.color;
        textLetterSpacing = td.letterSpacing || 0;
        textLineHeight = td.lineHeight || 1.2;
        textInput.value = td.content;
        textFontSelect.value = td.font;
        textSizeSlider.value = td.size;
        textSizeLabel.textContent = td.size + 'px';
        btnTextBold.classList.toggle('active', td.bold);
        btnTextItalic.classList.toggle('active', td.italic);
        btnTextUnderline.classList.toggle('active', td.underline);
        btnTextAlignLeft.classList.toggle('active', td.align === 'left');
        btnTextAlignCenter.classList.toggle('active', td.align === 'center');
        btnTextAlignRight.classList.toggle('active', td.align === 'right');
        textLetterSpacingSlider.value = textLetterSpacing;
        textLetterSpacingLabel.textContent = textLetterSpacing;
        textLineHeightSlider.value = Math.round(textLineHeight * 10);
        textLineHeightLabel.textContent = textLineHeight.toFixed(1);
        colorIndicator.style.backgroundColor = td.color;
        colorPreviewSwatch.style.backgroundColor = td.color;
        hexInput.value = td.color;
        textPanel.classList.remove('hidden');
        updateActiveTool(btnText);
        renderTextPreview();
    }

