    // --- Text to Vector SVG ---
    let vectorMode = false;
    let vectorSvgElement = null;
    let vectorDragOffset = { x: 0, y: 0 };
    let vectorPosition = { x: 0, y: 0 };
    const btnTextToVector = document.getElementById('btn-text-to-vector');

    function textToVectorSVG() {
        if (!textContent) return;
        const lines = textContent.split('\n');
        const lineHeight = textSize * textLineHeight;
        let svgContent = '';
        lines.forEach((line, i) => {
            if (!line) return;
            const y = (i + 1) * textSize;
            svgContent += `<text x="0" y="${y}" font-family="${textFont}" font-size="${textSize}" fill="none" stroke="${brushColor}" stroke-width="${Math.max(1, textSize / 30)}" ${textBold ? 'font-weight="bold"' : ''} ${textItalic ? 'font-style="italic"' : ''} letter-spacing="${textLetterSpacing}">${line.replace(/&/g, '&amp;').replace(/</g, '&lt;')}</text>`;
        });
        const totalHeight = lines.length * lineHeight;
        const svgStr = `<svg xmlns="http://www.w3.org/2000/svg" width="800" height="${Math.ceil(totalHeight) + textSize}" viewBox="0 0 800 ${Math.ceil(totalHeight) + textSize}"><g transform="translate(400,${textSize})" text-anchor="middle">${svgContent}</g></svg>`;
        const blob = new Blob([svgStr], { type: 'image/svg+xml' });
        const url = URL.createObjectURL(blob);
        vectorPosition = { x: textPosition.x - 400, y: textPosition.y - textSize };
        if (vectorSvgElement) vectorSvgElement.remove();
        vectorSvgElement = document.createElement('img');
        vectorSvgElement.src = url;
        vectorSvgElement.style.cssText = `position:absolute;pointer-events:all;cursor:move;border:1px dashed var(--accent-color);z-index:100;`;
        vectorSvgElement.style.left = (transform.x + vectorPosition.x * transform.scale) + 'px';
        vectorSvgElement.style.top = (transform.y + vectorPosition.y * transform.scale) + 'px';
        vectorSvgElement.style.width = (800 * transform.scale) + 'px';
        vectorSvgElement.style.height = (Math.ceil(totalHeight) + textSize) * transform.scale + 'px';
        document.getElementById('workspace').appendChild(vectorSvgElement);
        vectorMode = true;
        vectorSvgElement.onpointerdown = (e) => {
            e.stopPropagation();
            vectorDragOffset.x = e.clientX - vectorSvgElement.offsetLeft;
            vectorDragOffset.y = e.clientY - vectorSvgElement.offsetTop;
            vectorSvgElement.setPointerCapture(e.pointerId);
        };
        vectorSvgElement.onpointermove = (e) => {
            if (e.buttons === 0) return;
            vectorSvgElement.style.left = (e.clientX - vectorDragOffset.x) + 'px';
            vectorSvgElement.style.top = (e.clientY - vectorDragOffset.y) + 'px';
        };
        vectorSvgElement.ondblclick = () => rasterizeVectorToLayer();
    }

    function rasterizeVectorToLayer() {
        if (!vectorSvgElement) return;
        const layer = getActiveLayer();
        if (!layer) return;
        const img = new Image();
        img.onload = () => {
            const vw = parseFloat(vectorSvgElement.style.width);
            const vh = parseFloat(vectorSvgElement.style.height);
            const vx = (vectorSvgElement.offsetLeft - transform.x) / transform.scale;
            const vy = (vectorSvgElement.offsetTop - transform.y) / transform.scale;
            layer.ctx.save();
            layer.ctx.setTransform(1, 0, 0, 1, 0, 0);
            layer.ctx.drawImage(img, vx * dpr, vy * dpr, vw * dpr, vh * dpr);
            layer.ctx.restore();
            saveState();
            cancelVectorMode();
            compositeDirty = true;
            renderComposite();
        };
        img.src = vectorSvgElement.src;
    }

    function cancelVectorMode() {
        if (vectorSvgElement) { vectorSvgElement.remove(); vectorSvgElement = null; }
        vectorMode = false;
    }

    if (btnTextToVector) {
        btnTextToVector.addEventListener('click', textToVectorSVG);
    }

