    // --- Layer Groups ---
    let layerGroups = []; // [{id, name, collapsed, parentId}]
    let layerGroupIdCounter = 0;

    function createGroup(name) {
        const group = { id: `group-${layerGroupIdCounter++}`, name: name || `Grupo ${layerGroups.length + 1}`, collapsed: false, parentId: null };
        layerGroups.push(group);
        renderLayersUI();
        return group;
    }

    function addLayerToGroup(layerIdx, groupId) {
        if (!layers[layerIdx]) return;
        layers[layerIdx].groupId = groupId;
        renderLayersUI();
    }

    function toggleGroupCollapse(groupId) {
        const g = layerGroups.find(gr => gr.id === groupId);
        if (g) { g.collapsed = !g.collapsed; renderLayersUI(); }
    }

    function deleteGroup(groupId) {
        layers.forEach(l => { if (l.groupId === groupId) l.groupId = null; });
        layerGroups = layerGroups.filter(g => g.id !== groupId);
        renderLayersUI();
    }

    // --- Non-Destructive Layer Masks ---
    function addLayerMask() {
        const layer = getActiveLayer();
        if (!layer) return;
        if (layer.nonDestructiveMask) return; // already has one
        const maskCanvas = document.createElement('canvas');
        maskCanvas.width = layer.canvas.width;
        maskCanvas.height = layer.canvas.height;
        const maskCtx = maskCanvas.getContext('2d');
        maskCtx.fillStyle = 'white';
        maskCtx.fillRect(0, 0, maskCanvas.width, maskCanvas.height);
        layer.nonDestructiveMask = { canvas: maskCanvas, ctx: maskCtx, visible: true };
        renderLayersUI();
        compositeDirty = true;
        renderComposite();
    }

    function toggleLayerMaskVisibility() {
        const layer = getActiveLayer();
        if (!layer || !layer.nonDestructiveMask) return;
        layer.nonDestructiveMask.visible = !layer.nonDestructiveMask.visible;
        compositeDirty = true;
        renderComposite();
    }

    function deleteLayerMask() {
        const layer = getActiveLayer();
        if (!layer) return;
        layer.nonDestructiveMask = null;
        compositeDirty = true;
        renderComposite();
        renderLayersUI();
    }

    // --- Fill Layers ---
    const fillLayerTypes = { solid: 'Sólido', gradient: 'Degradado', pattern: 'Patrón' };

    function addFillLayer(type, options) {
        if (layers.length >= MAX_LAYERS) { alert('Límite de capas alcanzado'); return; }
        const { canvas, ctx } = createLayerEl();
        const fillLayer = {
            id: `layer-${layerIdCounter++}`,
            name: `Relleno ${fillLayerTypes[type] || type}`,
            canvas, ctx, visible: true,
            opacity: 1, alphaLock: false, blendMode: 'source-over',
            maskData: null, clippingMask: false,
            effects: JSON.parse(JSON.stringify(defaultEffects)),
            isFillLayer: true,
            fillType: type,
            fillOptions: options || { color: brushColor, gradientStops: [brushColor, '#ffffff'], patternType: 'checker', patternScale: 20 }
        };
        renderFillLayer(fillLayer);
        layers.push(fillLayer);
        activeLayerIndex = layers.length - 1;
        renderLayersUI();
        compositeDirty = true;
        renderComposite();
    }

    function renderFillLayer(layer) {
        if (!layer.isFillLayer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const ctx = layer.ctx;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        ctx.clearRect(0, 0, w, h);
        const opts = layer.fillOptions;
        if (layer.fillType === 'solid') {
            ctx.fillStyle = opts.color || '#808080';
            ctx.fillRect(0, 0, w, h);
        } else if (layer.fillType === 'gradient') {
            const grad = ctx.createLinearGradient(0, 0, w, h);
            (opts.gradientStops || ['#000000', '#ffffff']).forEach((c, i) => grad.addColorStop(i / ((opts.gradientStops || []).length - 1 || 1), c));
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, w, h);
        } else if (layer.fillType === 'pattern') {
            const fn = patterns[opts.patternType] || patterns.checker;
            const scale = opts.patternScale || 20;
            const imgData = ctx.createImageData(w, h);
            const d = imgData.data;
            const rgb = hexToRgb(opts.color || '#808080');
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    const v = fn(x, y, scale);
                    const i = (y * w + x) * 4;
                    d[i] = Math.round(rgb.r * v / 255);
                    d[i + 1] = Math.round(rgb.g * v / 255);
                    d[i + 2] = Math.round(rgb.b * v / 255);
                    d[i + 3] = 255;
                }
            }
            ctx.putImageData(imgData, 0, 0);
        }
        ctx.restore();
    }

    // --- Perspective Correction ---
    let perspCorrectActive = false, perspCorrectCorners = null;

    function enterPerspectiveCorrection() {
        const layer = getActiveLayer();
        if (!layer || !layer.visible) return;
        perspCorrectActive = true;
        const w = logicalWidth, h = logicalHeight;
        perspCorrectCorners = [
            { x: 0, y: 0 }, { x: w, y: 0 },
            { x: w, y: h }, { x: 0, y: h }
        ];
    }

    function applyPerspectiveCorrection() {
        if (!perspCorrectActive || !perspCorrectCorners) return;
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        const dst = layer.ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const [tl, tr, br, bl] = perspCorrectCorners;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const u = x / w, v = y / h;
                const sx = (1 - v) * ((1 - u) * tl.x + u * tr.x) + v * ((1 - u) * bl.x + u * br.x);
                const sy = (1 - v) * ((1 - u) * tl.y + u * tr.y) + v * ((1 - u) * bl.y + u * br.y);
                const si = (Math.round(sy) * w + Math.round(sx)) * 4;
                const di = (y * w + x) * 4;
                if (si >= 0 && si < sd.length - 3) {
                    dd[di] = sd[si]; dd[di + 1] = sd[si + 1]; dd[di + 2] = sd[si + 2]; dd[di + 3] = sd[si + 3];
                }
            }
        }
        layer.ctx.putImageData(dst, 0, 0);
        perspCorrectActive = false;
        perspCorrectCorners = null;
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- Content-Autofill ---
    function contentAutofill() {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Simple approach: for each transparent pixel, sample nearby opaque pixels
        const result = new Uint8ClampedArray(d);
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                if (d[i + 3] > 128) continue; // already opaque
                let r = 0, g = 0, b = 0, count = 0;
                for (let r2 = 1; r2 <= 10; r2++) {
                    let found = false;
                    for (let dy = -r2; dy <= r2 && !found; dy++) {
                        for (let dx = -r2; dx <= r2 && !found; dx++) {
                            if (Math.abs(dx) !== r2 && Math.abs(dy) !== r2) continue;
                            const nx = x + dx, ny = y + dy;
                            if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                                const ni = (ny * w + nx) * 4;
                                if (d[ni + 3] > 128) {
                                    r += d[ni]; g += d[ni + 1]; b += d[ni + 2]; count++;
                                    found = true;
                                }
                            }
                        }
                    }
                    if (count > 0) break;
                }
                if (count > 0) {
                    result[i] = r / count; result[i + 1] = g / count; result[i + 2] = b / count; result[i + 3] = 255;
                }
            }
        }
        const outData = new ImageData(result, w, h);
        layer.ctx.putImageData(outData, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- Clone Source Selection ---
    let cloneSourceLayer = null, cloneSourcePos = { x: 0, y: 0 };

    function setCloneSource() {
        const layer = getActiveLayer();
        if (!layer) return;
        cloneSourceLayer = layer;
        cloneSourcePos = { x: logicalWidth / 2, y: logicalHeight / 2 };
        showToast('Fuente de clonación establecida en el centro de la capa activa');
    }

    // --- Expanded Blending Modes ---
    const blendModeMap = {
        'source-over': 'Normal',
        'multiply': 'Multiply',
        'screen': 'Screen',
        'overlay': 'Overlay',
        'color-dodge': 'Color Dodge',
        'color-burn': 'Color Burn',
        'hard-light': 'Hard Light',
        'soft-light': 'Soft Light',
        'difference': 'Difference',
        'exclusion': 'Exclusion',
        'hue': 'Hue',
        'saturation': 'Saturation',
        'color': 'Color',
        'luminosity': 'Luminosity',
        'hard-mix': 'Hard Mix',
        'linear-dodge': 'Linear Dodge',
        'linear-burn': 'Linear Burn',
        'divide': 'Divide'
    };

    // Canvas2D doesn't support all modes natively, apply custom ones via pixel math
    function applyBlendModeCustom(baseCtx, topCanvas, mode, opacity) {
        if (mode === 'hard-mix' || mode === 'linear-dodge' || mode === 'linear-burn' || mode === 'divide') {
            const w = baseCtx.canvas.width, h = baseCtx.canvas.height;
            const baseData = baseCtx.getImageData(0, 0, w, h);
            const topData = topCanvas.getContext('2d').getImageData(0, 0, w, h);
            const bd = baseData.data, td = topData.data;
            for (let i = 0; i < bd.length; i += 4) {
                if (td[i + 3] === 0) continue;
                const t = td[i + 3] / 255 * opacity;
                for (let c = 0; c < 3; c++) {
                    let base = bd[i + c] / 255, top = td[i + c] / 255;
                    let result = base;
                    if (mode === 'hard-mix') result = (base + top) >= 1 ? 1 : 0;
                    else if (mode === 'linear-dodge') result = Math.min(1, base + top);
                    else if (mode === 'linear-burn') result = Math.max(0, base + top - 1);
                    else if (mode === 'divide') result = top === 0 ? 1 : Math.min(1, base / top);
                    bd[i + c] = Math.round((bd[i + c] / 255 * (1 - t) + result * t) * 255);
                }
            }
            baseCtx.putImageData(baseData, 0, 0);
        } else {
            baseCtx.save();
            baseCtx.globalAlpha = opacity;
            baseCtx.globalCompositeOperation = mode;
            baseCtx.drawImage(topCanvas, 0, 0);
            baseCtx.restore();
        }
    }

    // --- Blend If ---
    function applyBlendIf(layer, underLayer, blendIf) {
        if (!blendIf || !layer || !underLayer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const topData = layer.ctx.getImageData(0, 0, w, h);
        const underData = underLayer.ctx.getImageData(0, 0, w, h);
        const td = topData.data, ud = underData.data;
        const { underLow = 0, underHigh = 255, selfLow = 0, selfHigh = 255 } = blendIf;
        for (let i = 0; i < td.length; i += 4) {
            if (td[i + 3] === 0) continue;
            const underLum = (ud[i] * 0.299 + ud[i + 1] * 0.587 + ud[i + 2] * 0.114);
            const selfLum = (td[i] * 0.299 + td[i + 1] * 0.587 + td[i + 2] * 0.114);
            if (underLum < underLow || underLum > underHigh || selfLum < selfLow || selfLum > selfHigh) {
                td[i + 3] = 0;
            }
        }
        layer.ctx.putImageData(topData, 0, 0);
    }

    // --- HDR/EXR Export ---
    function exportHDR() {
        const w = logicalWidth * dpr, h = logicalHeight * dpr;
        const exportCanvas = document.createElement('canvas');
        exportCanvas.width = w; exportCanvas.height = h;
        const exportCtx = exportCanvas.getContext('2d');
        exportCtx.fillStyle = '#000';
        exportCtx.fillRect(0, 0, w, h);
        layers.forEach(layer => {
            if (layer.visible) {
                exportCtx.save();
                exportCtx.globalAlpha = layer.opacity;
                exportCtx.globalCompositeOperation = layer.blendMode;
                exportCtx.drawImage(layer.canvas, 0, 0);
                exportCtx.restore();
            }
        });
        // Export as 16-bit PNG (closest to HDR in browser)
        const link = document.createElement('a');
        link.download = `procreate-lite-hdr-${Date.now()}.png`;
        link.href = exportCanvas.toDataURL('image/png');
        link.click();
    }

    // --- Export Presets ---
    const exportPresets = {
        instagram: { w: 1080, h: 1080, name: 'Instagram Square' },
        instagram_story: { w: 1080, h: 1920, name: 'Instagram Story' },
        twitter: { w: 1200, h: 675, name: 'Twitter Post' },
        twitter_header: { w: 1500, h: 500, name: 'Twitter Header' },
        facebook: { w: 1200, h: 630, name: 'Facebook Post' },
        youtube: { w: 1280, h: 720, name: 'YouTube Thumbnail' },
        wallpaper_4k: { w: 3840, h: 2160, name: 'Wallpaper 4K' },
        wallpaper_1080: { w: 1920, h: 1080, name: 'Wallpaper 1080p' }
    };

    function exportWithPreset(presetKey) {
        const preset = exportPresets[presetKey];
        if (!preset) return;
        const exportCanvas = document.createElement('canvas');
        exportCanvas.width = preset.w; exportCanvas.height = preset.h;
        const exportCtx = exportCanvas.getContext('2d');
        exportCtx.fillStyle = '#ffffff';
        exportCtx.fillRect(0, 0, preset.w, preset.h);
        const scaleX = preset.w / logicalWidth, scaleY = preset.h / logicalHeight;
        const scale = Math.min(scaleX, scaleY);
        const ox = (preset.w - logicalWidth * scale) / 2;
        const oy = (preset.h - logicalHeight * scale) / 2;
        exportCtx.save();
        exportCtx.translate(ox, oy);
        exportCtx.scale(scale, scale);
        layers.forEach(layer => {
            if (layer.visible) {
                exportCtx.save();
                exportCtx.globalAlpha = layer.opacity;
                exportCtx.globalCompositeOperation = layer.blendMode;
                exportCtx.drawImage(layer.canvas, 0, 0);
                exportCtx.restore();
            }
        });
        exportCtx.restore();
        const link = document.createElement('a');
        link.download = `procreate-lite-${presetKey}-${Date.now()}.png`;
        link.href = exportCanvas.toDataURL('image/png');
        link.click();
    }

    // --- GIF Export from Animation Timeline ---
    function exportGIF() {
        if (animFrames.length === 0) { alert('No hay cuadros para exportar'); return; }
        const w = logicalWidth, h = logicalHeight;
        // Use canvas to render each frame and build GIF data
        // Simple GIF encoder (uncompressed, for demonstration)
        const frames = [];
        animFrames.forEach(frame => {
            const fc = document.createElement('canvas');
            fc.width = w; fc.height = h;
            const fctx = fc.getContext('2d');
            fctx.fillStyle = '#fff';
            fctx.fillRect(0, 0, w, h);
            frame.layers.forEach(fl => {
                if (fl.visible) fctx.drawImage(fl.canvas, 0, 0);
            });
            frames.push(fctx.getImageData(0, 0, w, h).data);
        });
        // Build minimal GIF89a
        const delay = Math.round(100 / animFPS);
        let gif = 'GIF89a';
        // Logical Screen Descriptor
        gif += String.fromCharCode(w & 0xff, (w >> 8) & 0xff, h & 0xff, (h >> 8) & 0xff);
        gif += String.fromCharCode(0xf7, 0, 0); // GCT flag, 256 colors
        // Global Color Table (256 colors from first frame quantized)
        const gct = new Uint8Array(768);
        for (let i = 0; i < 256; i++) { gct[i * 3] = i; gct[i * 3 + 1] = i; gct[i * 3 + 2] = i; }
        for (let i = 0; i < 768; i++) gif += String.fromCharCode(gct[i]);
        // Netscape extension for looping
        gif += String.fromCharCode(0x21, 0xff, 0x0b);
        gif += 'NETSCAPE2.0';
        gif += String.fromCharCode(0x03, 0x01, 0x00, 0x00);
        // Frames
        frames.forEach(frameData => {
            gif += String.fromCharCode(0x21, 0xf9, 0x04, 0x00);
            gif += String.fromCharCode(delay & 0xff, (delay >> 8) & 0xff);
            gif += String.fromCharCode(0x00, 0x00);
            gif += String.fromCharCode(0x2c);
            gif += String.fromCharCode(0, 0, 0, 0, w & 0xff, (w >> 8) & 0xff, h & 0xff, (h >> 8) & 0xff);
            gif += String.fromCharCode(0x00);
            // LZW minimum code size
            const minCodeSize = 8;
            gif += String.fromCharCode(minCodeSize);
            // Simple LZW output (uncompressed sub-blocks)
            const pixels = [];
            for (let i = 0; i < frameData.length; i += 4) {
                const v = Math.round(frameData[i] * 0.299 + frameData[i + 1] * 0.587 + frameData[i + 2] * 0.114);
                pixels.push(Math.min(255, v));
            }
            // Write as sub-blocks (uncompressed: clear + literals + EOI per row)
            let pos = 0;
            while (pos < pixels.length) {
                const blockSize = Math.min(255, pixels.length - pos);
                gif += String.fromCharCode(blockSize);
                for (let i = 0; i < blockSize; i++) gif += String.fromCharCode(pixels[pos++]);
            }
            gif += String.fromCharCode(0x00);
        });
        gif += String.fromCharCode(0x3b);
        // Download
        const bytes = new Uint8Array(gif.length);
        for (let i = 0; i < gif.length; i++) bytes[i] = gif.charCodeAt(i);
        const blob = new Blob([bytes], { type: 'image/gif' });
        const link = document.createElement('a');
        link.download = `procreate-lite-${Date.now()}.gif`;
        link.href = URL.createObjectURL(blob);
        link.click();
        URL.revokeObjectURL(link.href);
    }

    // --- AI Background Removal (edge-detection based) ---
    function aiBackgroundRemoval() {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Sample border pixels to determine background color
        let rSum = 0, gSum = 0, bSum = 0, count = 0;
        for (let x = 0; x < w; x++) {
            for (const y of [0, h - 1]) {
                const i = (y * w + x) * 4;
                rSum += d[i]; gSum += d[i + 1]; bSum += d[i + 2]; count++;
            }
        }
        for (let y = 0; y < h; y++) {
            for (const x of [0, w - 1]) {
                const i = (y * w + x) * 4;
                rSum += d[i]; gSum += d[i + 1]; bSum += d[i + 2]; count++;
            }
        }
        const bgR = rSum / count, bgG = gSum / count, bgB = bSum / count;
        // Remove pixels similar to background
        for (let i = 0; i < d.length; i += 4) {
            const dr = d[i] - bgR, dg = d[i + 1] - bgG, db = d[i + 2] - bgB;
            const dist = Math.sqrt(dr * dr + dg * dg + db * db);
            if (dist < 60) d[i + 3] = 0;
        }
        layer.ctx.putImageData(imgData, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- AI Super Resolution (bilinear upscale) ---
    function aiSuperResolution(scaleFactor) {
        const layer = getActiveLayer();
        if (!layer) return;
        const sw = layer.canvas.width, sh = layer.canvas.height;
        const nw = sw * scaleFactor, nh = sh * scaleFactor;
        const src = layer.ctx.getImageData(0, 0, sw, sh);
        const dst = new ImageData(nw, nh);
        const sd = src.data, dd = dst.data;
        for (let y = 0; y < nh; y++) {
            for (let x = 0; x < nw; x++) {
                const sx = (x / nw) * sw, sy = (y / nh) * sh;
                const x0 = Math.floor(sx), y0 = Math.floor(sy);
                const x1 = Math.min(x0 + 1, sw - 1), y1 = Math.min(y0 + 1, sh - 1);
                const fx = sx - x0, fy = sy - y0;
                for (let c = 0; c < 4; c++) {
                    const v00 = sd[(y0 * sw + x0) * 4 + c];
                    const v10 = sd[(y0 * sw + x1) * 4 + c];
                    const v01 = sd[(y1 * sw + x0) * 4 + c];
                    const v11 = sd[(y1 * sw + x1) * 4 + c];
                    dd[(y * nw + x) * 4 + c] = Math.round(v00 * (1 - fx) * (1 - fy) + v10 * fx * (1 - fy) + v01 * (1 - fx) * fy + v11 * fx * fy);
                }
            }
        }
        layer.canvas.width = nw; layer.canvas.height = nh;
        layer.ctx.putImageData(dst, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- Color Palette Generator ---
    function generateColorPalette() {
        const layer = getActiveLayer();
        if (!layer) return [];
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // K-means-like clustering (simple 8-bucket approach)
        const buckets = new Array(8).fill(null).map(() => ({ r: 0, g: 0, b: 0, count: 0 }));
        for (let i = 0; i < d.length; i += 16) { // sample every 4th pixel
            if (d[i + 3] < 128) continue;
            const idx = Math.min(7, Math.floor((d[i] + d[i + 1] + d[i + 2]) / 96));
            buckets[idx].r += d[i]; buckets[idx].g += d[i + 1]; buckets[idx].b += d[i + 2]; buckets[idx].count++;
        }
        const palette = buckets
            .filter(b => b.count > 0)
            .map(b => {
                const r = Math.round(b.r / b.count), g = Math.round(b.g / b.count), bl = Math.round(b.b / b.count);
                return '#' + [r, g, bl].map(c => c.toString(16).padStart(2, '0')).join('');
            })
            .slice(0, 8);
        return palette;
    }

    // --- Tiled Rendering ---
    const TILE_SIZE = 256;

    function renderCompositeTiled() {
        if (!compositeCtx) return;
        const w = compositeCanvas.width, h = compositeCanvas.height;
        compositeCtx.save();
        compositeCtx.setTransform(1, 0, 0, 1, 0, 0);
        compositeCtx.clearRect(0, 0, w, h);
        compositeCtx.fillStyle = '#ffffff';
        compositeCtx.fillRect(0, 0, w, h);
        // Render tiles sequentially
        for (let ty = 0; ty < h; ty += TILE_SIZE) {
            for (let tx = 0; tx < w; tx += TILE_SIZE) {
                const tw = Math.min(TILE_SIZE, w - tx);
                const th = Math.min(TILE_SIZE, h - ty);
                renderTile(compositeCtx, tx, ty, tw, th);
            }
        }
        compositeCtx.restore();
        compositeDirty = false;
    }

    function renderTile(ctx, tx, ty, tw, th) {
        layers.forEach(layer => {
            if (!layer.visible) return;
            ctx.save();
            ctx.beginPath();
            ctx.rect(tx, ty, tw, th);
            ctx.clip();
            ctx.globalAlpha = layer.opacity;
            ctx.globalCompositeOperation = layer.blendMode;
            ctx.drawImage(layer.canvas, 0, 0);
            ctx.restore();
        });
    }

    // --- Progressive Rendering ---
    let progressivePhase = 0;
    let progressiveTimer = null;

    function renderCompositeProgressive() {
        if (progressiveTimer) clearInterval(progressiveTimer);
        progressivePhase = 0;
        progressiveTimer = setInterval(() => {
            progressivePhase++;
            if (progressivePhase === 1) {
                // Phase 1: Low-res preview
                const tempCanvas = document.createElement('canvas');
                tempCanvas.width = logicalWidth / 4;
                tempCanvas.height = logicalHeight / 4;
                const tctx = tempCanvas.getContext('2d');
                tctx.fillStyle = '#fff';
                tctx.fillRect(0, 0, tempCanvas.width, tempCanvas.height);
                layers.forEach(layer => {
                    if (layer.visible) {
                        tctx.save();
                        tctx.globalAlpha = layer.opacity;
                        tctx.drawImage(layer.canvas, 0, 0, logicalWidth, logicalHeight, 0, 0, tempCanvas.width, tempCanvas.height);
                        tctx.restore();
                    }
                });
                compositeCtx.save();
                compositeCtx.setTransform(1, 0, 0, 1, 0, 0);
                compositeCtx.clearRect(0, 0, compositeCanvas.width, compositeCanvas.height);
                compositeCtx.imageSmoothingEnabled = false;
                compositeCtx.drawImage(tempCanvas, 0, 0, compositeCanvas.width, compositeCanvas.height);
                compositeCtx.imageSmoothingEnabled = true;
                compositeCtx.restore();
            } else if (progressivePhase >= 2) {
                // Phase 2: Full resolution
                clearInterval(progressiveTimer);
                progressiveTimer = null;
                renderComposite();
            }
        }, 16);
    }

