    // --- Text with Outline/Stroke ---
    let textStrokeEnabled = false, textStrokeWidth = 2, textStrokeColor = '#000000';

    function renderTextWithStroke(ctx, text, x, y, font, fill, stroke, strokeWidth) {
        ctx.font = font;
        if (stroke && strokeWidth > 0) {
            ctx.strokeStyle = stroke;
            ctx.lineWidth = strokeWidth;
            ctx.lineJoin = 'round';
            ctx.strokeText(text, x, y);
        }
        ctx.fillStyle = fill;
        ctx.fillText(text, x, y);
    }

// --- Text on Path ---
     let textOnPathEnabled = false;

     function renderTextOnPath(ctx, text, pathPoints, font, color, size) {
        if (pathPoints.length < 2 || !text) return;
        ctx.font = `${size}px ${font}`;
        ctx.fillStyle = color;
        ctx.textBaseline = 'middle';
        // Calculate total path length
        let totalLen = 0;
        for (let i = 1; i < pathPoints.length; i++) {
            const dx = pathPoints[i].x - pathPoints[i - 1].x;
            const dy = pathPoints[i].y - pathPoints[i - 1].y;
            totalLen += Math.sqrt(dx * dx + dy * dy);
        }
        const charSpacing = totalLen / text.length;
        let dist = 0;
        for (let ci = 0; ci < text.length; ci++) {
            const targetDist = (ci + 0.5) * charSpacing;
            let accumulated = 0;
            for (let i = 1; i < pathPoints.length; i++) {
                const dx = pathPoints[i].x - pathPoints[i - 1].x;
                const dy = pathPoints[i].y - pathPoints[i - 1].y;
                const segLen = Math.sqrt(dx * dx + dy * dy);
                if (accumulated + segLen >= targetDist) {
                    const t = (targetDist - accumulated) / segLen;
                    const px = pathPoints[i - 1].x + dx * t;
                    const py = pathPoints[i - 1].y + dy * t;
                    const angle = Math.atan2(dy, dx);
                    ctx.save();
                    ctx.translate(px, py);
                    ctx.rotate(angle);
                    ctx.fillText(text[ci], 0, 0);
                    ctx.restore();
                    break;
                }
                accumulated += segLen;
            }
        }
    }

    // --- Vectorize Strokes ---
    function vectorizeStrokes() {
        const layer = getActiveLayer();
        if (!layer) return;
        // Convert canvas strokes to SVG path data
        const w = layer.canvas.width, h = layer.canvas.height;
        const svgData = `<svg xmlns="http://www.w3.org/2000/svg" width="${w}" height="${h}"><image href="${layer.canvas.toDataURL()}" width="${w}" height="${h}"/></svg>`;
        const blob = new Blob([svgData], { type: 'image/svg+xml' });
        const link = document.createElement('a');
        link.download = `vectorized-${Date.now()}.svg`;
        link.href = URL.createObjectURL(blob);
        link.click();
        URL.revokeObjectURL(link.href);
    }

    // --- Wet Edges ---
    function applyWetEdges(ctx, x, y, size, color, opacity) {
        ctx.save();
        ctx.globalAlpha = opacity * 0.3;
        ctx.strokeStyle = color;
        ctx.lineWidth = size * 0.15;
        ctx.beginPath();
        ctx.arc(x, y, size / 2, 0, Math.PI * 2);
        ctx.stroke();
        ctx.restore();
    }

    // --- Advanced Liquify ---
    const liquifyModes = { push: 'Push', twirl: 'Twirl', pinch: 'Pinch', bloat: 'Bloat' };
    let currentLiquifyMode = 'push';

    function applyLiquifyAdvanced(ctx, x, y, radius, strength, mode) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(Math.max(0, x - radius - 5), Math.max(0, y - radius - 5), Math.min(w, radius * 2 + 10), Math.min(h, radius * 2 + 10));
        const d = imgData.data;
        const ox = Math.max(0, x - radius - 5), oy = Math.max(0, y - radius - 5);
        for (let py = 0; py < imgData.height; py++) {
            for (let px = 0; px < imgData.width; px++) {
                const dx = (ox + px) - x, dy = (oy + py) - y;
                const dist = Math.sqrt(dx * dx + dy * dy);
                if (dist > radius || dist < 1) continue;
                const factor = (1 - dist / radius) * strength;
                let sx = px, sy = py;
                if (mode === 'push') {
                    sx = px - dx * factor * 0.1;
                    sy = py - dy * factor * 0.1;
                } else if (mode === 'twirl') {
                    const angle = factor * 0.5;
                    const cos = Math.cos(angle), sin = Math.sin(angle);
                    sx = px - (dx * cos - dy * sin - dx) * 0.1;
                    sy = py - (dx * sin + dy * cos - dy) * 0.1;
                } else if (mode === 'pinch') {
                    sx = px + dx * factor * 0.05;
                    sy = py + dy * factor * 0.05;
                } else if (mode === 'bloat') {
                    sx = px - dx * factor * 0.05;
                    sy = py - dy * factor * 0.05;
                }
                const si = (Math.round(sy) * imgData.width + Math.round(sx)) * 4;
                const di = (py * imgData.width + px) * 4;
                if (si >= 0 && si < d.length - 3 && di >= 0 && di < d.length - 3) {
                    d[di] = d[si]; d[di + 1] = d[si + 1]; d[di + 2] = d[si + 2]; d[di + 3] = d[si + 3];
                }
            }
        }
        ctx.putImageData(imgData, ox, oy);
    }

    // --- Shape Builder ---
    let shapeBuilderMode = 'add'; // 'add' or 'subtract'
    let shapeBuilderShapes = [];

    function shapeBuilderAddRect(x, y, w, h) {
        shapeBuilderShapes.push({ type: 'rect', x, y, w, h, mode: shapeBuilderMode });
    }

    function shapeBuilderRender() {
        const layer = getActiveLayer();
        if (!layer) return;
        const ctx = layer.ctx;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        shapeBuilderShapes.forEach(shape => {
            ctx.globalCompositeOperation = shape.mode === 'subtract' ? 'destination-out' : 'source-over';
            ctx.fillStyle = brushColor;
            ctx.fillRect(shape.x, shape.y, shape.w, shape.h);
        });
        ctx.restore();
        shapeBuilderShapes = [];
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- Perspective Grid Warp ---
    let perspGridActive = false, perspGridPoints = null;

    function enterPerspectiveGridWarp() {
        const w = logicalWidth, h = logicalHeight;
        perspGridActive = true;
        perspGridPoints = {
            tl: { x: 0, y: 0 }, tr: { x: w, y: 0 },
            bl: { x: 0, y: h }, br: { x: w, y: h },
            // Inner grid points (3x3)
            grid: []
        };
        for (let gy = 0; gy <= 2; gy++) {
            for (let gx = 0; gx <= 2; gx++) {
                perspGridPoints.grid.push({ x: w * gx / 2, y: h * gy / 2 });
            }
        }
    }

    function applyPerspectiveGridWarp() {
        if (!perspGridActive || !perspGridPoints) return;
        const layer = getActiveLayer();
        if (!layer) return;
        // Use the 4 corners for perspective transform
        perspCorrectCorners = [perspGridPoints.tl, perspGridPoints.tr, perspGridPoints.br, perspGridPoints.bl];
        perspCorrectActive = true;
        applyPerspectiveCorrection();
        perspGridActive = false;
        perspGridPoints = null;
    }

    // --- Radial/Zoom Blur ---
    function applyRadialBlur(ctx, cx, cy, strength) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const samples = Math.max(1, Math.round(strength / 2));
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let r = 0, g = 0, b = 0, a = 0, count = 0;
                for (let s = 0; s < samples; s++) {
                    const t = s / samples;
                    const dx = (x - cx) * t * strength * 0.01;
                    const dy = (y - cy) * t * strength * 0.01;
                    const sx = Math.round(x + dx), sy = Math.round(y + dy);
                    if (sx >= 0 && sx < w && sy >= 0 && sy < h) {
                        const i = (sy * w + sx) * 4;
                        r += sd[i]; g += sd[i + 1]; b += sd[i + 2]; a += sd[i + 3];
                        count++;
                    }
                }
                if (count > 0) {
                    const i = (y * w + x) * 4;
                    dd[i] = r / count; dd[i + 1] = g / count; dd[i + 2] = b / count; dd[i + 3] = a / count;
                }
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- Unsharp Mask ---
    function applyUnsharpMask(ctx, amount, radius) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        // Create blurred version
        const blurred = new ImageData(new Uint8ClampedArray(src.data), w, h);
        const bd = blurred.data;
        const r = Math.max(1, radius);
        for (let y = r; y < h - r; y++) {
            for (let x = r; x < w - r; x++) {
                let sum = 0, count = 0;
                for (let ky = -r; ky <= r; ky++) {
                    for (let kx = -r; kx <= r; kx++) {
                        const i = ((y + ky) * w + (x + kx)) * 4;
                        sum += (src.data[i] + src.data[i + 1] + src.data[i + 2]) / 3;
                        count++;
                    }
                }
                const i = (y * w + x) * 4;
                const avg = sum / count;
                const orig = (src.data[i] + src.data[i + 1] + src.data[i + 2]) / 3;
                const diff = (orig - avg) * amount * 0.1;
                bd[i] = Math.max(0, Math.min(255, src.data[i] + diff));
                bd[i + 1] = Math.max(0, Math.min(255, src.data[i + 1] + diff));
                bd[i + 2] = Math.max(0, Math.min(255, src.data[i + 2] + diff));
            }
        }
        ctx.putImageData(blurred, 0, 0);
    }

    // --- Halftone Effect ---
    function applyHalftone(ctx, dotSize, angle) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, w, h);
        const rad = angle * Math.PI / 180;
        const cos = Math.cos(rad), sin = Math.sin(rad);
        for (let gy = 0; gy < h; gy += dotSize * 2) {
            for (let gx = 0; gx < w; gx += dotSize * 2) {
                // Rotate grid point
                const rx = gx * cos - gy * sin;
                const ry = gx * sin + gy * cos;
                const sx = Math.round(((rx % w) + w) % w);
                const sy = Math.round(((ry % h) + h) % h);
                const i = (sy * w + sx) * 4;
                const lum = (sd[i] * 0.299 + sd[i + 1] * 0.587 + sd[i + 2] * 0.114) / 255;
                const radius = dotSize * (1 - lum) * 0.9;
                if (radius > 0.5) {
                    ctx.beginPath();
                    ctx.arc(gx, gy, radius, 0, Math.PI * 2);
                    ctx.fillStyle = `rgb(${sd[i]},${sd[i + 1]},${sd[i + 2]})`;
                    ctx.fill();
                }
            }
        }
        ctx.restore();
    }

    // --- Glitch Effects ---
    function applyGlitchRGBShift(ctx, offset) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                const rIdx = (y * w + Math.max(0, Math.min(w - 1, x - offset))) * 4;
                const bIdx = (y * w + Math.max(0, Math.min(w - 1, x + offset))) * 4;
                dd[i] = sd[rIdx]; dd[i + 1] = sd[i + 1]; dd[i + 2] = sd[bIdx + 2]; dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applyGlitchPixelSort(ctx, threshold) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let y = 0; y < h; y++) {
            let rowPixels = [];
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                const lum = (d[i] + d[i + 1] + d[i + 2]) / 3;
                if (lum > threshold) rowPixels.push({ r: d[i], g: d[i + 1], b: d[i + 2], a: d[i + 3] });
            }
            if (rowPixels.length > 2) {
                rowPixels.sort((a, b) => (a.r + a.g + a.b) - (b.r + b.g + b.b));
                let idx = 0;
                for (let x = 0; x < w; x++) {
                    const i = (y * w + x) * 4;
                    const lum = (d[i] + d[i + 1] + d[i + 2]) / 3;
                    if (lum > threshold && idx < rowPixels.length) {
                        d[i] = rowPixels[idx].r; d[i + 1] = rowPixels[idx].g; d[i + 2] = rowPixels[idx].b;
                        idx++;
                    }
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // --- Film Grain Advanced ---
    function applyFilmGrainAdvanced(ctx, intensity, size) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Generate grain pattern at lower resolution then upscale
        const gw = Math.ceil(w / size), gh = Math.ceil(h / size);
        const grain = new Float32Array(gw * gh);
        for (let i = 0; i < grain.length; i++) grain[i] = (Math.random() - 0.5) * 2;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const gx = x / size, gy = y / size;
                const x0 = Math.floor(gx), y0 = Math.floor(gy);
                const x1 = Math.min(x0 + 1, gw - 1), y1 = Math.min(y0 + 1, gh - 1);
                const fx = gx - x0, fy = gy - y0;
                const gVal = grain[y0 * gw + x0] * (1 - fx) * (1 - fy) + grain[y0 * gw + x1] * fx * (1 - fy) + grain[y1 * gw + x0] * (1 - fx) * fy + grain[y1 * gw + x1] * fx * fy;
                const i = (y * w + x) * 4;
                const n = gVal * intensity;
                d[i] = Math.max(0, Math.min(255, d[i] + n));
                d[i + 1] = Math.max(0, Math.min(255, d[i + 1] + n));
                d[i + 2] = Math.max(0, Math.min(255, d[i + 2] + n));
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // --- Batch Export ZIP ---
    async function batchExportZIP() {
        const zipParts = [];
        for (let i = 0; i < layers.length; i++) {
            const layer = layers[i];
            if (!layer.visible) continue;
            const dataUrl = layer.canvas.toDataURL('image/png');
            const base64 = dataUrl.split(',')[1];
            zipParts.push({ name: `layer-${i + 1}-${layer.name.replace(/\s+/g, '_')}.png`, data: base64 });
        }
        // Simple ZIP builder
        let zip = [0x50, 0x4b, 0x03, 0x04]; // local file headers
        let offset = 0;
        const entries = [];
        for (const part of zipParts) {
            const nameBytes = [];
            for (let i = 0; i < part.name.length; i++) nameBytes.push(part.name.charCodeAt(i));
            const data = atob(part.data);
            const dataBytes = new Uint8Array(data.length);
            for (let i = 0; i < data.length; i++) dataBytes[i] = data.charCodeAt(i);
            // CRC32
            let crc = 0xffffffff;
            for (let i = 0; i < dataBytes.length; i++) { crc ^= dataBytes[i]; for (let j = 0; j < 8; j++) crc = (crc >>> 1) ^ (crc & 1 ? 0xedb88320 : 0); }
            crc ^= 0xffffffff;
            entries.push({ name: nameBytes, compressed: dataBytes, crc, offset, size: dataBytes.length });
            offset += 30 + nameBytes.length + dataBytes.length;
        }
        // Build binary
        let bytes = [];
        for (const e of entries) {
            bytes.push(0x50, 0x4b, 0x03, 0x04, 20, 0, 0, 0, 0, 0, 0, 0, 0, 0);
            bytes.push(e.crc & 0xff, (e.crc >> 8) & 0xff, (e.crc >> 16) & 0xff, (e.crc >> 24) & 0xff);
            bytes.push(e.size & 0xff, (e.size >> 8) & 0xff, (e.size >> 16) & 0xff, (e.size >> 24) & 0xff);
            bytes.push(e.size & 0xff, (e.size >> 8) & 0xff, (e.size >> 16) & 0xff, (e.size >> 24) & 0xff);
            bytes.push(e.name.length & 0xff, (e.name.length >> 8) & 0xff);
            bytes.push(0, 0, 0, 0, 0, 0);
            bytes.push(...e.name, ...e.compressed);
        }
        const blob = new Blob([new Uint8Array(bytes)], { type: 'application/zip' });
        const link = document.createElement('a');
        link.download = `procreate-layers-${Date.now()}.zip`;
        link.href = URL.createObjectURL(blob);
        link.click();
        URL.revokeObjectURL(link.href);
    }

    // --- Version History ---
    let versionHistory = [];
    function saveVersion(name) {
        const snapshot = layers.map(l => ({
            data: l.ctx.getImageData(0, 0, l.canvas.width, l.canvas.height),
            width: l.canvas.width, height: l.canvas.height,
            name: l.name, visible: l.visible, opacity: l.opacity, blendMode: l.blendMode
        }));
        versionHistory.push({ name: name || `Version ${versionHistory.length + 1}`, timestamp: Date.now(), snapshot });
        if (versionHistory.length > 20) versionHistory.shift();
    }

    function restoreVersion(idx) {
        const ver = versionHistory[idx];
        if (!ver) return;
        while (layers.length > ver.snapshot.length) layers.pop();
        while (layers.length < ver.snapshot.length) {
            const { canvas, ctx } = createLayerEl();
            layers.push({ id: `layer-${layerIdCounter++}`, name: '', canvas, ctx, visible: true, opacity: 1, alphaLock: false, blendMode: 'source-over', maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) });
        }
        ver.snapshot.forEach((s, i) => {
            const l = layers[i];
            l.canvas.width = s.width; l.canvas.height = s.height;
            l.ctx.putImageData(s.data, 0, 0);
            l.name = s.name; l.visible = s.visible; l.opacity = s.opacity; l.blendMode = s.blendMode;
        });
        compositeDirty = true;
        renderComposite();
        renderLayersUI();
    }

    // --- Auto-Recovery ---
    function setupAutoRecovery() {
        window.addEventListener('beforeunload', () => {
            try {
                const data = layers.map(l => ({
                    data: Array.from(l.ctx.getImageData(0, 0, l.canvas.width, l.canvas.height).data),
                    width: l.canvas.width, height: l.canvas.height,
                    name: l.name, visible: l.visible, opacity: l.opacity, blendMode: l.blendMode
                }));
                localStorage.setItem('procreate-lite-recovery', JSON.stringify({ data, timestamp: Date.now() }));
            } catch (e) { logError('autoRecovery-save', e, true); }
        });
    }

    function checkAutoRecovery() {
        try {
            const saved = localStorage.getItem('procreate-lite-recovery');
            if (!saved) return null;
            const parsed = JSON.parse(saved);
            if (Date.now() - parsed.timestamp < 3600000) return parsed; // within 1 hour
            localStorage.removeItem('procreate-lite-recovery');
        } catch (e) { }
        return null;
    }

    setupAutoRecovery();

    // --- Canvas Rotation ---
    let canvasRotation = 0;
    function rotateCanvas(degrees) {
        canvasRotation = (canvasRotation + degrees) % 360;
        if (canvasContainer) {
            canvasContainer.style.transform = `rotate(${canvasRotation}deg)`;
        }
    }

    // --- Rulers and Guides ---
    let rulersVisible = false;
    let userGuides = []; // [{orientation: 'h'|'v', position: number}]

    function toggleRulers() {
        rulersVisible = !rulersVisible;
        let rulerH = document.getElementById('ruler-horizontal');
        let rulerV = document.getElementById('ruler-vertical');
        if (!rulerH) {
            rulerH = document.createElement('div');
            rulerH.id = 'ruler-horizontal';
            rulerH.style.cssText = 'position:absolute;top:0;left:30px;right:0;height:20px;background:var(--toolbar-bg);border-bottom:1px solid var(--border-color);z-index:60;overflow:hidden;';
            canvasContainer.appendChild(rulerH);
        }
        if (!rulerV) {
            rulerV = document.createElement('div');
            rulerV.id = 'ruler-vertical';
            rulerV.style.cssText = 'position:absolute;top:20px;left:0;bottom:0;width:20px;background:var(--toolbar-bg);border-right:1px solid var(--border-color);z-index:60;overflow:hidden;';
            canvasContainer.appendChild(rulerV);
        }
        rulerH.style.display = rulersVisible ? 'block' : 'none';
        rulerV.style.display = rulersVisible ? 'block' : 'none';
        if (rulersVisible) renderRulers();
    }

    function renderRulers() {
        const rulerH = document.getElementById('ruler-horizontal');
        const rulerV = document.getElementById('ruler-vertical');
        if (!rulerH || !rulerV) return;
        const hCtx = rulerH.getContext ? rulerH.getContext('2d') : null;
        // Use simple div markers instead of canvas for simplicity
        rulerH.innerHTML = '';
        rulerV.innerHTML = '';
        const w = rulerH.offsetWidth, h = rulerV.offsetHeight;
        for (let x = 0; x < w; x += 50) {
            const mark = document.createElement('div');
            mark.style.cssText = `position:absolute;left:${x}px;top:0;width:1px;height:10px;background:var(--text-color);opacity:0.5;`;
            const label = document.createElement('span');
            label.textContent = Math.round(x / transform.scale);
            label.style.cssText = 'font-size:8px;color:var(--text-color);position:absolute;left:' + (x + 2) + 'px;top:10px;';
            rulerH.appendChild(mark);
            rulerH.appendChild(label);
        }
        for (let y = 0; y < h; y += 50) {
            const mark = document.createElement('div');
            mark.style.cssText = `position:absolute;top:${y}px;left:0;height:1px;width:10px;background:var(--text-color);opacity:0.5;`;
            rulerV.appendChild(mark);
        }
    }

    // --- Color History Panel ---
    let colorHistoryList = [];
    function addToColorHistory(hex) {
        colorHistoryList = colorHistoryList.filter(c => c !== hex);
        colorHistoryList.unshift(hex);
        if (colorHistoryList.length > 20) colorHistoryList.length = 20;
    }

    // --- Non-Destructive Filters ---
    function addNonDestructiveFilter(filterType, params) {
        if (layers.length >= MAX_LAYERS) { alert('Límite de capas alcanzado'); return; }
        const { canvas, ctx } = createLayerEl();
        const filterLayer = {
            id: `layer-${layerIdCounter++}`,
            name: `Filtro: ${filterType}`,
            canvas, ctx, visible: true,
            opacity: 1, alphaLock: false, blendMode: 'source-over',
            maskData: null, clippingMask: false,
            effects: JSON.parse(JSON.stringify(defaultEffects)),
            isFilterLayer: true,
            filterType, filterParams: params || {},
            filterEnabled: true
        };
        layers.push(filterLayer);
        activeLayerIndex = layers.length - 1;
        renderLayersUI();
        compositeDirty = true;
        renderComposite();
    }

    // --- Layer Locking ---
    function toggleLayerLock(layerIdx, lockType) {
        const layer = layers[layerIdx];
        if (!layer) return;
        if (lockType === 'position') layer.positionLocked = !layer.positionLocked;
        else if (lockType === 'pixels') layer.pixelLocked = !layer.pixelLocked;
        else if (lockType === 'all') layer.allLocked = !layer.allLocked;
        renderLayersUI();
    }

    // --- Snap to Objects ---
    function snapToObjects(x, y, excludeLayerIdx) {
        const threshold = 10;
        let sx = x, sy = y;
        layers.forEach((layer, i) => {
            if (i === excludeLayerIdx || !layer.visible) return;
            // Get non-transparent bounds
            const w = layer.canvas.width, h = layer.canvas.height;
            const edges = { left: 0, right: w, top: 0, bottom: h };
            // Snap to edges
            if (Math.abs(x - edges.left) < threshold) sx = edges.left;
            if (Math.abs(x - edges.right) < threshold) sx = edges.right;
            if (Math.abs(y - edges.top) < threshold) sy = edges.top;
            if (Math.abs(y - edges.bottom) < threshold) sy = edges.bottom;
        });
        return { x: sx, y: sy };
    }

    // --- Touch Shortcuts (2/3 fingers) ---
    let touchShortcutsEnabled = true;
    let activeTouchCount = 0;
    let touchShortcutTriggered = false;

    function handleTouchShortcuts(e) {
        if (!touchShortcutsEnabled) return;
        if (e.touches) activeTouchCount = e.touches.length;
        if (activeTouchCount === 3 && !touchShortcutTriggered) {
            touchShortcutTriggered = true;
            // 3-finger tap: undo
            if (e.type === 'touchend') { undo(); touchShortcutTriggered = false; }
        } else if (activeTouchCount === 2 && !touchShortcutTriggered) {
            touchShortcutTriggered = true;
            // 2-finger tap: toggle brush/eraser
            if (e.type === 'touchend') {
                if (currentMode === 'brush') { currentMode = 'eraser'; updateActiveTool(btnEraser); }
                else { currentMode = 'brush'; updateActiveTool(btnBrush); }
                touchShortcutTriggered = false;
            }
        }
        if (e.type === 'touchend') { activeTouchCount = 0; touchShortcutTriggered = false; }
    }

    // --- Canvas Caching ---
    let layerCache = new Map();
    function getCachedComposite() {
        if (!compositeDirty && layerCache.has('composite')) return layerCache.get('composite');
        return null;
    }

    function setCompositeCache() {
        layerCache.set('composite', compositeCanvas);
    }

    // --- Memory Pooling Advanced ---
    const advancedPool = { canvases: [], imageDatas: [] };
    function getFromAdvancedPool(w, h) {
        if (advancedPool.canvases.length > 0) {
            const c = advancedPool.canvases.pop();
            if (c.width !== w || c.height !== h) { c.width = w; c.height = h; }
            return c;
        }
        const c = document.createElement('canvas');
        c.width = w; c.height = h;
        return c;
    }
    function releaseToAdvancedPool(c) { if (advancedPool.canvases.length < 20) advancedPool.canvases.push(c); }

    // --- RAF Batching ---
    let rafBatchPending = false;
    function scheduleRAFBatch(fn) {
        if (!rafBatchPending) {
            rafBatchPending = true;
            requestAnimationFrame(() => {
                rafBatchPending = false;
                fn();
            });
        }
    }

    // --- Offscreen Canvas ---
    let offscreenCanvas = null, offscreenCtx = null;
    function initOffscreenCanvas() {
        try {
            offscreenCanvas = new OffscreenCanvas(logicalWidth * dpr, logicalHeight * dpr);
            offscreenCtx = offscreenCanvas.getContext('2d');
        } catch (e) { offscreenCanvas = null; offscreenCtx = null; }
    }

    function renderToOffscreen() {
        if (!offscreenCtx) return;
        offscreenCtx.clearRect(0, 0, offscreenCanvas.width, offscreenCanvas.height);
        offscreenCtx.fillStyle = '#fff';
        offscreenCtx.fillRect(0, 0, offscreenCanvas.width, offscreenCanvas.height);
        layers.forEach(layer => {
            if (layer.visible) {
                offscreenCtx.save();
                offscreenCtx.globalAlpha = layer.opacity;
                offscreenCtx.globalCompositeOperation = layer.blendMode;
                offscreenCtx.drawImage(layer.canvas, 0, 0);
                offscreenCtx.restore();
            }
        });
    }

    // --- Share to Social ---
    async function shareToSocial() {
        if (!navigator.share) { alert('Web Share API no disponible'); return; }
        try {
            const blob = await new Promise(resolve => compositeCanvas.toBlob(resolve, 'image/png'));
            const file = new File([blob], 'procreate-lite-art.png', { type: 'image/png' });
            await navigator.share({ files: [file], title: 'Mi arte en Procreate Lite' });
        } catch (e) { /* Share cancelled or failed */ }
    }

    // --- Cloud Sync (localStorage backup) ---
    function cloudSyncBackup() {
        try {
            const data = layers.map(l => ({
                dataUrl: l.canvas.toDataURL(),
                name: l.name, visible: l.visible, opacity: l.opacity, blendMode: l.blendMode
            }));
            localStorage.setItem('procreate-lite-cloud-sync', JSON.stringify({ data, timestamp: Date.now(), width: logicalWidth, height: logicalHeight }));
            return true;
        } catch (e) { return false; }
    }

    function cloudSyncRestore() {
        try {
            const saved = localStorage.getItem('procreate-lite-cloud-sync');
            if (!saved) return false;
            const parsed = JSON.parse(saved);
            // Restore would go here
            return true;
        } catch (e) { return false; }
    }

    // --- Community Brushes ---
    const communityBrushes = [
        { name: 'Fur', spacing: 2, scatter: 30, jitter: 20, texture: true },
        { name: 'Leaves', spacing: 4, scatter: 50, jitter: 40, texture: true },
        { name: 'Sparkle', spacing: 6, scatter: 40, jitter: 60, texture: false },
        { name: 'Cloud', spacing: 3, scatter: 20, jitter: 15, texture: true },
        { name: 'Rain', spacing: 1, scatter: 10, jitter: 80, texture: false }
    ];

    function downloadCommunityBrush(brushDef) {
        brushStudio[brushDef.name.toLowerCase()] = {
            spacing: brushDef.spacing, scatter: brushDef.scatter, jitter: brushDef.jitter,
            rotation: 0, dirRotation: 0, colorDynamics: 0, wetMix: 0,
            dual: false, dualType: 'airbrush'
        };
        // Add to brush list UI
        const brushList = document.querySelector('#brushes-panel .layers-list');
        if (brushList) {
            const item = document.createElement('div');
            item.className = 'layer-item';
            item.setAttribute('data-brush', brushDef.name.toLowerCase());
            item.textContent = brushDef.name;
            brushList.appendChild(item);
        }
    }

