    // --- Advanced Onion Skinning (multi-frame with progressive opacity) ---
    let onionSkinFrames = 3;
    let onionSkinForward = 2;
    let onionSkinDecay = 0.6;
    function renderAdvancedOnionSkin() {
        document.querySelectorAll('.onion-overlay').forEach(el => el.remove());
        if (!animOnionEnabled || animPlaying) return;
        const compCanvas = document.querySelector('#composite-canvas') || compositeCtx.canvas;
        if (!compCanvas) return;
        const parent = compCanvas.parentElement;
        if (!parent) return;
        // Previous frames (red tint)
        for (let f = 1; f <= onionSkinFrames; f++) {
            const idx = animCurrentFrame - f;
            if (idx < 0) continue;
            const frame = animFrames[idx];
            const opacity = animOnionOpacity * Math.pow(onionSkinDecay, f);
            const onion = document.createElement('canvas');
            onion.className = 'onion-overlay';
            onion.width = compCanvas.width; onion.height = compCanvas.height;
            onion.style.cssText = `position:absolute;top:${compCanvas.style.top || '0'};left:${compCanvas.style.left || '0'};width:${compCanvas.style.width || '100%'};height:${compCanvas.style.height || '100%'};opacity:${opacity};pointer-events:none;mix-blend-mode:screen;`;
            const octx = onion.getContext('2d');
            const rgb = hexToRgb(brushColor);
            octx.fillStyle = onionSkinColorPrev + '0.15)';
            octx.fillRect(0, 0, onion.width, onion.height);
            frame.layers.forEach(fl => { if (fl.visible) octx.drawImage(fl.canvas, 0, 0); });
            parent.appendChild(onion);
        }
        // Next frames (blue tint)
        for (let f = 1; f <= onionSkinForward; f++) {
            const idx = animCurrentFrame + f;
            if (idx >= animFrames.length) break;
            const frame = animFrames[idx];
            const opacity = animOnionOpacity * Math.pow(onionSkinDecay, f);
            const onion = document.createElement('canvas');
            onion.className = 'onion-overlay';
            onion.width = compCanvas.width; onion.height = compCanvas.height;
            onion.style.cssText = `position:absolute;top:${compCanvas.style.top || '0'};left:${compCanvas.style.left || '0'};width:${compCanvas.style.width || '100%'};height:${compCanvas.style.height || '100%'};opacity:${opacity};pointer-events:none;mix-blend-mode:screen;`;
            const octx = onion.getContext('2d');
            octx.fillStyle = onionSkinColorNext + '0.15)';
            octx.fillRect(0, 0, onion.width, onion.height);
            frame.layers.forEach(fl => { if (fl.visible) octx.drawImage(fl.canvas, 0, 0); });
            parent.appendChild(onion);
        }
    }

    // --- Motion Tweening ---
    function motionTween(frameA, frameB, steps) {
        if (!frameA || !frameB) return [];
        const tweens = [];
        for (let s = 0; s <= steps; s++) {
            const t = s / steps;
            const tweenFrame = { layers: [] };
            for (let i = 0; i < Math.min(frameA.layers.length, frameB.layers.length); i++) {
                const c = document.createElement('canvas');
                c.width = frameA.layers[i].canvas.width; c.height = frameA.layers[i].canvas.height;
                const ctx = c.getContext('2d');
                ctx.globalAlpha = 1 - t;
                ctx.drawImage(frameA.layers[i].canvas, 0, 0);
                ctx.globalAlpha = t;
                ctx.drawImage(frameB.layers[i].canvas, 0, 0);
                ctx.globalAlpha = 1;
                tweenFrame.layers.push({ canvas: c, ctx, visible: true, opacity: 1, blendMode: 'source-over', name: `Tween ${s}` });
            }
            tweens.push(tweenFrame);
        }
        return tweens;
    }

    // --- Bone Rigging ---
    let bones = []; // [{x1,y1,x2,y2,parentIdx,name}]
    let boneDragging = -1;

    function addBone(x1, y1, x2, y2, parentIdx) {
        bones.push({ x1, y1, x2, y2, parentIdx: parentIdx ?? -1, name: `Hueso ${bones.length + 1}` });
    }

    function getBoneChain(boneIdx) {
        const chain = [];
        let idx = boneIdx;
        while (idx >= 0 && idx < bones.length) {
            chain.unshift(bones[idx]);
            idx = bones[idx].parentIdx;
        }
        return chain;
    }

    // --- Improved Brush Stabilizer (predictive) ---
    function getPredictivePoint(points, lookahead) {
        if (points.length < 3) return points[points.length - 1];
        const p = points[points.length - 1];
        const p1 = points[points.length - 2];
        const p2 = points[points.length - 3];
        // Catmull-Rom-like prediction
        const vx = (p.x - p2.x) * 0.5;
        const vy = (p.y - p2.y) * 0.5;
        return { x: p.x + vx * lookahead, y: p.y + vy * lookahead };
    }

    // --- Brush Dynamics by Velocity ---
    let lastVelocityTime = 0;
    function getVelocityDynamics(x, y, pressure) {
        const now = performance.now();
        const dt = now - lastVelocityTime;
        lastVelocityTime = now;
        const velocity = dt > 0 ? Math.min(1, 50 / dt) : 0.5;
        return {
            sizeMult: 0.3 + velocity * 0.7,
            opacityMult: 0.4 + velocity * 0.6
        };
    }

    // --- Dual Brush Advanced with Mask ---
    function applyDualBrushMask(ctx, x, y, size, maskCanvas) {
        if (!maskCanvas) return;
        ctx.save();
        ctx.globalCompositeOperation = 'source-in';
        ctx.drawImage(maskCanvas, x - size / 2, y - size / 2, size, size);
        ctx.restore();
    }

    // --- Text Warp ---
    function renderTextWarped(ctx, text, font, color, x, y, type, amount) {
        ctx.font = font;
        ctx.fillStyle = color;
        ctx.textBaseline = 'middle';
        const chars = text.split('');
        const charWidth = ctx.measureText('M').width;
        const totalWidth = chars.length * charWidth;
        chars.forEach((ch, i) => {
            const t = i / chars.length;
            let dx = 0, dy = 0, rotation = 0;
            if (type === 'arc') {
                const angle = (t - 0.5) * amount * Math.PI;
                dx = Math.sin(angle) * amount * 30;
                dy = -Math.cos(angle) * amount * 30 + amount * 30;
                rotation = angle * 0.5;
            } else if (type === 'flag') {
                dy = Math.sin(t * Math.PI * 2) * amount * 20;
                rotation = Math.cos(t * Math.PI * 2) * amount * 0.3;
            } else if (type === 'spiral') {
                const angle = t * amount * Math.PI * 2;
                const r = t * amount * 40;
                dx = Math.cos(angle) * r;
                dy = Math.sin(angle) * r;
                rotation = angle;
            } else if (type === 'wave') {
                dy = Math.sin(t * Math.PI * 4) * amount * 15;
            }
            ctx.save();
            ctx.translate(x + i * charWidth - totalWidth / 2 + dx, y + dy);
            ctx.rotate(rotation);
            ctx.fillText(ch, 0, 0);
            ctx.restore();
        });
    }

    // --- Text with Gradient Stroke/Fill ---
    function renderTextGradientFill(ctx, text, font, x, y, colors, direction) {
        ctx.font = font;
        const metrics = ctx.measureText(text);
        const grad = direction === 'v'
            ? ctx.createLinearGradient(x, y - 20, x, y + 20)
            : ctx.createLinearGradient(x - metrics.width / 2, y, x + metrics.width / 2, y);
        colors.forEach((c, i) => grad.addColorStop(i / (colors.length - 1), c));
        ctx.fillStyle = grad;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(text, x, y);
    }

    // --- 3D Text ---
    function renderText3D(ctx, text, font, x, y, depth, color, shadowColor) {
        ctx.font = font;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        // Draw depth layers
        for (let d = depth; d > 0; d--) {
            ctx.fillStyle = shadowColor || '#000000';
            ctx.globalAlpha = 0.3;
            ctx.fillText(text, x + d * 0.7, y + d * 0.7);
        }
        ctx.globalAlpha = 1;
        ctx.fillStyle = color;
        ctx.fillText(text, x, y);
    }

    // --- Color Range Selection ---
    function colorRangeSelect(hueMin, hueMax, satMin, satMax) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const maskCanvas = document.createElement('canvas');
        maskCanvas.width = w; maskCanvas.height = h;
        const maskCtx = maskCanvas.getContext('2d');
        const maskData = maskCtx.createImageData(w, h);
        const md = maskData.data;
        for (let i = 0; i < d.length; i += 4) {
            const hsb = rgbToHsb(d[i], d[i + 1], d[i + 2]);
            if (hsb.h >= hueMin && hsb.h <= hueMax && hsb.s * 100 >= satMin && hsb.s * 100 <= satMax) {
                md[i] = md[i + 1] = md[i + 2] = 255; md[i + 3] = 255;
            }
        }
        maskCtx.putImageData(maskData, 0, 0);
        selectionData = maskData;
        selectionActive = true;
        compositeDirty = true;
        renderComposite();
    }

    // --- Feather Selection ---
    function featherSelection(radius) {
        if (!selectionData) return;
        const w = selectionData.width, h = selectionData.height;
        const d = selectionData.data;
        // Apply gaussian-like blur to selection mask
        const temp = new Uint8ClampedArray(d);
        const r = Math.max(1, Math.round(radius));
        for (let y = r; y < h - r; y++) {
            for (let x = r; x < w - r; x++) {
                let sum = 0, count = 0;
                for (let ky = -r; ky <= r; ky++) {
                    for (let kx = -r; kx <= r; kx++) {
                        sum += temp[((y + ky) * w + (x + kx)) * 4 + 3];
                        count++;
                    }
                }
                d[(y * w + x) * 4 + 3] = Math.round(sum / count);
            }
        }
        compositeDirty = true;
        renderComposite();
    }

    // --- Select Similar ---
    function selectSimilar(x, y, tolerance) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const si = (Math.round(y) * w + Math.round(x)) * 4;
        const sr = d[si], sg = d[si + 1], sb = d[si + 2];
        const visited = new Uint8Array(w * h);
        const stack = [Math.round(x), Math.round(y)];
        const maskData = new ImageData(w, h);
        const md = maskData.data;
        while (stack.length > 0) {
            const py = stack.pop(), px = stack.pop();
            if (px < 0 || px >= w || py < 0 || py >= h) continue;
            const idx = py * w + px;
            if (visited[idx]) continue;
            visited[idx] = 1;
            const pi = idx * 4;
            const dr = d[pi] - sr, dg = d[pi + 1] - sg, db = d[pi + 2] - sb;
            const lum1 = sr * 0.299 + sg * 0.587 + sb * 0.114;
            const lum2 = d[pi] * 0.299 + d[pi + 1] * 0.587 + d[pi + 2] * 0.114;
            if (Math.abs(lum1 - lum2) <= tolerance) {
                md[pi] = md[pi + 1] = md[pi + 2] = 255; md[pi + 3] = 255;
                stack.push(px + 1, py, px - 1, py, px, py + 1, px, py - 1);
            }
        }
        selectionData = maskData;
        selectionActive = true;
        compositeDirty = true;
        renderComposite();
    }

    // --- Oil Paint Filter ---
    function applyOilPaint(ctx, radius, intensity) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const r = Math.max(1, radius);
        for (let y = r; y < h - r; y++) {
            for (let x = r; x < w - r; x++) {
                const histogram = {};
                for (let ky = -r; ky <= r; ky++) {
                    for (let kx = -r; kx <= r; kx++) {
                        const i = ((y + ky) * w + (x + kx)) * 4;
                        const key = `${sd[i]},${sd[i + 1]},${sd[i + 2]}`;
                        histogram[key] = (histogram[key] || 0) + 1;
                    }
                }
                let maxCount = 0, dominant = '';
                for (const [k, v] of Object.entries(histogram)) { if (v > maxCount) { maxCount = v; dominant = k; } }
                const [r2, g2, b2] = dominant.split(',').map(Number);
                const i = (y * w + x) * 4;
                dd[i] = r2; dd[i + 1] = g2; dd[i + 2] = b2; dd[i + 3] = 255;
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- Colored Pencil Filter ---
    function applyColoredPencil(ctx, strokeSize) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        // Edge detection + color
        for (let y = 1; y < h - 1; y++) {
            for (let x = 1; x < w - 1; x++) {
                const i = (y * w + x) * 4;
                const left = ((y * w + x - 1) * 4);
                const top = (((y - 1) * w + x) * 4);
                const gx = sd[i] - sd[left];
                const gy = sd[i] - sd[top];
                const edge = Math.min(255, Math.sqrt(gx * gx + gy * gy) * 3);
                dd[i] = Math.max(0, sd[i] - edge);
                dd[i + 1] = Math.max(0, sd[i + 1] - edge);
                dd[i + 2] = Math.max(0, sd[i + 2] - edge);
                dd[i + 3] = 255;
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- Watercolor Simulation ---
    function applyWatercolor(ctx, intensity) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Posterize + blur edges
        const levels = 8;
        for (let i = 0; i < d.length; i += 4) {
            for (let c = 0; c < 3; c++) {
                d[i + c] = Math.round(d[i + c] / (256 / levels)) * (256 / levels);
            }
        }
        // Soft edges
        const temp = new Uint8ClampedArray(d);
        for (let y = 2; y < h - 2; y++) {
            for (let x = 2; x < w - 2; x++) {
                const i = (y * w + x) * 4;
                for (let c = 0; c < 3; c++) {
                    let sum = 0;
                    for (let ky = -2; ky <= 2; ky++) for (let kx = -2; kx <= 2; kx++) sum += temp[((y + ky) * w + (x + kx)) * 4 + c];
                    d[i + c] = Math.round(d[i + c] * (1 - intensity * 0.1) + (sum / 25) * intensity * 0.1);
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // --- Neural Style Transfer (simplified) ---
    function applyNeuralStyleTransfer(ctx, styleStrength) {
        // Simplified: apply artistic filters that approximate style transfer
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Color quantization + edge enhancement = style-like effect
        const palette = [[70, 30, 10], [180, 60, 30], [220, 180, 80], [40, 80, 120], [20, 20, 40]];
        for (let i = 0; i < d.length; i += 4) {
            let minDist = Infinity, closest = palette[0];
            for (const p of palette) {
                const dist = Math.sqrt((d[i] - p[0]) ** 2 + (d[i + 1] - p[1]) ** 2 + (d[i + 2] - p[2]) ** 2);
                if (dist < minDist) { minDist = dist; closest = p; }
            }
            const t = styleStrength * 0.01;
            d[i] = Math.round(d[i] * (1 - t) + closest[0] * t);
            d[i + 1] = Math.round(d[i + 1] * (1 - t) + closest[1] * t);
            d[i + 2] = Math.round(d[i + 2] * (1 - t) + closest[2] * t);
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // --- Facial Recognition Auto-Enhance ---
    function applyFaceEnhance(ctx) {
        // Simplified: enhance skin tones and brighten center area
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const cx = w / 2, cy = h / 2;
        const maxDist = Math.sqrt(cx * cx + cy * cy);
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                const hsb = rgbToHsb(d[i], d[i + 1], d[i + 2]);
                // Skin tone detection (hue 0-50, sat 20-70)
                if (hsb.h <= 50 && hsb.s >= 0.2 && hsb.s <= 0.7) {
                    const dist = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2) / maxDist;
                    const boost = Math.max(0, 1 - dist * 2) * 0.15;
                    d[i] = Math.min(255, d[i] + boost * 40);
                    d[i + 1] = Math.min(255, d[i + 1] + boost * 20);
                    d[i + 2] = Math.min(255, d[i + 2] + boost * 10);
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // --- ICC Profiles / Soft Proofing ---
    let softProofingActive = false;
    let softProofProfile = null;
    let gamutWarningActive = false;

    // CMYK simulation: proper RGB↔CMYK conversion with ICC-like curves
    function rgbToCmykProof(r, g, b) {
        const rn = r / 255, gn = g / 255, bn = b / 255;
        const k = 1 - Math.max(rn, gn, bn);
        if (k >= 1) return { c: 0, m: 0, y: 0, k: 100 };
        return {
            c: ((1 - rn - k) / (1 - k)) * 100,
            m: ((1 - gn - k) / (1 - k)) * 100,
            y: ((1 - bn - k) / (1 - k)) * 100,
            k: k * 100
        };
    }

    function cmykToRgbProof(c, m, y, k) {
        const cn = c / 100, mn = m / 100, yn = y / 100, kn = k / 100;
        return {
            r: Math.round(255 * (1 - cn) * (1 - kn)),
            g: Math.round(255 * (1 - mn) * (1 - kn)),
            b: Math.round(255 * (1 - yn) * (1 - kn))
        };
    }

    // ICC-like gamma correction per profile
    function profileGammaCorrect(val, profileName) {
        const v = val / 255;
        switch (profileName) {
            case 'adobeRGB': return Math.round(255 * Math.pow(v, 2.2 / 2.2)); // gamma 2.2
            case 'displayP3': return Math.round(255 * Math.pow(v, 2.2 / 2.2));
            case 'proPhoto': return Math.round(255 * Math.pow(v, 1.8 / 2.2)); // gamma 1.8
            case 'printCMYK': return Math.round(255 * Math.pow(v, 1.4 / 2.2)); // print simulation
            default: return val; // sRGB: no correction needed (already in sRGB)
        }
    }

    // Apply soft proof as non-destructive overlay on composite canvas
    function applySoftProofToComposite(ctx) {
        if (!softProofingActive || !softProofProfile) return;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        if (w === 0 || h === 0) return;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let i = 0; i < d.length; i += 4) {
            if (d[i + 3] === 0) continue;
            // Apply ICC profile gamma correction
            let r = profileGammaCorrect(d[i], softProofProfile);
            let g = profileGammaCorrect(d[i + 1], softProofProfile);
            let b = profileGammaCorrect(d[i + 2], softProofProfile);
            // For CMYK proof: simulate print gamut compression
            if (softProofProfile === 'printCMYK') {
                const cmyk = rgbToCmykProof(r, g, b);
                // Reduce saturation slightly to simulate CMYK gamut
                const avg = (r + g + b) / 3;
                const satFactor = 0.85;
                r = Math.round(avg + (r - avg) * satFactor);
                g = Math.round(avg + (g - avg) * satFactor);
                b = Math.round(avg + (b - avg) * satFactor);
                // Apply K channel darkening
                const kFactor = 1 - cmyk.k / 200;
                r = Math.round(r * kFactor);
                g = Math.round(g * kFactor);
                b = Math.round(b * kFactor);
            }
            d[i] = Math.max(0, Math.min(255, r));
            d[i + 1] = Math.max(0, Math.min(255, g));
            d[i + 2] = Math.max(0, Math.min(255, b));
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function applySoftProofing(profileName) {
        if (!iccProfiles[profileName] && profileName !== 'printCMYK') return;
        softProofingActive = true;
        softProofProfile = profileName;
        compositeDirty = true;
        renderComposite();
    }

    function toggleSoftProof() {
        if (softProofingActive) {
            softProofingActive = false;
            softProofProfile = null;
            compositeDirty = true;
            renderComposite();
            showToast('Soft proof desactivado');
        } else {
            const profileName = currentICCProfile || 'sRGB';
            applySoftProofing(profileName);
            showToast(`Soft proof: ${iccProfiles[profileName]?.name || profileName}`);
        }
    }

    // --- Gamut Warning ---
    function applyGamutWarning(ctx) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        if (w === 0 || h === 0) return;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let i = 0; i < d.length; i += 4) {
            if (d[i + 3] === 0) continue;
            // Check if out of sRGB gamut (simplified)
            const max = Math.max(d[i], d[i + 1], d[i + 2]);
            const min = Math.min(d[i], d[i + 1], d[i + 2]);
            if (max > 240 || min < 15 || (max - min) > 200) {
                // Mark as out of gamut with bright magenta overlay
                d[i] = 255; d[i + 1] = 0; d[i + 2] = 255;
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function applyGamutWarningToComposite(ctx) {
        if (!gamutWarningActive) return;
        applyGamutWarning(ctx);
    }

    function toggleGamutWarning() {
        gamutWarningActive = !gamutWarningActive;
        compositeDirty = true;
        renderComposite();
        showToast(gamutWarningActive ? 'Gamut warning activado' : 'Gamut warning desactivado');
    }

    // --- Advanced Layer Effects (Stroke, Satin) ---
    function applyLayerStroke(ctx, canvas, width, color, position) {
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineWidth = width;
        ctx.globalCompositeOperation = position === 'inside' ? 'source-atop' : 'source-over';
        // Create outline by drawing expanded version
        const temp = document.createElement('canvas');
        temp.width = canvas.width; temp.height = canvas.height;
        const tctx = temp.getContext('2d');
        tctx.drawImage(canvas, 0, 0);
        tctx.globalCompositeOperation = 'destination-fill';
        tctx.fillStyle = color;
        // Stroke outline
        ctx.beginPath();
        const step = 2;
        for (let y = 0; y < canvas.height; y += step) {
            for (let x = 0; x < canvas.width; x += step) {
                const d = tctx.getImageData(x, y, 1, 1).data;
                if (d[3] > 128) {
                    // Check if edge pixel
                    let isEdge = false;
                    for (let dy = -1; dy <= 1 && !isEdge; dy++) {
                        for (let dx = -1; dx <= 1 && !isEdge; dx++) {
                            if (dx === 0 && dy === 0) continue;
                            const nd = tctx.getImageData(x + dx, y + dy, 1, 1).data;
                            if (nd[3] < 128) isEdge = true;
                        }
                    }
                    if (isEdge) {
                        ctx.rect(x - width / 2, y - width / 2, step + width, step + width);
                    }
                }
            }
        }
        ctx.fill();
        ctx.restore();
    }

    function applySatinEffect(ctx, canvas, color, size, opacity) {
        const w = canvas.width, h = canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const rgb = hexToRgb(color);
        for (let i = 0; i < sd.length; i += 4) {
            const lum = (sd[i] * 0.299 + sd[i + 1] * 0.587 + sd[i + 2] * 0.114) / 255;
            const satin = Math.sin(lum * Math.PI) * opacity;
            dd[i] = Math.min(255, sd[i] + rgb.r * satin);
            dd[i + 1] = Math.min(255, sd[i + 1] + rgb.g * satin);
            dd[i + 2] = Math.min(255, sd[i + 2] + rgb.b * satin);
            dd[i + 3] = sd[i + 3];
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- Pattern Overlay ---
    function applyPatternOverlay(ctx, w, h, patternName, scale, opacity, blendMode) {
        ctx.save();
        ctx.globalAlpha = opacity;
        ctx.globalCompositeOperation = blendMode;
        const fn = patterns[patternName] || patterns.checker;
        const imgData = ctx.createImageData(w, h);
        const d = imgData.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const v = fn(x, y, scale);
                const i = (y * w + x) * 4;
                d[i] = d[i + 1] = d[i + 2] = v; d[i + 3] = 255;
            }
        }
        const tempCanvas = document.createElement('canvas');
        tempCanvas.width = w; tempCanvas.height = h;
        tempCanvas.getContext('2d').putImageData(imgData, 0, 0);
        ctx.drawImage(tempCanvas, 0, 0);
        ctx.restore();
    }

    // --- Gradient Overlay ---
    function applyGradientOverlay(ctx, w, h, colors, direction, opacity, blendMode) {
        ctx.save();
        ctx.globalAlpha = opacity;
        ctx.globalCompositeOperation = blendMode;
        const grad = direction === 'v'
            ? ctx.createLinearGradient(0, 0, 0, h)
            : ctx.createLinearGradient(0, 0, w, 0);
        colors.forEach((c, i) => grad.addColorStop(i / (colors.length - 1), c));
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, w, h);
        ctx.restore();
    }

    // --- Batch Processing ---
    function batchProcess(filterFn, fileList) {
        // Apply filter to multiple layers
        layers.forEach(layer => {
            if (layer.visible) filterFn(layer.ctx, layer.canvas.width, layer.canvas.height);
        });
        compositeDirty = true;
        renderComposite();
    }

    // --- Custom Workspace Layouts ---
    let savedLayouts = [];
    function saveWorkspaceLayout(name) {
        const layout = {};
        document.querySelectorAll('.panel, .sidebar-settings').forEach(panel => {
            if (panel.id) layout[panel.id] = { left: panel.style.left, top: panel.style.top, display: panel.style.display || (panel.classList.contains('hidden') ? 'none' : 'block') };
        });
        savedLayouts.push({ name, layout });
        try { localStorage.setItem('procreate-lite-layouts', JSON.stringify(savedLayouts)); } catch (e) { }
    }

    function loadWorkspaceLayout(name) {
        const saved = savedLayouts.find(l => l.name === name);
        if (!saved) return;
        Object.entries(saved.layout).forEach(([id, pos]) => {
            const el = document.getElementById(id);
            if (el) { el.style.left = pos.left; el.style.top = pos.top; el.style.display = pos.display; }
        });
    }

    // --- Improved Action Recording with Loops ---
    function executeRecordedMacro(macro) {
        let i = 0;
        function next() {
            if (i >= macro.steps.length) return;
            const step = macro.steps[i++];
            if (step.type === 'loop') {
                let count = step.count || 3;
                let loopSteps = step.steps || [];
                function doLoop() {
                    if (count <= 0) { next(); return; }
                    count--;
                    let j = 0;
                    function loopNext() {
                        if (j >= loopSteps.length) { doLoop(); return; }
                        const ls = loopSteps[j++];
                        executeStep(ls, loopNext);
                    }
                    loopNext();
                }
                doLoop();
            } else {
                executeStep(step, next);
            }
        }
        next();
    }

    function executeStep(step, callback) {
        if (step.type === 'tool') { const btn = document.getElementById(step.id); if (btn) btn.click(); }
        else if (step.type === 'brushSize') { brushSize = step.value; }
        else if (step.type === 'color') { brushColor = step.value; }
        setTimeout(callback || (() => { }), step.delay || 50);
    }

    // --- Scripting API ---
    const ScriptAPI = {
        getLayers: () => layers.map(l => ({ name: l.name, visible: l.visible, opacity: l.opacity, width: l.canvas.width, height: l.canvas.height })),
        setBrushColor: (hex) => { brushColor = hex; },
        setBrushSize: (size) => { brushSize = size; },
        getCanvasSize: () => ({ width: logicalWidth, height: logicalHeight }),
        exportLayer: (idx) => { const l = layers[idx]; return l ? l.canvas.toDataURL() : null; },
        applyFilter: (fn) => { layers.forEach(l => { if (l.visible) fn(l.ctx, l.canvas.width, l.canvas.height); }); compositeDirty = true; renderComposite(); },
        addLayer: () => addLayer(),
        setActiveLayer: (idx) => { activeLayerIndex = idx; renderLayersUI(); },
        undo, redo,
        saveVersion: (name) => saveVersion(name),
        generatePalette: () => generateColorPalette()
    };

    // --- AI Real Upscaling (pixel art style) ---
    function aiRealUpscale(scale) {
        const layer = getActiveLayer();
        if (!layer) return;
        const sw = layer.canvas.width, sh = layer.canvas.height;
        const nw = sw * scale, nh = sh * scale;
        const src = layer.ctx.getImageData(0, 0, sw, sh);
        const dst = new ImageData(nw, nh);
        const sd = src.data, dd = dst.data;
        // Nearest-neighbor for sharp edges (pixel art upscaling)
        for (let y = 0; y < nh; y++) {
            for (let x = 0; x < nw; x++) {
                const sx = Math.floor(x / scale), sy = Math.floor(y / scale);
                const si = (sy * sw + sx) * 4;
                const di = (y * nw + x) * 4;
                dd[di] = sd[si]; dd[di + 1] = sd[si + 1]; dd[di + 2] = sd[si + 2]; dd[di + 3] = sd[si + 3];
            }
        }
        layer.canvas.width = nw; layer.canvas.height = nh;
        layer.ctx.putImageData(dst, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- AI Real Style Transfer ---
    function aiRealStyleTransfer(styleImage) {
        const layer = getActiveLayer();
        if (!layer || !styleImage) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const srcData = layer.ctx.getImageData(0, 0, w, h);
        const styleCanvas = document.createElement('canvas');
        styleCanvas.width = w; styleCanvas.height = h;
        const sctx = styleCanvas.getContext('2d');
        sctx.drawImage(styleImage, 0, 0, w, h);
        const styleData = sctx.getImageData(0, 0, w, h);
        const sd = srcData.data, ssd = styleData.data;
        // Color transfer: match mean and std of style
        let srcMean = [0, 0, 0], styleMean = [0, 0, 0];
        const pixels = w * h;
        for (let i = 0; i < sd.length; i += 4) { srcMean[0] += sd[i]; srcMean[1] += sd[i + 1]; srcMean[2] += sd[i + 2]; }
        for (let i = 0; i < ssd.length; i += 4) { styleMean[0] += ssd[i]; styleMean[1] += ssd[i + 1]; styleMean[2] += ssd[i + 2]; }
        srcMean = srcMean.map(v => v / pixels);
        styleMean = styleMean.map(v => v / pixels);
        for (let i = 0; i < sd.length; i += 4) {
            for (let c = 0; c < 3; c++) {
                sd[i + c] = Math.max(0, Math.min(255, Math.round(styleMean[c] + (sd[i + c] - srcMean[c]) * 0.8)));
            }
        }
        layer.ctx.putImageData(srcData, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- AI Auto-Color ---
    function aiAutoColor() {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Auto levels: stretch each channel to full range
        for (let c = 0; c < 3; c++) {
            let min = 255, max = 0;
            for (let i = c; i < d.length; i += 4) { if (d[i] < min) min = d[i]; if (d[i] > max) max = d[i]; }
            const range = max - min || 1;
            for (let i = c; i < d.length; i += 4) { d[i] = Math.round((d[i] - min) / range * 255); }
        }
        layer.ctx.putImageData(imgData, 0, 0);
        saveState();
        compositeDirty = true;
        renderComposite();
    }

    // --- AI Scene Detection ---
    function aiSceneDetect() {
        const layer = getActiveLayer();
        if (!layer) return 'unknown';
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        let avgR = 0, avgG = 0, avgB = 0, count = 0;
        for (let i = 0; i < d.length; i += 16) { avgR += d[i]; avgG += d[i + 1]; avgB += d[i + 2]; count++; }
        avgR /= count; avgG /= count; avgB /= count;
        if (avgB > avgR && avgB > avgG) return 'sky';
        if (avgG > avgR && avgG > avgB) return 'nature';
        if (avgR > avgG && avgR > avgB) return 'sunset';
        return 'neutral';
    }

    // --- WebAssembly Filter Stubs ---
    let wasmModule = null;
