    function computeStrokeVelocity(x1, y1, x2, y2) {
        const dx = x2 - x1, dy = y2 - y1;
        return Math.sqrt(dx * dx + dy * dy);
    }

    function applyBrushTextureMask(ctx, x, y, radius, color, opacity) {
        if (!brushTextureMask) { ctx.fillStyle = color; ctx.globalAlpha = opacity; ctx.beginPath(); ctx.arc(x, y, radius, 0, Math.PI * 2); ctx.fill(); return; }
        ctx.save();
        ctx.globalAlpha = opacity;
        ctx.beginPath();
        ctx.arc(x, y, radius, 0, Math.PI * 2);
        ctx.clip();
        ctx.drawImage(brushTextureMask, x - radius, y - radius, radius * 2, radius * 2);
        ctx.globalCompositeOperation = 'source-in';
        ctx.fillStyle = color;
        ctx.fillRect(x - radius, y - radius, radius * 2, radius * 2);
        ctx.restore();
    }

    function invertSelection() {
        if (!selectionData) return;
        const d = selectionData.data;
        for (let i = 3; i < d.length; i += 4) { d[i] = 255 - d[i]; }
        selectionOverlay.classList.remove('hidden');
        drawSelectionOverlay();
    }

    function growSelection(amount) {
        if (!selectionData) return;
        const w = selectionData.width, h = selectionData.height;
        const src = new Uint8ClampedArray(selectionData.data);
        const dst = selectionData.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let maxAlpha = 0;
                for (let dy = -amount; dy <= amount; dy++) {
                    for (let dx = -amount; dx <= amount; dx++) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                            const a = src[(ny * w + nx) * 4 + 3];
                            if (a > maxAlpha) maxAlpha = a;
                        }
                    }
                }
                dst[(y * w + x) * 4 + 3] = maxAlpha;
            }
        }
        drawSelectionOverlay();
    }
    function shrinkSelection(amount) { growSelection(-amount); }

    function toggleQuickMask() {
        quickMaskMode = !quickMaskMode;
        if (quickMaskMode) {
            const layer = getActiveLayer();
            if (!layer) { quickMaskMode = false; return; }
            quickMaskCanvas = document.createElement('canvas');
            quickMaskCanvas.width = layer.canvas.width; quickMaskCanvas.height = layer.canvas.height;
            const qctx = quickMaskCanvas.getContext('2d');
            qctx.fillStyle = 'white'; qctx.fillRect(0, 0, quickMaskCanvas.width, quickMaskCanvas.height);
            if (selectionData) { qctx.putImageData(selectionData, 0, 0); }
        } else {
            if (quickMaskCanvas) {
                const layer = getActiveLayer();
                if (layer) {
                    selectionData = quickMaskCanvas.getContext('2d').getImageData(0, 0, quickMaskCanvas.width, quickMaskCanvas.height);
                    selectionOverlay.classList.remove('hidden');
                    drawSelectionOverlay();
                }
            }
            quickMaskCanvas = null;
        }
        compositeDirty = true; renderComposite();
    }

    function toggleAlphaLock() {
        const layer = getActiveLayer();
        if (!layer) return;
        layer.alphaLock = !layer.alphaLock;
        renderLayersUI();
    }

    function applyMaskAsLayer() {
        const layer = getActiveLayer();
        if (!layer || !layer.nonDestructiveMask) return;
        const { canvas: newCanvas, ctx: newCtx } = createLayerEl();
        newCtx.putImageData(layer.nonDestructiveMask.canvas.getContext('2d').getImageData(0, 0, layer.nonDestructiveMask.canvas.width, layer.nonDestructiveMask.canvas.height), 0, 0);
        const maskLayer = { id: `layer-${layerIdCounter++}`, name: `Máscara ${layer.name}`, canvas: newCanvas, ctx: newCtx, visible: true, opacity: 1, alphaLock: false, blendMode: 'source-over', maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) };
        layers.push(maskLayer);
        activeLayerIndex = layers.length - 1;
        renderLayersUI(); compositeDirty = true; renderComposite();
    }

    function mergeVisibleToNew() {
        if (layers.length >= MAX_LAYERS) { showAlert('Limite de capas', 'Limite de capas alcanzado'); return; }
        const { canvas: newCanvas, ctx: newCtx } = createLayerEl();
        newCanvas.width = logicalWidth * dpr; newCanvas.height = logicalHeight * dpr;
        newCtx.scale(dpr, dpr);
        layers.forEach(l => {
            if (l.visible) {
                newCtx.save();
                newCtx.globalAlpha = l.opacity;
                newCtx.globalCompositeOperation = l.blendMode || 'source-over';
                newCtx.drawImage(l.canvas, 0, 0);
                newCtx.restore();
            }
        });
        const merged = { id: `layer-${layerIdCounter++}`, name: 'Combinadas', canvas: newCanvas, ctx: newCtx, visible: true, opacity: 1, alphaLock: false, blendMode: 'source-over', maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) };
        layers.push(merged);
        activeLayerIndex = layers.length - 1;
        renderLayersUI(); compositeDirty = true; renderComposite();
    }

    function flattenAllLayers() {
        const { canvas: newCanvas, ctx: newCtx } = createLayerEl();
        newCanvas.width = logicalWidth * dpr; newCanvas.height = logicalHeight * dpr;
        newCtx.scale(dpr, dpr);
        newCtx.fillStyle = '#ffffff'; newCtx.fillRect(0, 0, newCanvas.width, newCanvas.height);
        layers.forEach(l => {
            if (l.visible) {
                newCtx.save();
                newCtx.globalAlpha = l.opacity;
                newCtx.globalCompositeOperation = l.blendMode || 'source-over';
                newCtx.drawImage(l.canvas, 0, 0);
                newCtx.restore();
            }
        });
        layers.length = 0;
        const flat = { id: `layer-${layerIdCounter++}`, name: 'Plano', canvas: newCanvas, ctx: newCtx, visible: true, opacity: 1, alphaLock: false, blendMode: 'source-over', maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) };
        layers.push(flat);
        activeLayerIndex = 0;
        layerGroups.length = 0;
        renderLayersUI(); compositeDirty = true; renderComposite();
    }

    function applyEdgeDetect(ctx) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const sobelX = [-1, 0, 1, -2, 0, 2, -1, 0, 1];
        const sobelY = [-1, -2, -1, 0, 0, 0, 1, 2, 1];
        for (let y = 1; y < h - 1; y++) {
            for (let x = 1; x < w - 1; x++) {
                let gx = 0, gy = 0;
                for (let ky = -1; ky <= 1; ky++) {
                    for (let kx = -1; kx <= 1; kx++) {
                        const idx = ((y + ky) * w + (x + kx)) * 4;
                        const gray = (sd[idx] + sd[idx + 1] + sd[idx + 2]) / 3;
                        gx += gray * sobelX[(ky + 1) * 3 + (kx + 1)];
                        gy += gray * sobelY[(ky + 1) * 3 + (kx + 1)];
                    }
                }
                const mag = Math.min(255, Math.sqrt(gx * gx + gy * gy));
                const di = (y * w + x) * 4;
                dd[di] = dd[di + 1] = dd[di + 2] = mag; dd[di + 3] = 255;
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applyPosterize(ctx, levels) {
        levels = levels || 4;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const step = 255 / (levels - 1);
        for (let i = 0; i < d.length; i += 4) {
            d[i] = Math.round(Math.round(d[i] / step) * step);
            d[i + 1] = Math.round(Math.round(d[i + 1] / step) * step);
            d[i + 2] = Math.round(Math.round(d[i + 2] / step) * step);
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function applyPixelate(ctx, blockSize) {
        blockSize = blockSize || 8;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let by = 0; by < h; by += blockSize) {
            for (let bx = 0; bx < w; bx += blockSize) {
                let r = 0, g = 0, b = 0, a = 0, count = 0;
                for (let dy = 0; dy < blockSize && by + dy < h; dy++) {
                    for (let dx = 0; dx < blockSize && bx + dx < w; dx++) {
                        const i = ((by + dy) * w + (bx + dx)) * 4;
                        r += d[i]; g += d[i + 1]; b += d[i + 2]; a += d[i + 3]; count++;
                    }
                }
                r = Math.round(r / count); g = Math.round(g / count); b = Math.round(b / count); a = Math.round(a / count);
                for (let dy = 0; dy < blockSize && by + dy < h; dy++) {
                    for (let dx = 0; dx < blockSize && bx + dx < w; dx++) {
                        const i = ((by + dy) * w + (bx + dx)) * 4;
                        d[i] = r; d[i + 1] = g; d[i + 2] = b; d[i + 3] = a;
                    }
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function applyEmboss(ctx) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const kernel = [-2, -1, 0, -1, 1, 1, 0, 1, 2];
        const sd = src.data, dd = dst.data;
        for (let y = 1; y < h - 1; y++) {
            for (let x = 1; x < w - 1; x++) {
                for (let c = 0; c < 3; c++) {
                    let val = 0;
                    for (let ky = -1; ky <= 1; ky++) {
                        for (let kx = -1; kx <= 1; kx++) {
                            val += sd[((y + ky) * w + (x + kx)) * 4 + c] * kernel[(ky + 1) * 3 + (kx + 1)];
                        }
                    }
                    dd[(y * w + x) * 4 + c] = Math.max(0, Math.min(255, val + 128));
                }
                dd[(y * w + x) * 4 + 3] = 255;
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applySolarize(ctx, threshold) {
        threshold = threshold || 128;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let i = 0; i < d.length; i += 4) {
            if (d[i] > threshold) d[i] = 255 - d[i];
            if (d[i + 1] > threshold) d[i + 1] = 255 - d[i + 1];
            if (d[i + 2] > threshold) d[i + 2] = 255 - d[i + 2];
        }
        ctx.putImageData(imgData, 0, 0);
    }

