    // =====================================================================
    // Batch 7A: Brush Engine
    // =====================================================================

    let brushPaintLoad = 100; let brushPaintLoadMax = 100;

    function depletePaintLoad(amount) {
        brushPaintLoad = Math.max(0, brushPaintLoad - amount);
    }
    function refillPaintLoad() { brushPaintLoad = brushPaintLoadMax; }

    let bristleCount = 5; let bristleSpread = 0.3;

    function drawBristleStroke(ctx, x, y, radius, color, pressure, angle) {
        ctx.save();
        ctx.fillStyle = color;
        for (let i = 0; i < bristleCount; i++) {
            const t = i / bristleCount;
            const ox = Math.cos(angle + t * Math.PI * 2) * radius * bristleSpread * (1 - pressure * 0.5);
            const oy = Math.sin(angle + t * Math.PI * 2) * radius * bristleSpread * (1 - pressure * 0.5);
            const br = radius * (0.1 + 0.2 * Math.random());
            ctx.globalAlpha = 0.3 + 0.7 * Math.random();
            ctx.beginPath();
            ctx.arc(x + ox, y + oy, br, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    let eraserHardness = 100;

    function eraserDot(ctx, x, y, radius) {
        ctx.save();
        ctx.globalCompositeOperation = 'destination-out';
        if (eraserHardness >= 90) {
            ctx.beginPath();
            ctx.arc(x, y, radius, 0, Math.PI * 2);
            ctx.fill();
        } else {
            const grad = ctx.createRadialGradient(x, y, 0, x, y, radius);
            const alpha = eraserHardness / 100;
            grad.addColorStop(0, `rgba(0,0,0,${alpha})`);
            grad.addColorStop(1, 'rgba(0,0,0,0)');
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(x, y, radius, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    // =====================================================================
    // Batch 7B: Selection Tools
    // =====================================================================

    let polyLassoPoints = []; let polyLassoActive = false;

    function startPolyLasso() { polyLassoActive = true; polyLassoPoints = []; }
    function addPolyLassoPoint(x, y) { polyLassoPoints.push({ x, y }); }
    function finishPolyLasso() {
        if (polyLassoPoints.length < 3) { polyLassoActive = false; return; }
        const w = logicalWidth * dpr, h = logicalHeight * dpr;
        selectionData = selectionCtx.createImageData(w, h);
        const d = selectionData.data;
        const pts = polyLassoPoints.map(p => ({ x: p.x * dpr, y: p.y * dpr }));
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                if (pointInPolygon(x, y, pts)) {
                    d[(y * w + x) * 4 + 3] = 255;
                }
            }
        }
        selectionData.width = w; selectionData.height = h;
        selectionOverlay.classList.remove('hidden');
        drawSelectionOverlay();
        polyLassoActive = false; polyLassoPoints = [];
    }
    function pointInPolygon(x, y, poly) {
        let inside = false;
        for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
            const xi = poly[i].x, yi = poly[i].y, xj = poly[j].x, yj = poly[j].y;
            if ((yi > y) !== (yj > y) && x < (xj - xi) * (y - yi) / (yj - yi) + xi) inside = !inside;
        }
        return inside;
    }

    function selectColorRange(hueMin, hueMax, satMin, satMax, valMin, valMax) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        selectionData = new ImageData(w, h);
        const sd = src.data, dd = selectionData.data;
        for (let i = 0; i < sd.length; i += 4) {
            const hsb = rgbToHsb(sd[i], sd[i + 1], sd[i + 2]);
            if (hsb.h >= hueMin && hsb.h <= hueMax && hsb.s >= satMin && hsb.s <= satMax && hsb.b >= valMin && hsb.b <= valMax) {
                dd[i + 3] = 255;
            }
        }
        selectionData.width = w; selectionData.height = h;
        selectionOverlay.classList.remove('hidden');
        drawSelectionOverlay();
    }

    function selectByChannel(channel, threshold) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        selectionData = new ImageData(w, h);
        const sd = src.data, dd = selectionData.data;
        const ci = channel === 'red' ? 0 : channel === 'green' ? 1 : channel === 'blue' ? 2 : 3;
        for (let i = 0; i < sd.length; i += 4) {
            if (sd[i + ci] >= threshold) { dd[i + 3] = 255; }
        }
        selectionData.width = w; selectionData.height = h;
        selectionOverlay.classList.remove('hidden');
        drawSelectionOverlay();
    }

    // --- Color Range Selection Modal ---
    function showColorRangeModal() {
        const layer = getActiveLayer();
        if (!layer) { showToast('No hay capa activa'); return; }
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);

        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:10px;';

        const previewCanvas = document.createElement('canvas');
        previewCanvas.width = 200; previewCanvas.height = 150;
        previewCanvas.style.cssText = 'width:100%;border-radius:8px;border:1px solid var(--border-color);background:#1a1a1a;';
        const prevCtx = previewCanvas.getContext('2d');
        prevCtx.drawImage(layer.canvas, 0, 0, 200, 150);
        wrapper.appendChild(previewCanvas);

        const pickHint = document.createElement('div');
        pickHint.style.cssText = 'font-size:10px;color:var(--text-secondary);text-align:center;';
        pickHint.textContent = 'Haz clic en la vista previa para elegir un color base';
        wrapper.appendChild(pickHint);

        let pickedColor = null;
        let tolerance = 30;

        const slidersDiv = document.createElement('div');
        slidersDiv.style.cssText = 'display:grid;grid-template-columns:1fr 1fr;gap:6px;';

        function makeSlider(label, min, max, val, id) {
            const col = document.createElement('div');
            col.style.cssText = 'display:flex;flex-direction:column;gap:2px;';
            const lbl = document.createElement('label');
            lbl.style.cssText = 'font-size:9px;color:var(--text-secondary);';
            lbl.textContent = label;
            const row = document.createElement('div');
            row.style.cssText = 'display:flex;align-items:center;gap:4px;';
            const slider = document.createElement('input');
            slider.type = 'range'; slider.min = min; slider.max = max; slider.value = val;
            slider.style.cssText = 'flex:1;accent-color:var(--accent-color);';
            const valSpan = document.createElement('span');
            valSpan.style.cssText = 'font-size:9px;color:var(--text-color);min-width:24px;text-align:right;';
            valSpan.textContent = val;
            slider.addEventListener('input', () => { valSpan.textContent = slider.value; updatePreview(); });
            row.appendChild(slider); row.appendChild(valSpan);
            col.appendChild(lbl); col.appendChild(row);
            return { col, slider };
        }

        const hueMin = makeSlider('Tono mín', 0, 360, 0);
        const hueMax = makeSlider('Tono máx', 0, 360, 360);
        const satMin = makeSlider('Saturación mín', 0, 100, 0);
        const satMax = makeSlider('Saturación máx', 0, 100, 100);
        const valMin = makeSlider('Brillo mín', 0, 100, 0);
        const valMax = makeSlider('Brillo máx', 0, 100, 100);

        const tolDiv = document.createElement('div');
        tolDiv.style.cssText = 'grid-column:span 2;';
        const tolSlider = makeSlider('Tolerancia (al elegir color)', 1, 100, tolerance);
        tolerance = parseInt(tolSlider.slider.value);
        tolSlider.slider.addEventListener('input', () => { tolerance = parseInt(tolSlider.slider.value); });
        tolDiv.appendChild(tolSlider.col);

        slidersDiv.appendChild(hueMin.col);
        slidersDiv.appendChild(hueMax.col);
        slidersDiv.appendChild(satMin.col);
        slidersDiv.appendChild(satMax.col);
        slidersDiv.appendChild(valMin.col);
        slidersDiv.appendChild(valMax.col);
        slidersDiv.appendChild(tolDiv);
        wrapper.appendChild(slidersDiv);

        function updatePreview() {
            const layerData = layer.ctx.getImageData(0, 0, w, h).data;
            const hMin = parseInt(hueMin.slider.value), hMax = parseInt(hueMax.slider.value);
            const sMin = parseInt(satMin.slider.value), sMax = parseInt(satMax.slider.value);
            const vMin = parseInt(valMin.slider.value), vMax = parseInt(valMax.slider.value);
            const tmpCanvas = document.createElement('canvas');
            tmpCanvas.width = 200; tmpCanvas.height = 150;
            const tmpCtx = tmpCanvas.getContext('2d');
            tmpCtx.fillStyle = '#1a1a1a';
            tmpCtx.fillRect(0, 0, 200, 150);
            const tmpData = tmpCtx.getImageData(0, 0, 200, 150);
            const scale_x = w / 200, scale_y = h / 150;
            for (let py = 0; py < 150; py++) {
                for (let px = 0; px < 200; px++) {
                    const sx = Math.min(w - 1, Math.floor(px * scale_x));
                    const sy = Math.min(h - 1, Math.floor(py * scale_y));
                    const si = (sy * w + sx) * 4;
                    const hsb = rgbToHsb(layerData[si], layerData[si + 1], layerData[si + 2]);
                    if (hsb.h >= hMin && hsb.h <= hMax && hsb.s >= sMin && hsb.s <= sMax && hsb.b >= vMin && hsb.b <= vMax) {
                        const di = (py * 200 + px) * 4;
                        tmpData.data[di] = layerData[si];
                        tmpData.data[di + 1] = layerData[si + 1];
                        tmpData.data[di + 2] = layerData[si + 2];
                        tmpData.data[di + 3] = 255;
                    }
                }
            }
            tmpCtx.putImageData(tmpData, 0, 0);
            prevCtx.clearRect(0, 0, 200, 150);
            prevCtx.drawImage(tmpCanvas, 0, 0);
        }

        previewCanvas.addEventListener('click', (e) => {
            const rect = previewCanvas.getBoundingClientRect();
            const px = Math.floor((e.clientX - rect.left) / rect.width * 200);
            const py = Math.floor((e.clientY - rect.top) / rect.height * 150);
            const imgData = prevCtx.getImageData(px, py, 1, 1).data;
            pickedColor = rgbToHsb(imgData[0], imgData[1], imgData[2]);
            const tol = tolerance;
            hueMin.slider.value = Math.max(0, pickedColor.h - tol);
            hueMax.slider.value = Math.min(360, pickedColor.h + tol);
            satMin.slider.value = Math.max(0, pickedColor.s - tol);
            satMax.slider.value = Math.min(100, pickedColor.s + tol);
            valMin.slider.value = Math.max(0, pickedColor.b - tol);
            valMax.slider.value = Math.min(100, pickedColor.b + tol);
            [hueMin, hueMax, satMin, satMax, valMin, valMax].forEach(s => s.slider.nextElementSibling.textContent = s.slider.value);
            updatePreview();
            pickHint.textContent = `Color: H=${pickedColor.h} S=${pickedColor.s} B=${pickedColor.b}`;
            pickHint.style.color = `rgb(${imgData[0]},${imgData[1]},${imgData[2]})`;
        });

        updatePreview();

        showModal({
            title: 'Selección por Rango de Color',
            body: wrapper,
            buttons: [
                { label: 'Cancelar', value: false },
                {
                    label: 'Seleccionar', class: 'primary', value: true, action: () => {
                        selectColorRange(
                            parseInt(hueMin.slider.value), parseInt(hueMax.slider.value),
                            parseInt(satMin.slider.value), parseInt(satMax.slider.value),
                            parseInt(valMin.slider.value), parseInt(valMax.slider.value)
                        );
                        announceToScreenReader('Rango de color seleccionado');
                    }
                }
            ]
        });
    }

    // =====================================================================
    // Batch 7C: Filters
    // =====================================================================

    function applyDenoise(ctx, strength) {
        strength = strength || 5;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const patchSize = 3;
        const half = Math.floor(patchSize / 2);
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let sumR = 0, sumG = 0, sumB = 0, totalW = 0;
                for (let dy = -strength; dy <= strength; dy++) {
                    for (let dx = -strength; dx <= strength; dx++) {
                        const nx = x + dx, ny = y + dy;
                        if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                        let diff = 0;
                        for (let py = -half; py <= half; py++) {
                            for (let px = -half; px <= half; px++) {
                                const sx1 = x + px, sy1 = y + py, sx2 = nx + px, sy2 = ny + py;
                                if (sx1 >= 0 && sx1 < w && sy1 >= 0 && sy1 < h && sx2 >= 0 && sx2 < w && sy2 >= 0 && sy2 < h) {
                                    const i1 = (sy1 * w + sx1) * 4, i2 = (sy2 * w + sx2) * 4;
                                    diff += Math.abs(sd[i1] - sd[i2]) + Math.abs(sd[i1 + 1] - sd[i2 + 1]) + Math.abs(sd[i1 + 2] - sd[i2 + 2]);
                                }
                            }
                        }
                        const wt = Math.exp(-diff / (strength * strength * 100));
                        const ni = (ny * w + nx) * 4;
                        sumR += sd[ni] * wt; sumG += sd[ni + 1] * wt; sumB += sd[ni + 2] * wt;
                        totalW += wt;
                    }
                }
                const i = (y * w + x) * 4;
                dd[i] = totalW > 0 ? sumR / totalW : sd[i];
                dd[i + 1] = totalW > 0 ? sumG / totalW : sd[i + 1];
                dd[i + 2] = totalW > 0 ? sumB / totalW : sd[i + 2];
                dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applyBilateral(ctx, radius, sigmaSpace, sigmaColor) {
        radius = radius || 3; sigmaSpace = sigmaSpace || 3; sigmaColor = sigmaColor || 25;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let sumR = 0, sumG = 0, sumB = 0, totalW = 0;
                for (let dy = -radius; dy <= radius; dy++) {
                    for (let dx = -radius; dx <= radius; dx++) {
                        const nx = x + dx, ny = y + dy;
                        if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                        const ci = (y * w + x) * 4, ni = (ny * w + nx) * 4;
                        const spatialDist = dx * dx + dy * dy;
                        const colorDist = (sd[ci] - sd[ni]) ** 2 + (sd[ci + 1] - sd[ni + 1]) ** 2 + (sd[ci + 2] - sd[ni + 2]) ** 2;
                        const wt = Math.exp(-spatialDist / (2 * sigmaSpace * sigmaSpace)) * Math.exp(-colorDist / (2 * sigmaColor * sigmaColor));
                        sumR += sd[ni] * wt; sumG += sd[ni + 1] * wt; sumB += sd[ni + 2] * wt;
                        totalW += wt;
                    }
                }
                const i = (y * w + x) * 4;
                dd[i] = sumR / totalW; dd[i + 1] = sumG / totalW; dd[i + 2] = sumB / totalW; dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applyKuwahara(ctx, radius) {
        radius = radius || 3;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let means = [], vars = [];
                for (let q = 0; q < 4; q++) {
                    let sum = [0, 0, 0], sumSq = [0, 0, 0], count = 0;
                    const ox = q % 2 === 0 ? -1 : 0;
                    const oy = q < 2 ? -1 : 0;
                    for (let dy = oy; dy <= oy + radius; dy++) {
                        for (let dx = ox; dx <= ox + radius; dx++) {
                            const nx = x + dx, ny = y + dy;
                            if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                                const i = (ny * w + nx) * 4;
                                for (let c = 0; c < 3; c++) { sum[c] += sd[i + c]; sumSq[c] += sd[i + c] * sd[i + c]; }
                                count++;
                            }
                        }
                    }
                    const m = sum.map(s => s / count);
                    const v = sumSq.map((sq, c) => sq / count - m[c] * m[c]);
                    means.push(m); vars.push(v.reduce((a, b) => a + b, 0));
                }
                let minVar = Infinity, bestIdx = 0;
                vars.forEach((v, i) => { if (v < minVar) { minVar = v; bestIdx = i; } });
                const i = (y * w + x) * 4;
                dd[i] = means[bestIdx][0]; dd[i + 1] = means[bestIdx][1]; dd[i + 2] = means[bestIdx][2]; dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    function applyTiltShift(ctx, focalY, focalRange, blurAmount) {
        focalY = focalY || ctx.canvas.height / 2;
        focalRange = focalRange || ctx.canvas.height * 0.3;
        blurAmount = blurAmount || 6;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const blurred = document.createElement('canvas');
        blurred.width = w; blurred.height = h;
        const bctx = blurred.getContext('2d');
        bctx.putImageData(src, 0, 0);
        applyGaussianBlur(blurred, blurAmount);
        const bd = bctx.getImageData(0, 0, w, h).data;
        for (let y = 0; y < h; y++) {
            const dist = Math.abs(y - focalY);
            const blend = Math.min(1, Math.max(0, (dist - focalRange) / (h * 0.3)));
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                dd[i] = Math.round(sd[i] * (1 - blend) + bd[i] * blend);
                dd[i + 1] = Math.round(sd[i + 1] * (1 - blend) + bd[i + 1] * blend);
                dd[i + 2] = Math.round(sd[i + 2] * (1 - blend) + bd[i + 2] * blend);
                dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // =====================================================================
    // Batch 7D: Color
    // =====================================================================

    function computeHistogram(ctx) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const d = src.data;
        const hist = { r: new Uint32Array(256), g: new Uint32Array(256), b: new Uint32Array(256), lum: new Uint32Array(256) };
        for (let i = 0; i < d.length; i += 4) {
            hist.r[d[i]]++;
            hist.g[d[i + 1]]++;
            hist.b[d[i + 2]]++;
            hist.lum[Math.round(0.299 * d[i] + 0.587 * d[i + 1] + 0.114 * d[i + 2])]++;
        }
        return hist;
    }
    function renderHistogram(canvasId) {
        const canvas = document.getElementById(canvasId);
        if (!canvas) return;
        const layer = getActiveLayer();
        if (!layer) return;
        const hist = computeHistogram(layer.ctx);
        const ctx = canvas.getContext('2d');
        const w = canvas.width, h = canvas.height;
        ctx.clearRect(0, 0, w, h);
        ctx.fillStyle = '#1a1a1a';
        ctx.fillRect(0, 0, w, h);
        const max = Math.max(...hist.lum);
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        for (let i = 0; i < 256; i++) {
            const bh = (hist.lum[i] / max) * h;
            ctx.fillRect(i * w / 256, h - bh, w / 256 + 1, bh);
        }
        ['r', 'g', 'b'].forEach((ch, ci) => {
            const colors = ['rgba(255,0,0,0.4)', 'rgba(0,255,0,0.4)', 'rgba(0,0,255,0.4)'];
            ctx.fillStyle = colors[ci];
            const chMax = Math.max(...hist[ch]);
            for (let i = 0; i < 256; i++) {
                const bh = (hist[ch][i] / chMax) * h * 0.5;
                ctx.fillRect(i * w / 256, h - bh, w / 256 + 1, bh);
            }
        });
    }

    function applyTemperatureTint(ctx, temp, tint) {
        temp = temp || 0; tint = tint || 0;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let i = 0; i < d.length; i += 4) {
            d[i] = Math.max(0, Math.min(255, d[i] + temp));
            d[i + 1] = Math.max(0, Math.min(255, d[i + 1] + tint));
            d[i + 2] = Math.max(0, Math.min(255, d[i + 2] - temp));
        }
        ctx.putImageData(imgData, 0, 0);
    }

    // =====================================================================
    // Batch 7E: Masking
    // =====================================================================

    function createChannelMask(channel) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        const maskData = new ImageData(w, h);
        const sd = src.data, md = maskData.data;
        const ci = channel === 'red' ? 0 : channel === 'green' ? 1 : channel === 'blue' ? 2 : 3;
        for (let i = 0; i < sd.length; i += 4) {
            const val = sd[i + ci];
            md[i] = md[i + 1] = md[i + 2] = val;
            md[i + 3] = 255;
        }
        layer.maskData = maskData;
        compositeDirty = true; renderComposite();
    }

    function createGradientMask(startY, endY) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const maskData = new ImageData(w, h);
        const md = maskData.data;
        for (let y = 0; y < h; y++) {
            const t = Math.max(0, Math.min(1, (y - startY) / (endY - startY)));
            const val = Math.round(t * 255);
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                md[i] = md[i + 1] = md[i + 2] = val; md[i + 3] = 255;
            }
        }
        layer.maskData = maskData;
        compositeDirty = true; renderComposite();
    }

    let maskPaintMode = false;
    function paintOnMask(ctx, x, y, radius, erase) {
        if (!maskPaintMode) return;
        const layer = getActiveLayer();
        if (!layer || !layer.maskData) return;
        const md = layer.maskData.data;
        const w = layer.maskData.width, h = layer.maskData.height;
        const px = Math.round(x * dpr), py = Math.round(y * dpr);
        const r = Math.round(radius * dpr);
        const val = erase ? 0 : 255;
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                if (dx * dx + dy * dy > r * r) continue;
                const nx = px + dx, ny = py + dy;
                if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                    const i = (ny * w + nx) * 4;
                    md[i] = md[i + 1] = md[i + 2] = val;
                }
            }
        }
        compositeDirty = true; renderComposite();
    }

    // =====================================================================
    // Batch 7F: Workflow
    // =====================================================================

    function renameLayer(idx, newName) {
        if (idx >= 0 && idx < layers.length) {
            layers[idx].name = newName;
            renderLayersUI();
        }
    }

    function autoArrangeLayers() {
        const named = layers.filter(l => l.name.match(/^Capa \d+$/));
        const unnamed = layers.filter(l => !l.name.match(/^Capa \d+$/));
        named.sort((a, b) => {
            const na = parseInt(a.name.match(/\d+/)?.[0] || '0');
            const nb = parseInt(b.name.match(/\d+/)?.[0] || '0');
            return na - nb;
        });
        layers.length = 0;
        layers.push(...unnamed, ...named);
        activeLayerIndex = Math.min(activeLayerIndex, layers.length - 1);
        renderLayersUI();
    }

    function filterLayers(query) {
        query = query.toLowerCase();
        return layers.filter(l => l.name.toLowerCase().includes(query));
    }

    function getHistoryList() {
        return history.map((s, i) => ({
            index: i,
            name: s.name || `Estado ${i + 1}`,
            timestamp: s.timestamp || Date.now(),
            isCurrent: i === historyStep
        }));
    }

    // =====================================================================
    // Batch 7G: View
    // =====================================================================

    let splitViewActive = false;
    let splitViewX = 0.5;
    function toggleSplitView() {
        splitViewActive = !splitViewActive;
        compositeDirty = true; renderComposite();
    }
    function renderSplitView(ctx) {
        if (!splitViewActive) return;
        ctx.save();
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        ctx.beginPath();
        ctx.moveTo(ctx.canvas.width * splitViewX, 0);
        ctx.lineTo(ctx.canvas.width * splitViewX, ctx.canvas.height);
        ctx.stroke();
        ctx.restore();
    }

    let pixelGridEnabled = false;
    function renderPixelGrid(ctx) {
        if (!pixelGridEnabled || transform.scale < 4) return;
        ctx.save();
        ctx.strokeStyle = 'rgba(255,255,255,0.15)';
        ctx.lineWidth = 0.5;
        const step = dpr;
        for (let x = 0; x < ctx.canvas.width; x += step) {
            ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, ctx.canvas.height); ctx.stroke();
        }
        for (let y = 0; y < ctx.canvas.height; y += step) {
            ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(ctx.canvas.width, y); ctx.stroke();
        }
        ctx.restore();
    }

    let maskOverlayVisible = false;
    function renderMaskOverlay(ctx) {
        if (!maskOverlayVisible) return;
        layers.forEach(layer => {
            if (layer.maskData && layer.visible) {
                ctx.save();
                ctx.globalAlpha = 0.4;
                ctx.fillStyle = 'rgba(255,0,0,1)';
                const md = layer.maskData.data;
                for (let y = 0; y < layer.maskData.height; y += 4) {
                    for (let x = 0; x < layer.maskData.width; x += 4) {
                        const i = (y * layer.maskData.width + x) * 4;
                        if (md[i] < 128) {
                            ctx.fillRect(x / dpr, y / dpr, 4 / dpr, 4 / dpr);
                        }
                    }
                }
                ctx.restore();
            }
        });
    }

    // =====================================================================
    // Batch 7H: Animation Improvements
    // =====================================================================

    let onionSkinColorPrev = 'rgba(255,100,100,';
    let onionSkinColorNext = 'rgba(100,100,255,';
    function setOnionSkinColors(prev, next) { onionSkinColorPrev = prev; onionSkinColorNext = next; }

    function renderMotionPath(ctx) {
        if (animFrames.length < 2) return;
        ctx.save();
        ctx.strokeStyle = 'rgba(0,255,0,0.5)';
        ctx.lineWidth = 1;
        ctx.setLineDash([3, 3]);
        ctx.beginPath();
        animFrames.forEach((frame, i) => {
            if (frame.layers.length === 0) return;
            const tc = document.createElement('canvas');
            tc.width = frame.layers[0].canvas.width; tc.height = frame.layers[0].canvas.height;
            const tctx = tc.getContext('2d');
            frame.layers.forEach(fl => { if (fl.visible) tctx.drawImage(fl.canvas, 0, 0); });
            const cx = tc.width / 2, cy = tc.height / 2;
            if (i === 0) ctx.moveTo(cx / dpr, cy / dpr);
            else ctx.lineTo(cx / dpr, cy / dpr);
        });
        ctx.stroke();
        ctx.restore();
    }

    let timelineZoomLevel = 1;
    function setTimelineZoom(level) { timelineZoomLevel = Math.max(0.5, Math.min(3, level)); }

    // =====================================================================
    // Batch 7I: Export
    // =====================================================================

    function exportAsWebP(quality) {
        quality = quality || 0.9;
        compositeCanvas.toBlob(blob => {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url; a.download = 'procreate-lite-export.webp'; a.click();
            URL.revokeObjectURL(url);
        }, 'image/webp', quality);
    }

    function generateExportFilename(template) {
        const now = new Date();
        return template
            .replace('{date}', now.toISOString().slice(0, 10))
            .replace('{time}', now.toTimeString().slice(0, 8).replace(/:/g, '-'))
            .replace('{width}', logicalWidth)
            .replace('{height}', logicalHeight)
            .replace('{layer}', getActiveLayer()?.name || 'unknown')
            .replace('{project}', 'procreate-lite');
    }

    // =====================================================================
    // Batch 7J: Advanced Tools
    // =====================================================================

    function createSeamlessPattern(sourceCanvas, tileSize) {
        tileSize = tileSize || 64;
        const tc = document.createElement('canvas');
        tc.width = tileSize; tc.height = tileSize;
        const tctx = tc.getContext('2d');
        const sw = sourceCanvas.width, sh = sourceCanvas.height;
        tctx.drawImage(sourceCanvas, 0, 0, sw / 2, sh / 2, 0, 0, tileSize / 2, tileSize / 2);
        tctx.drawImage(sourceCanvas, sw / 2, 0, sw / 2, sh / 2, tileSize / 2, 0, tileSize / 2, tileSize / 2);
        tctx.drawImage(sourceCanvas, 0, sh / 2, sw / 2, sh / 2, 0, tileSize / 2, tileSize / 2, tileSize / 2);
        tctx.drawImage(sourceCanvas, sw / 2, sh / 2, sw / 2, sh / 2, tileSize / 2, tileSize / 2, tileSize / 2, tileSize / 2);
        return tc;
    }

    function applyDodgeBurn(ctx, x, y, radius, exposure, mode) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const factor = mode === 'dodge' ? exposure / 100 : -exposure / 100;
        for (let dy = -radius; dy <= radius; dy++) {
            for (let dx = -radius; dx <= radius; dx++) {
                const nx = Math.round(x) + dx, ny = Math.round(y) + dy;
                if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                const dist = Math.sqrt(dx * dx + dy * dy);
                if (dist > radius) continue;
                const wt = 1 - dist / radius;
                const i = (ny * w + nx) * 4;
                for (let c = 0; c < 3; c++) {
                    if (factor > 0) d[i + c] = Math.min(255, d[i + c] + d[i + c] * factor * wt);
                    else d[i + c] = Math.max(0, d[i + c] + d[i + c] * factor * wt);
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function applySponge(ctx, x, y, radius, strength, mode) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const factor = mode === 'saturate' ? strength / 100 : -strength / 100;
        for (let dy = -radius; dy <= radius; dy++) {
            for (let dx = -radius; dx <= radius; dx++) {
                const nx = Math.round(x) + dx, ny = Math.round(y) + dy;
                if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                const dist = Math.sqrt(dx * dx + dy * dy);
                if (dist > radius) continue;
                const wt = 1 - dist / radius;
                const i = (ny * w + nx) * 4;
                const gray = 0.299 * d[i] + 0.587 * d[i + 1] + 0.114 * d[i + 2];
                for (let c = 0; c < 3; c++) {
                    d[i + c] = Math.max(0, Math.min(255, Math.round(d[i + c] + (d[i + c] - gray) * factor * wt)));
                }
            }
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function drawAdvancedGradient(ctx, x1, y1, x2, y2, colors, type) {
        type = type || 'linear';
        const w = ctx.canvas.width, h = ctx.canvas.height;
        if (type === 'linear') {
            const angle = Math.atan2(y2 - y1, x2 - x1);
            const len = Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
            const grad = ctx.createLinearGradient(x1, y1, x2, y2);
            colors.forEach((c, i) => grad.addColorStop(i / (colors.length - 1), c));
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, w, h);
        } else if (type === 'radial') {
            const cx = (x1 + x2) / 2, cy = (y1 + y2) / 2;
            const r = Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2) / 2;
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
            colors.forEach((c, i) => grad.addColorStop(i / (colors.length - 1), c));
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, w, h);
        } else if (type === 'angle') {
            const cx = (x1 + x2) / 2, cy = (y1 + y2) / 2;
            for (let a = 0; a < 360; a++) {
                const t = a / 360;
                const rad = a * Math.PI / 180;
                const ci = Math.floor(t * (colors.length - 1));
                const ct = t * (colors.length - 1) - ci;
                ctx.strokeStyle = colors[Math.min(ci + 1, colors.length - 1)];
                ctx.lineWidth = 3;
                ctx.beginPath();
                ctx.moveTo(cx, cy);
                ctx.lineTo(cx + Math.cos(rad) * 500, cy + Math.sin(rad) * 500);
                ctx.stroke();
            }
        } else if (type === 'reflected') {
            const grad = ctx.createLinearGradient(x1, y1, x1, y2);
            colors.forEach((c, i) => { const t = i / (colors.length - 1); grad.addColorStop(t < 0.5 ? t * 2 : 1 - (t - 0.5) * 2, c); });
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, w, h);
        } else if (type === 'diamond') {
            const cx = (x1 + x2) / 2, cy = (y1 + y2) / 2;
            const r = Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2) / 2;
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
            colors.forEach((c, i) => grad.addColorStop(i / (colors.length - 1), c));
            ctx.fillStyle = grad;
            ctx.save();
            ctx.translate(cx, cy);
            ctx.rotate(Math.PI / 4);
            ctx.scale(1, 0.5);
            ctx.translate(-cx, -cy);
            ctx.fillRect(0, 0, w, h);
            ctx.restore();
        }
    }

    // =====================================================================
    // Batch 7K: Misc
    // =====================================================================

    function duplicateCanvas() {
        if (layers.length >= MAX_LAYERS) { alert('Límite de capas alcanzado'); return; }
        const layer = getActiveLayer();
        if (!layer) return;
        const { canvas: newCanvas, ctx: newCtx } = createLayerEl();
        newCanvas.width = layer.canvas.width; newCanvas.height = layer.canvas.height;
        newCtx.drawImage(layer.canvas, 0, 0);
        const dup = { id: `layer-${layerIdCounter++}`, name: `${layer.name} copia`, canvas: newCanvas, ctx: newCtx, visible: true, opacity: layer.opacity, alphaLock: false, blendMode: layer.blendMode, maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) };
        layers.push(dup);
        activeLayerIndex = layers.length - 1;
        renderLayersUI(); compositeDirty = true; renderComposite();
    }

    function flipCanvas(axis) {
        layers.forEach(layer => {
            const tc = document.createElement('canvas');
            tc.width = layer.canvas.width; tc.height = layer.canvas.height;
            const tctx = tc.getContext('2d');
            if (axis === 'horizontal') { tctx.scale(-1, 1); tctx.drawImage(layer.canvas, -tc.width, 0); }
            else { tctx.scale(1, -1); tctx.drawImage(layer.canvas, 0, -tc.height); }
            layer.ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
            layer.ctx.drawImage(tc, 0, 0);
        });
        saveState(); compositeDirty = true; renderComposite();
    }

    function zoomToFit() {
        const wrapperRect = document.getElementById('canvas-wrapper')?.getBoundingClientRect();
        if (!wrapperRect) return;
        const fitScale = Math.min(wrapperRect.width / logicalWidth, wrapperRect.height / logicalHeight) * 0.9;
        transform.scale = fitScale;
        transform.x = (wrapperRect.width - logicalWidth * fitScale) / 2;
        transform.y = (wrapperRect.height - logicalHeight * fitScale) / 2;
        updateTransform(); compositeDirty = true; renderComposite();
    }
    function zoomTo100() {
        transform.scale = 1;
        const wrapperRect = document.getElementById('canvas-wrapper')?.getBoundingClientRect();
        if (wrapperRect) {
            transform.x = (wrapperRect.width - logicalWidth) / 2;
            transform.y = (wrapperRect.height - logicalHeight) / 2;
        }
        updateTransform(); compositeDirty = true; renderComposite();
    }

    function renderNavigator(navigatorCanvas) {
        if (!navigatorCanvas) return;
        const ctx = navigatorCanvas.getContext('2d');
        const nw = navigatorCanvas.width, nh = navigatorCanvas.height;
        ctx.clearRect(0, 0, nw, nh);
        ctx.fillStyle = '#1a1a1a';
        ctx.fillRect(0, 0, nw, nh);
        const scale = Math.min(nw / logicalWidth, nh / logicalHeight);
        ctx.save();
        ctx.scale(scale, scale);
        layers.forEach(l => { if (l.visible) ctx.drawImage(l.canvas, 0, 0, logicalWidth, logicalHeight); });
        ctx.restore();
        ctx.strokeStyle = '#00ff00';
        ctx.lineWidth = 2;
        const vw = (compositeCanvas.width / dpr) / transform.scale;
        const vh = (compositeCanvas.height / dpr) / transform.scale;
        const vx = -transform.x / transform.scale;
        const vy = -transform.y / transform.scale;
        ctx.strokeRect(vx * scale, vy * scale, vw * scale, vh * scale);
    }

