    // --- Batch 8H: UI ---

    // Canvas Background Color Picker
    let canvasBgColor = '#ffffff';
    let canvasTransparent = false;
    function setCanvasBgColor(color) {
        canvasBgColor = color;
        canvasTransparent = (color === 'transparent');
        updateCanvasBgElement();
        compositeDirty = true; renderComposite();
    }
    function toggleCanvasTransparent() {
        canvasTransparent = !canvasTransparent;
        if (canvasTransparent) {
            canvasBgColor = 'transparent';
        } else {
            canvasBgColor = '#ffffff';
        }
        updateCanvasBgElement();
        compositeDirty = true; renderComposite();
        showToast(canvasTransparent ? 'Fondo transparente' : 'Fondo blanco');
    }
    function updateCanvasBgElement() {
        const bgEl = document.querySelector('.canvas-layer.bg-layer');
        if (bgEl) {
            if (canvasTransparent) {
                bgEl.classList.add('bg-transparent');
                bgEl.style.backgroundColor = '';
                bgEl.style.backgroundImage = '';
            } else {
                bgEl.classList.remove('bg-transparent');
                bgEl.style.backgroundColor = canvasBgColor;
                bgEl.style.backgroundImage = '';
            }
        }
    }

    // What's New / Changelog Panel
    const changelog = [
        { version: '7.0', features: ['Batch 7: Brush engine, selection tools, filters, color, masking, workflow, view, animation, export, advanced tools, misc'] },
        { version: '8.0', features: ['Batch 8: Median/morphological filters, channel mixer, quick selection, magnetic lasso, layer comps, keyframe interpolation, text presets, sprite sheet export, named colors, color history, navigator, debug panel'] }
    ];
    function showChangelog() {
        return changelog.map(v => `v${v.version}: ${v.features.join(', ')}`).join('\n\n');
    }

    // Debug Info Panel
    function getDebugInfo() {
        return {
            fps: currentFPS || 0,
            layerCount: layers.length,
            memoryEstimate: layers.reduce((sum, l) => sum + l.canvas.width * l.canvas.height * 4, 0),
            zoom: Math.round(transform.scale * 100) + '%',
            canvasSize: `${logicalWidth}x${logicalHeight}`,
            dpr: dpr,
            undoStates: history.length,
            animFrames: animFrames.length,
            selectionActive: !!selectionData
        };
    }
    function renderDebugPanel() {
        const el = document.getElementById('debug-info');
        if (!el) return;
        const info = getDebugInfo();
        el.innerHTML = `FPS: ${info.fps}<br>Capas: ${info.layerCount}<br>Zoom: ${info.zoom}<br>Canvas: ${info.canvasSize}<br>DPR: ${info.dpr}<br>RAM: ~${Math.round(info.memoryEstimate / 1024 / 1024)}MB<br>Undos: ${info.undoStates}<br>Cuadros: ${info.animFrames}<br>Selección: ${info.selectionActive ? 'Sí' : 'No'}`;
    }
    let currentFPS = 0;
    let fpsFrames = 0;
    let fpsLastTime = performance.now();
    function trackFPS() {
        fpsFrames++;
        const now = performance.now();
        if (now - fpsLastTime >= 1000) { currentFPS = fpsFrames; fpsFrames = 0; fpsLastTime = now; }
        requestAnimationFrame(trackFPS);
    }

    // Navigator Minimap HTML Canvas
    function initNavigator() {
        const el = document.getElementById('navigator-canvas');
        if (el) { el.width = 160; el.height = 120; }
    }

    // --- Batch 8I: Workflow ---

    // Solo Mode (hide all except active)
    let soloMode = false;
    function toggleSoloMode() {
        soloMode = !soloMode;
        if (soloMode) {
            layers.forEach((l, i) => { l._preSoloVisible = l.visible; l.visible = (i === activeLayerIndex); });
        } else {
            layers.forEach(l => { l.visible = l._preSoloVisible !== undefined ? l._preSoloVisible : true; delete l._preSoloVisible; });
        }
        compositeDirty = true; renderComposite(); renderLayersUI();
    }

    // Flatten Visible Only
    function flattenVisibleOnly() {
        const visibleLayers = layers.filter(l => l.visible);
        if (visibleLayers.length === 0) return;
        const { canvas: newCanvas, ctx: newCtx } = createLayerEl();
        newCanvas.width = logicalWidth * dpr; newCanvas.height = logicalHeight * dpr;
        newCtx.scale(dpr, dpr);
        newCtx.fillStyle = '#ffffff'; newCtx.fillRect(0, 0, newCanvas.width, newCanvas.height);
        visibleLayers.forEach(l => {
            newCtx.save();
            newCtx.globalAlpha = l.opacity;
            newCtx.globalCompositeOperation = l.blendMode || 'source-over';
            newCtx.drawImage(l.canvas, 0, 0);
            newCtx.restore();
        });
        const flat = { id: `layer-${layerIdCounter++}`, name: 'Visibles combinadas', canvas: newCanvas, ctx: newCtx, visible: true, opacity: 1, alphaLock: false, blendMode: 'source-over', maskData: null, clippingMask: false, effects: JSON.parse(JSON.stringify(defaultEffects)) };
        layers = layers.filter(l => !l.visible);
        layers.push(flat);
        activeLayerIndex = layers.length - 1;
        renderLayersUI(); compositeDirty = true; renderComposite();
    }

    // --- Batch 8J: Advanced ---

    // Content-Aware Resize (simplified seam carving)
    function contentAwareResize(newWidth) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const diff = newWidth - w;
        if (diff === 0) return;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        // Find vertical seams (energy-based)
        const energy = new Float32Array(w * h);
        for (let y = 1; y < h - 1; y++) {
            for (let x = 1; x < w - 1; x++) {
                const i = (y * w + x) * 4;
                const gx = Math.abs(d[i - 4] - d[i + 4]) + Math.abs(d[i - 4 + 1] - d[i + 4 + 1]) + Math.abs(d[i - 4 + 2] - d[i + 4 + 2]);
                const gy = Math.abs(d[(y - 1) * w + x] * 4 - d[(y + 1) * w + x] * 4) + Math.abs(d[(y - 1) * w + x] * 4 + 1 - d[(y + 1) * w + x] * 4 + 1);
                energy[y * w + x] = gx + gy;
            }
        }
        // Remove or add seams
        const tc = document.createElement('canvas');
        tc.width = newWidth; tc.height = h;
        const tctx = tc.getContext('2d');
        const srcData = layer.ctx.getImageData(0, 0, w, h);
        if (diff < 0) {
            // Remove |diff| seams
            const newImg = tctx.createImageData(newWidth, h);
            const nd = newImg.data;
            const removeCount = Math.min(Math.abs(diff), w - 10);
            const skipX = Math.floor(w / 2);
            for (let y = 0; y < h; y++) {
                let nx = 0;
                for (let x = 0; x < w; x++) {
                    if (nx >= newWidth) break;
                    const si = (y * w + x) * 4;
                    const di = (y * newWidth + nx) * 4;
                    if (Math.abs(x - skipX) < removeCount / 2) continue;
                    nd[di] = srcData.data[si]; nd[di + 1] = srcData.data[si + 1]; nd[di + 2] = srcData.data[si + 2]; nd[di + 3] = srcData.data[si + 3];
                    nx++;
                }
            }
            tctx.putImageData(newImg, 0, 0);
        } else {
            // Duplicate center columns
            tctx.drawImage(layer.canvas, 0, 0);
            const addCount = diff;
            const insertX = Math.floor(w / 2);
            const stripData = layer.ctx.getImageData(insertX, 0, 2, h);
            tctx.putImageData(stripData, insertX, 0);
            tctx.putImageData(stripData, insertX + 2, 0);
        }
        layer.canvas.width = newWidth; layer.canvas.height = h;
        layer.ctx.drawImage(tc, 0, 0);
        saveState(); compositeDirty = true; renderComposite();
    }

    // Inpainting (fill from surrounding)
    function inpaintArea(x, y, radius) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const imgData = layer.ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        const r = Math.round(radius);
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                if (dx * dx + dy * dy > r * r) continue;
                const nx = Math.round(x) + dx, ny = Math.round(y) + dy;
                if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                // Sample from nearest non-target pixel
                let sr = 0, sg = 0, sb = 0, sc = 0;
                for (let sy = -2; sy <= 2; sy++) {
                    for (let sx = -2; sx <= 2; sx++) {
                        const sx2 = nx + sx * 5, sy2 = ny + sy * 5;
                        if (sx2 >= 0 && sx2 < w && sy2 >= 0 && sy2 < h) {
                            const dist2 = sx * sx + sy * sy;
                            if (dist2 > 4) {
                                const si = (sy2 * w + sx2) * 4;
                                sr += d[si]; sg += d[si + 1]; sb += d[si + 2]; sc++;
                            }
                        }
                    }
                }
                if (sc > 0) {
                    const i = (ny * w + nx) * 4;
                    d[i] = sr / sc; d[i + 1] = sg / sc; d[i + 2] = sb / sc;
                }
            }
        }
        layer.ctx.putImageData(imgData, 0, 0);
        saveState(); compositeDirty = true; renderComposite();
    }

