    // --- iPad Optimization: Chunked Pixel Processing ---
    function processPixelsChunked(imgData, processFn, chunkSize) {
        chunkSize = chunkSize || deviceInfo.filterChunkSize;
        const d = imgData.data;
        const total = d.length;
        let offset = 0;
        function processChunk() {
            const end = Math.min(offset + chunkSize * 4, total);
            for (let i = offset; i < end; i += 4) {
                processFn(d, i);
            }
            offset = end;
            if (offset < total) {
                requestAnimationFrame(processChunk);
            }
        }
        processChunk();
    }

    // --- Memory Pressure Detection ---
    let memoryWarningShown = false;
    function checkMemoryPressure() {
        if (!deviceInfo.isLowEnd) return;
        const estimatedMB = layers.reduce((sum, l) => sum + l.canvas.width * l.canvas.height * 4, 0) / 1024 / 1024;
        const historyMB = history.reduce((sum, state) => {
            return sum + state.reduce((s, entry) => s + (entry.canvas ? entry.canvas.length * 0.75 : 0), 0);
        }, 0) / 1024 / 1024;
        const totalMB = estimatedMB + historyMB;
        if (totalMB > 500 && !memoryWarningShown) {
            memoryWarningShown = true;
            showToast(`Memoria alta: ~${Math.round(totalMB)}MB. Considera reducir capas o historial.`);
        }
        if (totalMB > 800) {
            // Aggressively trim history
            while (history.length > 5) history.shift();
            historyStep = Math.min(historyStep, history.length - 1);
        }
    }
    // Check memory every 30 seconds
    setInterval(checkMemoryPressure, 30000);

