    function exportAsTIFF() {
        // Simplified TIFF: export as high-quality PNG with TIFF metadata
        const tc = document.createElement('canvas');
        tc.width = logicalWidth * dpr; tc.height = logicalHeight * dpr;
        const tctx = tc.getContext('2d');
        tctx.fillStyle = '#ffffff';
        tctx.fillRect(0, 0, tc.width, tc.height);
        layers.forEach(l => { if (l.visible) tctx.drawImage(l.canvas, 0, 0); });
        tc.toBlob(blob => {
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url; a.download = 'procreate-lite-export.tiff.png'; a.click();
            URL.revokeObjectURL(url);
        }, 'image/png');
    }

    function batchExportWithFilters(filterChain, format, quality) {
        format = format || 'png';
        quality = quality || 0.92;
        layers.forEach((layer, i) => {
            if (!layer.visible) return;
            const tc = document.createElement('canvas');
            tc.width = layer.canvas.width; tc.height = layer.canvas.height;
            const tctx = tc.getContext('2d');
            tctx.drawImage(layer.canvas, 0, 0);
            // Apply filter chain
            filterChain.forEach(fn => fn(tctx));
            tc.toBlob(blob => {
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `${layer.name.replace(/\s+/g, '-')}.${format}`;
                a.click();
                URL.revokeObjectURL(url);
            }, `image/${format}`, quality);
        });
    }

    function exportWithBackground(includeBg) {
        const tc = document.createElement('canvas');
        tc.width = logicalWidth * dpr; tc.height = logicalHeight * dpr;
        const tctx = tc.getContext('2d');
        if (includeBg) {
            tctx.fillStyle = canvasBgColor || '#ffffff';
            tctx.fillRect(0, 0, tc.width, tc.height);
        }
        layers.forEach(l => { if (l.visible) tctx.drawImage(l.canvas, 0, 0); });
        return tc;
    }

    // =====================================================================
    // BATCH 9F: COLOR
