    let colorGroups = [];
    function createColorGroup(name) {
        const group = { name, colors: [] };
        colorGroups.push(group);
        try { localStorage.setItem('procreate-lite-color-groups', JSON.stringify(colorGroups)); } catch (e) { }
        return group;
    }
    function addColorToGroup(groupName, color) {
        const group = colorGroups.find(g => g.name === groupName);
        if (group && !group.colors.includes(color)) {
            group.colors.push(color);
            try { localStorage.setItem('procreate-lite-color-groups', JSON.stringify(colorGroups)); } catch (e) { }
        }
    }
    function removeColorFromGroup(groupName, color) {
        const group = colorGroups.find(g => g.name === groupName);
        if (group) {
            group.colors = group.colors.filter(c => c !== color);
            try { localStorage.setItem('procreate-lite-color-groups', JSON.stringify(colorGroups)); } catch (e) { }
        }
    }
    function loadColorGroups() {
        try { colorGroups = JSON.parse(localStorage.getItem('procreate-lite-color-groups') || '[]'); } catch (e) { colorGroups = []; }
    }

    function gamutMapColor(r, g, b) {
        // Simple sRGB gamut mapping: clamp out-of-gamut to nearest in-gamut
        let max = Math.max(r, g, b);
        if (max <= 255) return { r, g, b };
        const ratio = 255 / max;
        return { r: Math.round(r * ratio), g: Math.round(g * ratio), b: Math.round(b * ratio) };
    }
    function applyGamutMapping(ctx) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const imgData = ctx.getImageData(0, 0, w, h);
        const d = imgData.data;
        for (let i = 0; i < d.length; i += 4) {
            const mapped = gamutMapColor(d[i], d[i + 1], d[i + 2]);
            d[i] = mapped.r; d[i + 1] = mapped.g; d[i + 2] = mapped.b;
        }
        ctx.putImageData(imgData, 0, 0);
    }

