    // =====================================================================
    // BATCH 9H: ADVANCED
    // =====================================================================

    let perspWarpActive = false;
    let perspWarpPoints = [];
    function startPerspWarp() { perspWarpActive = true; perspWarpPoints = []; }
    function addPerspWarpPoint(x, y) {
        if (perspWarpPoints.length < 4) perspWarpPoints.push({ x, y });
    }
    function applyPerspWarp() {
        if (perspWarpPoints.length < 4) return;
        const layer = getActiveLayer();
        if (!layer) return;
        const src = perspWarpPoints;
        const w = layer.canvas.width, h = layer.canvas.height;
        // Compute bounding box of destination
        const dstW = Math.max(Math.abs(src[1].x - src[0].x), Math.abs(src[3].x - src[2].x)) * dpr;
        const dstH = Math.max(Math.abs(src[3].y - src[0].y), Math.abs(src[2].y - src[1].y)) * dpr;
        const tc = document.createElement('canvas');
        tc.width = dstW; tc.height = dstH;
        const tctx = tc.getContext('2d');
        const srcImg = layer.ctx.getImageData(0, 0, w, h);
        // Bilinear interpolation for perspective transform
        for (let dy = 0; dy < dstH; dy++) {
            for (let dx = 0; dx < dstW; dx++) {
                const u = dx / dstW, v = dy / dstH;
                const sx = (1 - v) * ((1 - u) * src[0].x * dpr + u * src[1].x * dpr) + v * ((1 - u) * src[3].x * dpr + u * src[2].x * dpr);
                const sy = (1 - v) * ((1 - u) * src[0].y * dpr + u * src[1].y * dpr) + v * ((1 - u) * src[3].y * dpr + u * src[2].y * dpr);
                const si = (Math.floor(sy) * w + Math.floor(sx)) * 4;
                const di = (dy * dstW + dx) * 4;
                if (si >= 0 && si < srcImg.data.length - 3) {
                    tctx.fillStyle = `rgba(${srcImg.data[si]},${srcImg.data[si + 1]},${srcImg.data[si + 2]},${srcImg.data[si + 3] / 255})`;
                    tctx.fillRect(dx, dy, 1, 1);
                }
            }
        }
        layer.canvas.width = dstW; layer.canvas.height = dstH;
        layer.ctx.drawImage(tc, 0, 0);
        saveState(); compositeDirty = true; renderComposite();
        perspWarpActive = false; perspWarpPoints = [];
    }

    const liquifyPresets = [
        { name: 'Fine', strength: 30, radius: 20 },
        { name: 'Medium', strength: 50, radius: 40 },
        { name: 'Large', strength: 70, radius: 60 },
        { name: 'Heavy', strength: 90, radius: 80 }
    ];
    let currentLiquifyPreset = 1;
    function applyLiquifyPreset(idx) {
        if (!liquifyPresets[idx]) return;
        currentLiquifyPreset = idx;
        const p = liquifyPresets[idx];
        document.getElementById('liquify-strength') && (document.getElementById('liquify-strength').value = p.strength);
    }

    shapeBuilderMode = 'combine';
    let shapeBuilderPaths = [];
    function addShapeBuilderPath(points) { shapeBuilderPaths.push(points); }
    function clearShapeBuilderPaths() { shapeBuilderPaths = []; }
    function executeShapeBuilder(ctx) {
        if (shapeBuilderPaths.length < 2) return;
        ctx.save();
        ctx.fillStyle = brushColor;
        ctx.globalAlpha = brushOpacity;
        ctx.beginPath();
        shapeBuilderPaths.forEach(path => {
            if (path.length < 3) return;
            ctx.moveTo(path[0].x, path[0].y);
            path.forEach((p, i) => { if (i > 0) ctx.lineTo(p.x, p.y); });
            ctx.closePath();
        });
        if (shapeBuilderMode === 'combine') ctx.fill('evenodd');
        else { ctx.globalCompositeOperation = 'destination-out'; ctx.fill('evenodd'); }
        ctx.restore();
shapeBuilderPaths = [];
     }

     // Export shape builder paths to SVG
     function exportShapeToSVG() {
         if (shapeBuilderPaths.length < 2) {
             showToast('No hay forma que exportar');
             return;
         }
         let svgPaths = '';
         shapeBuilderPaths.forEach((path, idx) => {
             if (path.length < 3) return;
             let d = `M ${path[0].x} ${path[0].y}`;
             for (let i = 1; i < path.length; i++) {
                 d += ` L ${path[i].x} ${path[i].y}`;
             }
             d += ' Z';
             svgPaths += `<path d="${d}" fill="${brushColor}" fill-rule="${shapeBuilderMode === 'combine' ? 'evenodd' : 'nonzero'}" />\n`;
         });
         const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${logicalWidth} ${logicalHeight}">\n${svgPaths}</svg>`;
         const blob = new Blob([svg], { type: 'image/svg+xml' });
         const url = URL.createObjectURL(blob);
         const a = document.createElement('a');
         a.href = url;
         a.download = `brush-shape-${Date.now()}.svg`;
         a.click();
         URL.revokeObjectURL(url);
         showToast('Forma exportada como SVG');
     }

     // Use for brush tip mask generation

    // =====================================================================
    // BATCH 9I: MISC
    // =====================================================================

    let canvasRotationGesture = false;
    let rotationGestureStart = 0;
    let rotationGestureAngle = 0;
    function handleRotationGesture(e) {
        if (e.touches.length === 2) {
            const dx = e.touches[0].clientX - e.touches[1].clientX;
            const dy = e.touches[0].clientY - e.touches[1].clientY;
            const angle = Math.atan2(dy, dx);
            if (e.type === 'touchstart') {
                rotationGestureStart = angle - rotationGestureAngle;
            } else if (e.type === 'touchmove') {
                rotationGestureAngle = angle - rotationGestureStart;
                transform.rotation = rotationGestureAngle;
                updateTransform();
            }
        }
    }

    let brushPreviewEl = null;
    let streamlineTrail = null;
    let streamlineTrailCtx = null;
    let streamlinePoints = [];
    const STREAMLINE_DELAY = 6;
    function updateBrushPreview(x, y, pressure = 1, angle = 0) {
        if (!brushPreviewEl) {
            brushPreviewEl = document.createElement('div');
            brushPreviewEl.style.cssText = 'position:fixed;border:1.5px solid rgba(255,255,255,0.6);border-radius:50%;pointer-events:none;z-index:9999;transform:translate(-50%,-50%);box-shadow:0 0 0 1px rgba(0,0,0,0.3);transition:width 0.08s,height 0.08s;';
            document.body.appendChild(brushPreviewEl);
        }
        const size = Math.max(4, brushSize * transform.scale);
        brushPreviewEl.style.left = x + 'px';
        brushPreviewEl.style.top = y + 'px';
        brushPreviewEl.style.width = size + 'px';
        brushPreviewEl.style.height = size + 'px';
        brushPreviewEl.style.display = 'block';
        brushPreviewEl.style.borderColor = currentMode === 'eraser' ? 'rgba(255,100,100,0.7)' : 'rgba(255,255,255,0.6)';
    }
    function hideBrushPreview() { if (brushPreviewEl) brushPreviewEl.style.display = 'none'; }

    function updateStreamlineTrail(x, y) {
        if (!streamlineTrail) {
            streamlineTrail = document.createElement('canvas');
            streamlineTrail.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9998;';
            streamlineTrail.width = window.innerWidth;
            streamlineTrail.height = window.innerHeight;
            streamlineTrailCtx = streamlineTrail.getContext('2d');
            document.body.appendChild(streamlineTrail);
        }
        streamlinePoints.push({ x, y, age: 0 });
        if (streamlinePoints.length > 40) streamlinePoints.shift();
        streamlineTrailCtx.clearRect(0, 0, streamlineTrail.width, streamlineTrail.height);
        if (streamlinePoints.length >= 2) {
            streamlineTrailCtx.beginPath();
            streamlineTrailCtx.moveTo(streamlinePoints[0].x, streamlinePoints[0].y);
            for (let i = 1; i < streamlinePoints.length; i++) {
                const p = streamlinePoints[i];
                const prev = streamlinePoints[i - 1];
                const cpx = (prev.x + p.x) / 2;
                const cpy = (prev.y + p.y) / 2;
                streamlineTrailCtx.quadraticCurveTo(prev.x, prev.y, cpx, cpy);
            }
            streamlineTrailCtx.strokeStyle = currentMode === 'eraser' ? 'rgba(255,100,100,0.3)' : 'rgba(255,255,255,0.2)';
            streamlineTrailCtx.lineWidth = Math.max(1, brushSize * transform.scale * 0.3);
            streamlineTrailCtx.lineCap = 'round';
            streamlineTrailCtx.stroke();
        }
    }
    function clearStreamlineTrail() {
        streamlinePoints = [];
        if (streamlineTrailCtx) streamlineTrailCtx.clearRect(0, 0, streamlineTrail.width, streamlineTrail.height);
    }

    // ======================================================================
    //  PREMIUM BRUSH 1: STABILIZATION LIVE PREVIEW
    //  Shows a ghost line of the stabilized path while drawing
    // ======================================================================
    let stabilizationPreviewCanvas = null;
    let stabilizationPreviewCtx = null;
    let stabilizationPreviewPoints = [];

    function showStabilizationPreview(rawPoints) {
        if (stabilizationLevel < 5) return;
        if (!stabilizationPreviewCanvas) {
            stabilizationPreviewCanvas = document.createElement('canvas');
            stabilizationPreviewCanvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9997;';
            stabilizationPreviewCanvas.width = window.innerWidth;
            stabilizationPreviewCanvas.height = window.innerHeight;
            stabilizationPreviewCtx = stabilizationPreviewCanvas.getContext('2d');
            document.body.appendChild(stabilizationPreviewCanvas);
        }
        stabilizationPreviewCtx.clearRect(0, 0, stabilizationPreviewCanvas.width, stabilizationPreviewCanvas.height);

        // Run the stabilization algorithm on recent raw points
        const buf = [];
        const bufSize = 3 + Math.floor(stabilizationLevel / 10);
        const stabilized = [];
        for (let i = 0; i < rawPoints.length; i++) {
            buf.push({ x: rawPoints[i].x, y: rawPoints[i].y });
            while (buf.length > bufSize) buf.shift();
            const n = buf.length;
            if (n > 1) {
                let tw = 0, sx = 0, sy = 0;
                for (let j = 0; j < n; j++) {
                    const w = 1 + (j / (n - 1)) * (stabilizationLevel / 10);
                    sx += buf[j].x * w;
                    sy += buf[j].y * w;
                    tw += w;
                }
                stabilized.push({ x: sx / tw, y: sy / tw });
            } else {
                stabilized.push({ ...buf[0] });
            }
        }

        if (stabilized.length < 2) return;

        // Convert canvas coords to screen coords
        const container = document.getElementById('canvas-container');
        const cRect = container ? container.getBoundingClientRect() : { left: 0, top: 0 };

        stabilizationPreviewCtx.beginPath();
        const s0 = stabilized[0];
        stabilizationPreviewCtx.moveTo(cRect.left + s0.x * transform.scale + transform.x, cRect.top + s0.y * transform.scale + transform.y);
        for (let i = 1; i < stabilized.length; i++) {
            const sp = stabilized[i];
            stabilizationPreviewCtx.lineTo(cRect.left + sp.x * transform.scale + transform.x, cRect.top + sp.y * transform.scale + transform.y);
        }
        stabilizationPreviewCtx.strokeStyle = 'rgba(0,180,255,0.35)';
        stabilizationPreviewCtx.lineWidth = Math.max(1, brushSize * transform.scale * 0.15);
        stabilizationPreviewCtx.lineCap = 'round';
        stabilizationPreviewCtx.lineJoin = 'round';
        stabilizationPreviewCtx.setLineDash([4, 4]);
        stabilizationPreviewCtx.stroke();
        stabilizationPreviewCtx.setLineDash([]);
    }

    function clearStabilizationPreview() {
        if (stabilizationPreviewCtx) {
            stabilizationPreviewCtx.clearRect(0, 0, stabilizationPreviewCanvas.width, stabilizationPreviewCanvas.height);
        }
        stabilizationPreviewPoints = [];
    }

    // ======================================================================
    //  PREMIUM BRUSH 2: BRUSH DYNAMICS VISUALIZER
    //  Animated mini-preview showing spacing, scatter, jitter, rotation
    // ======================================================================
    let brushDynamicsPreviewCanvas = null;
    let brushDynamicsAnimFrame = null;
    let brushDynamicsAnimT = 0;

    function createBrushDynamicsPreview() {
        const panel = document.getElementById('brushes-panel');
        if (!panel) return;
        // Remove old preview if exists
        const old = panel.querySelector('.brush-dynamics-preview');
        if (old) old.remove();

        const wrapper = document.createElement('div');
        wrapper.className = 'brush-dynamics-preview';
        wrapper.style.cssText = 'padding:4px 8px;border-top:1px solid var(--border-color);margin-top:4px;';

        const label = document.createElement('div');
        label.style.cssText = 'font-size:9px;color:var(--icon-color);margin-bottom:2px;';
        label.textContent = 'Preview dinámica';
        wrapper.appendChild(label);

        brushDynamicsPreviewCanvas = document.createElement('canvas');
        brushDynamicsPreviewCanvas.width = 200;
        brushDynamicsPreviewCanvas.height = 60;
        brushDynamicsPreviewCanvas.style.cssText = 'width:100%;height:60px;border:1px solid var(--border-color);border-radius:4px;background:#1a1a1a;';
        wrapper.appendChild(brushDynamicsPreviewCanvas);
        panel.querySelector('.panel-content').appendChild(wrapper);

        brushDynamicsAnimT = 0;
        if (brushDynamicsAnimFrame) cancelAnimationFrame(brushDynamicsAnimFrame);
        animateBrushDynamics();
    }

    function animateBrushDynamics() {
        if (!brushDynamicsPreviewCanvas) return;
        const ctx = brushDynamicsPreviewCanvas.getContext('2d');
        const w = 200, h = 60;
        const bs = brushStudio[currentBrush] || brushStudio.solid;
        const spacing = Math.max(1, bs.spacing);
        const scatter = bs.scatter || 0;
        const jitter = bs.jitter || 0;
        const rotation = bs.rotation || 0;
        const dotSize = Math.max(2, Math.min(12, spacing * 1.5));

        ctx.clearRect(0, 0, w, h);
        ctx.fillStyle = brushColor;

        brushDynamicsAnimT += 0.03;
        const numDots = Math.floor(w / spacing);
        for (let i = 0; i < numDots; i++) {
            const x = i * spacing;
            const phase = brushDynamicsAnimT + i * 0.3;
            // Scatter: Y offset
            const scatterY = Math.sin(phase * 2) * (scatter / 100) * 15;
            // Jitter: size variation
            const sizeVar = dotSize * (1 + Math.sin(phase * 3) * (jitter / 100) * 0.6);
            // Rotation: angle
            const angle = (rotation / 360) * Math.PI * 2 + Math.sin(phase) * 0.2;
            const y = h / 2 + scatterY;

            ctx.save();
            ctx.translate(x, y);
            ctx.rotate(angle);
            ctx.globalAlpha = 0.6 + Math.sin(phase * 1.5) * 0.2;
            ctx.fillRect(-sizeVar / 2, -sizeVar / 2, sizeVar, sizeVar);
            ctx.restore();
        }
        brushDynamicsAnimFrame = requestAnimationFrame(animateBrushDynamics);
    }

    function destroyBrushDynamicsPreview() {
        if (brushDynamicsAnimFrame) { cancelAnimationFrame(brushDynamicsAnimFrame); brushDynamicsAnimFrame = null; }
        brushDynamicsPreviewCanvas = null;
    }

    // ======================================================================
    //  PREMIUM BRUSH 3: BRUSH SHAPE BUILDER
    //  Canvas editor for custom brush tip shapes using Bézier points
    // ======================================================================
    let brushShapePoints = [];
    let brushShapeDragging = -1;

    function openBrushShapeBuilder() {
        const existing = document.getElementById('brush-shape-modal');
        if (existing) existing.remove();

        const overlay = document.createElement('div');
        overlay.id = 'brush-shape-modal';
        overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.7);z-index:10010;display:flex;align-items:center;justify-content:center;';

        const box = document.createElement('div');
        box.style.cssText = 'background:#2c2c2e;border-radius:12px;padding:16px;width:320px;box-shadow:0 8px 32px rgba(0,0,0,0.5);';

        box.innerHTML = `
            <div style="font-size:13px;font-weight:600;color:#fff;margin-bottom:8px;">Constructor de forma de pincel</div>
            <div style="font-size:10px;color:#999;margin-bottom:8px;">Arrastra los puntos para crear la forma de la punta.</div>
            <canvas id="brush-shape-canvas" width="280" height="200" style="width:100%;border:1px solid #444;border-radius:6px;cursor:crosshair;background:#1a1a1a;"></canvas>
            <div style="display:flex;gap:6px;margin-top:8px;">
                <button id="bs-reset" style="flex:1;padding:6px;border:none;background:#444;color:#fff;border-radius:6px;font-size:11px;cursor:pointer;">Reset</button>
                <button id="bs-circle" style="flex:1;padding:6px;border:none;background:#444;color:#fff;border-radius:6px;font-size:11px;cursor:pointer;">Círculo</button>
                <button id="bs-apply" style="flex:1;padding:6px;border:none;background:#007aff;color:#fff;border-radius:6px;font-size:11px;cursor:pointer;">Aplicar</button>
                <button id="bs-close" style="flex:1;padding:6px;border:none;background:#ff3b30;color:#fff;border-radius:6px;font-size:11px;cursor:pointer;">Cerrar</button>
            </div>
        `;
        overlay.appendChild(box);
        document.body.appendChild(overlay);

        const canvas = document.getElementById('brush-shape-canvas');
        const ctx = canvas.getContext('2d');

        // Default: circle (8 points)
        if (brushShapePoints.length === 0) {
            brushShapePoints = [];
            for (let i = 0; i < 8; i++) {
                const a = (i / 8) * Math.PI * 2;
                brushShapePoints.push({ x: 140 + Math.cos(a) * 70, y: 100 + Math.sin(a) * 70 });
            }
        }

        function drawShape() {
            ctx.clearRect(0, 0, 280, 200);
            ctx.strokeStyle = '#007aff';
            ctx.lineWidth = 2;
            ctx.beginPath();
            if (brushShapePoints.length > 2) {
                ctx.moveTo(brushShapePoints[0].x, brushShapePoints[0].y);
                for (let i = 1; i < brushShapePoints.length; i++) {
                    ctx.lineTo(brushShapePoints[i].x, brushShapePoints[i].y);
                }
                ctx.closePath();
            }
            ctx.stroke();
            ctx.fillStyle = 'rgba(0,122,255,0.15)';
            ctx.fill();

            // Draw points
            brushShapePoints.forEach((p, i) => {
                ctx.fillStyle = '#fff';
                ctx.beginPath();
                ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
                ctx.fill();
                ctx.strokeStyle = '#007aff';
                ctx.lineWidth = 1.5;
                ctx.stroke();
            });
        }

        canvas.addEventListener('pointerdown', (e) => {
            const rect = canvas.getBoundingClientRect();
            const sx = (e.clientX - rect.left) * (280 / rect.width);
            const sy = (e.clientY - rect.top) * (200 / rect.height);
            brushShapeDragging = -1;
            for (let i = 0; i < brushShapePoints.length; i++) {
                if (Math.hypot(brushShapePoints[i].x - sx, brushShapePoints[i].y - sy) < 12) {
                    brushShapeDragging = i;
                    break;
                }
            }
        });

        canvas.addEventListener('pointermove', (e) => {
            if (brushShapeDragging < 0) return;
            const rect = canvas.getBoundingClientRect();
            brushShapePoints[brushShapeDragging].x = (e.clientX - rect.left) * (280 / rect.width);
            brushShapePoints[brushShapeDragging].y = (e.clientY - rect.top) * (200 / rect.height);
            drawShape();
        });

        canvas.addEventListener('pointerup', () => { brushShapeDragging = -1; });

        document.getElementById('bs-reset').onclick = () => {
            brushShapePoints = [];
            for (let i = 0; i < 8; i++) {
                const a = (i / 8) * Math.PI * 2;
                brushShapePoints.push({ x: 140 + Math.cos(a) * 70, y: 100 + Math.sin(a) * 70 });
            }
            drawShape();
        };

        document.getElementById('bs-circle').onclick = () => {
            brushShapePoints = [];
            for (let i = 0; i < 16; i++) {
                const a = (i / 16) * Math.PI * 2;
                brushShapePoints.push({ x: 140 + Math.cos(a) * 70, y: 100 + Math.sin(a) * 70 });
            }
            drawShape();
        };

        document.getElementById('bs-apply').onclick = () => {
            // Convert points to a 1-bit mask for brush tip
            const maskCanvas = document.createElement('canvas');
            maskCanvas.width = 64;
            maskCanvas.height = 64;
            const mCtx = maskCanvas.getContext('2d');
            mCtx.fillStyle = '#000';
            mCtx.fillRect(0, 0, 64, 64);
            mCtx.fillStyle = '#fff';
            mCtx.beginPath();
            const scale = 64 / 280;
            if (brushShapePoints.length > 2) {
                mCtx.moveTo(brushShapePoints[0].x * scale, brushShapePoints[0].y * scale * (64 / 200));
                for (let i = 1; i < brushShapePoints.length; i++) {
                    mCtx.lineTo(brushShapePoints[i].x * scale, brushShapePoints[i].y * scale * (64 / 200));
                }
                mCtx.closePath();
            }
            mCtx.fill();
            brushStudio[currentBrush] = brushStudio[currentBrush] || {};
            brushStudio[currentBrush].tipMask = mCtx.getImageData(0, 0, 64, 64).data;
            showToast('Forma de pincel aplicada');
            overlay.remove();
        };

        document.getElementById('bs-close').onclick = () => overlay.remove();
        overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });

        drawShape();
    }

    function updateUndoRedoIndicator() {
        const undoBtn = document.getElementById('btn-undo');
        const redoBtn = document.getElementById('btn-redo');
        if (undoBtn) undoBtn.style.opacity = historyStep > 0 ? '1' : '0.3';
        if (redoBtn) redoBtn.style.opacity = historyStep < history.length - 1 ? '1' : '0.3';
    }

    let layerThumbSize = 40;
    function setLayerThumbnailSize(size) {
        layerThumbSize = Math.max(24, Math.min(80, size));
        document.documentElement.style.setProperty('--layer-thumb-size', layerThumbSize + 'px');
        renderLayersUI();
    }

    // =====================================================================
    // END FEATURES BATCH 5
    // =====================================================================

    // =====================================================================
    // END FEATURES BATCH 9A: Shape Tools
    // =====================================================================

    let shapeToolActive = false;
    let shapeToolType = 'rect';
    let shapeFillMode = 'fill';
    let shapeCornerRadius = 0;
    let shapeStartPoint = null;
    let shapePreview = null;

    function drawRectShape(ctx, x1, y1, x2, y2, radius, fillMode) {
        ctx.save();
        ctx.fillStyle = brushColor;
        ctx.strokeStyle = brushColor;
        ctx.lineWidth = brushSize;
        ctx.globalAlpha = brushOpacity;
        const w = x2 - x1, h = y2 - y1;
        const r = Math.min(radius, Math.abs(w) / 2, Math.abs(h) / 2);
        ctx.beginPath();
        if (r > 0) {
            ctx.moveTo(x1 + r, y1);
            ctx.lineTo(x2 - r, y1); ctx.quadraticCurveTo(x2, y1, x2, y1 + r);
            ctx.lineTo(x2, y2 - r); ctx.quadraticCurveTo(x2, y2, x2 - r, y2);
            ctx.lineTo(x1 + r, y2); ctx.quadraticCurveTo(x1, y2, x1, y2 - r);
            ctx.lineTo(x1, y1 + r); ctx.quadraticCurveTo(x1, y1, x1 + r, y1);
        } else {
            ctx.rect(x1, y1, w, h);
        }
        ctx.closePath();
        if (fillMode === 'fill') ctx.fill();
        else if (fillMode === 'stroke') ctx.stroke();
        else { ctx.fill(); ctx.stroke(); }
        ctx.restore();
    }

    function drawEllipseShape(ctx, x1, y1, x2, y2, fillMode) {
        ctx.save();
        ctx.fillStyle = brushColor;
        ctx.strokeStyle = brushColor;
        ctx.lineWidth = brushSize;
        ctx.globalAlpha = brushOpacity;
        const cx = (x1 + x2) / 2, cy = (y1 + y2) / 2;
        const rx = Math.abs(x2 - x1) / 2, ry = Math.abs(y2 - y1) / 2;
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
        ctx.closePath();
        if (fillMode === 'fill') ctx.fill();
        else if (fillMode === 'stroke') ctx.stroke();
        else { ctx.fill(); ctx.stroke(); }
        ctx.restore();
    }

    function drawLineShape(ctx, x1, y1, x2, y2) {
        ctx.save();
        ctx.strokeStyle = brushColor;
        ctx.lineWidth = brushSize;
        ctx.lineCap = 'round';
        ctx.globalAlpha = brushOpacity;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();
        ctx.restore();
    }

    function drawPolygonShape(ctx, cx, cy, radius, sides, fillMode) {
        sides = Math.max(3, Math.round(sides));
        ctx.save();
        ctx.fillStyle = brushColor;
        ctx.strokeStyle = brushColor;
        ctx.lineWidth = brushSize;
        ctx.globalAlpha = brushOpacity;
        ctx.beginPath();
        for (let i = 0; i < sides; i++) {
            const angle = (i / sides) * Math.PI * 2 - Math.PI / 2;
            const x = cx + Math.cos(angle) * radius;
            const y = cy + Math.sin(angle) * radius;
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        }
        ctx.closePath();
        if (fillMode === 'fill') ctx.fill();
        else if (fillMode === 'stroke') ctx.stroke();
        else { ctx.fill(); ctx.stroke(); }
        ctx.restore();
    }

    // =====================================================================
    // END FEATURES BATCH 9B: More Brushes
    // =====================================================================

    function drawSprayDot(ctx, x, y, radius, color, opacity) {
        ctx.save();
        ctx.fillStyle = color;
        ctx.globalAlpha = opacity * 0.15;
        const density = Math.floor(radius * 2);
        for (let i = 0; i < density; i++) {
            const angle = Math.random() * Math.PI * 2;
            const dist = Math.random() * radius;
            const sx = x + Math.cos(angle) * dist;
            const sy = y + Math.sin(angle) * dist;
            const size = Math.random() * 2 + 0.5;
            ctx.beginPath();
            ctx.arc(sx, sy, size, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    function drawPastelDot(ctx, x, y, radius, color, opacity) {
        ctx.save();
        ctx.globalAlpha = opacity * 0.4;
        ctx.fillStyle = color;
        for (let i = 0; i < 3; i++) {
            const ox = (Math.random() - 0.5) * radius * 0.5;
            const oy = (Math.random() - 0.5) * radius * 0.5;
            const r = radius * (0.6 + Math.random() * 0.4);
            const grad = ctx.createRadialGradient(x + ox, y + oy, 0, x + ox, y + oy, r);
            grad.addColorStop(0, color);
            grad.addColorStop(0.7, color);
            grad.addColorStop(1, 'rgba(0,0,0,0)');
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(x + ox, y + oy, r, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    function drawInkDot(ctx, x, y, pressure, dx, dy) {
        ctx.save();
        ctx.fillStyle = brushColor;
        ctx.globalAlpha = brushOpacity;
        const size = Math.max(1, brushSize * pressure * 0.6);
        const angle = Math.atan2(dy || 0.001, dx || 0.001);
        const flatness = 0.2 + 0.3 * (1 - pressure);
        ctx.translate(x, y);
        ctx.rotate(angle);
        ctx.beginPath();
        ctx.ellipse(0, 0, size, size * flatness, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }

    function drawFlatDot(ctx, x, y, radius, color, opacity, angle) {
        ctx.save();
        ctx.fillStyle = color;
        ctx.globalAlpha = opacity;
        ctx.translate(x, y);
        ctx.rotate(angle || 0);
        ctx.fillRect(-radius, -radius * 0.3, radius * 2, radius * 0.6);
        ctx.restore();
    }

    function drawFanDot(ctx, x, y, radius, color, opacity, angle) {
        ctx.save();
        ctx.fillStyle = color;
        ctx.globalAlpha = opacity * 0.5;
        ctx.translate(x, y);
        ctx.rotate(angle || 0);
        const bristles = 7;
        for (let i = 0; i < bristles; i++) {
            const t = (i / (bristles - 1)) - 0.5;
            const bx = t * radius * 1.5;
            const by = -radius * 0.3 + Math.abs(t) * radius * 0.4;
            ctx.beginPath();
            ctx.arc(bx, by, radius * 0.08, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    // =====================================================================
    // END FEATURES BATCH 9C: Selection
    // =====================================================================

    function featherSelection(radius) {
        radius = radius || 5;
        if (!selectionData) return;
        const w = selectionData.width, h = selectionData.height;
        const tc = document.createElement('canvas');
        tc.width = w; tc.height = h;
        const tctx = tc.getContext('2d');
        tctx.putImageData(selectionData, 0, 0);
        applyGaussianBlur(tc, radius);
        selectionData = tctx.getImageData(0, 0, w, h);
        drawSelectionOverlay();
    }

    let fixedRatioEnabled = false;
    let fixedRatioW = 1, fixedRatioH = 1;
    function constrainToFixedRatio(x1, y1, x2, y2) {
        if (!fixedRatioEnabled) return { x2, y2 };
        const dx = x2 - x1, dy = y2 - y1;
        const ratio = fixedRatioW / fixedRatioH;
        const absDx = Math.abs(dx), absDy = Math.abs(dy);
        if (absDx / absDy > ratio) {
            return { x2: x1 + Math.sign(dx) * absDy * ratio, y2 };
        } else {
            return { x2, y2: y1 + Math.sign(dy) * absDx / ratio };
        }
    }

    // =====================================================================
    // END FEATURES BATCH 9D: Animation
    // =====================================================================

    const easingPresets = {
        linear: t => t,
        easeInQuad: t => t * t,
        easeOutQuad: t => 1 - (1 - t) * (1 - t),
        easeInOutQuad: t => t < 0.5 ? 2 * t * t : 1 - (-2 * t + 2) ** 2 / 2,
        easeInCubic: t => t * t * t,
        easeOutCubic: t => 1 - (1 - t) ** 3,
        easeInOutCubic: t => t < 0.5 ? 4 * t * t * t : 1 - (-2 * t + 2) ** 3 / 2,
        easeInElastic: t => t === 0 ? 0 : t === 1 ? 1 : -Math.pow(2, 10 * t - 10) * Math.sin((t * 10 - 10.75) * (2 * Math.PI / 3)),
        easeOutElastic: t => t === 0 ? 0 : t === 1 ? 1 : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * (2 * Math.PI / 3)) + 1,
        easeOutBounce: t => { const n1 = 7.5625, d1 = 2.75; if (t < 1 / d1) return n1 * t * t; else if (t < 2 / d1) return n1 * (t -= 1.5 / d1) * t + 0.75; else if (t < 2.5 / d1) return n1 * (t -= 2.25 / d1) * t + 0.9375; else return n1 * (t -= 2.625 / d1) * t + 0.984375; },
        easeInBack: t => { const c1 = 1.70158, c3 = c1 + 1; return c3 * t * t * t - c1 * t * t; },
        easeOutBack: t => { const c1 = 1.70158, c3 = c1 + 1; return 1 + c3 * (t - 1) ** 3 + c1 * (t - 1) ** 2; }
    };
    function applyEasing(t, presetName) {
        const fn = easingPresets[presetName] || easingPresets.linear;
        return fn(Math.max(0, Math.min(1, t)));
    }

    const animTemplates = [
        { name: 'Bounce', frames: 12, apply: (i, total) => ({ y: Math.abs(Math.sin(i / total * Math.PI)) * -50 }) },
        { name: 'Fade In', frames: 10, apply: (i, total) => ({ opacity: i / total }) },
        { name: 'Fade Out', frames: 10, apply: (i, total) => ({ opacity: 1 - i / total }) },
        { name: 'Spin', frames: 20, apply: (i, total) => ({ rotation: (i / total) * 360 }) },
        { name: 'Pulse', frames: 15, apply: (i, total) => ({ scale: 1 + Math.sin(i / total * Math.PI * 2) * 0.2 }) },
        { name: 'Slide Left', frames: 12, apply: (i, total) => ({ x: -i / total * 200 }) },
        { name: 'Walk Cycle', frames: 16, apply: (i, total) => ({ y: Math.abs(Math.sin(i / total * Math.PI * 2)) * -10, x: i / total * 100 }) }
    ];

