    // --- Selection Feather ---
    const selectionFeatherSlider = document.getElementById('selection-feather');
    const selectionFeatherVal = document.getElementById('selection-feather-val');
    const btnSelectionInvert = document.getElementById('btn-selection-invert');

    function applySelectionFeather() {
        const radius = parseInt(selectionFeatherSlider.value);
        selectionFeatherVal.textContent = radius;
        drawSelectionOverlay(); // Live preview of feather border
        if (!selectionData || radius === 0) return;
        const blurred = applyGaussianBlur(selectionData, radius);
        const blurCtx = blurred.getContext('2d');
        const blurData = blurCtx.getImageData(0, 0, blurred.width, blurred.height);
        const origCtx = selectionData.getContext('2d');
        const origData = origCtx.getImageData(0, 0, selectionData.width, selectionData.height);
        for (let i = 0; i < origData.data.length; i += 4) {
            origData.data[i + 3] = blurData.data[i + 3];
        }
        origCtx.putImageData(origData, 0, 0);
        drawTransformOverlay();
    }

    selectionFeatherSlider.addEventListener('input', applySelectionFeather);

    // --- Selection Invert ---
    btnSelectionInvert.addEventListener('click', () => {
        const layer = getActiveLayer();
        if (!layer || !selectionRect) return;
        const r = selectionRect;
        const dprLocal = window.devicePixelRatio || 1;
        // Create inverse selection: everything EXCEPT the current selection
        // Strategy: copy full layer, clear selection area, select the cleared area
        const fullData = document.createElement('canvas');
        fullData.width = layer.canvas.width;
        fullData.height = layer.canvas.height;
        fullData.getContext('2d').drawImage(layer.canvas, 0, 0);

        // Create new selectionData that is the inverse
        const newSelection = document.createElement('canvas');
        newSelection.width = layer.canvas.width;
        newSelection.height = layer.canvas.height;
        const nsCtx = newSelection.getContext('2d');

        // Draw the full layer content
        nsCtx.drawImage(fullData, 0, 0);

        // Clear the current selection area (this removes the selected part)
        if (selectionType === 'freeform' && lassoMask) {
            nsCtx.putImageData(lassoMask, 0, 0);
            nsCtx.globalCompositeOperation = 'destination-out';
            nsCtx.drawImage(selectionData,
                Math.round(r.x * dprLocal), Math.round(r.y * dprLocal),
                selectionData.width, selectionData.height);
            nsCtx.globalCompositeOperation = 'source-over';
        } else {
            nsCtx.clearRect(Math.round(r.x * dprLocal), Math.round(r.y * dprLocal),
                selectionData.width, selectionData.height);
        }

        // Update selection to cover the entire canvas
        selectionRect = { x: 0, y: 0, w: logicalWidth, h: logicalHeight };
        selectionData = document.createElement('canvas');
        selectionData.width = layer.canvas.width;
        selectionData.height = layer.canvas.height;
        selectionData.getContext('2d').drawImage(nsCtx.canvas, 0, 0);

        drawSelectionOverlay();
        drawTransformOverlay();
    });

