    // --- Painter Mode (edge-aware brush) ---
    const btnPainterMode = document.getElementById('btn-painter-mode');

    function getEdgeStrength(ctx, x, y, radius) {
        const px = Math.floor(x * dpr);
        const py = Math.floor(y * dpr);
        const r = Math.max(1, Math.floor(radius * dpr * 0.3));
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const w = r * 2 + 1;
        if (px - r < 0 || py - r < 0 || px + r >= ctx.canvas.width || py + r >= ctx.canvas.height) {
            ctx.restore();
            return 0;
        }
        const data = ctx.getImageData(px - r, py - r, w, w).data;
        ctx.restore();
        let gx = 0, gy = 0;
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                const idx = ((dy + r) * w + (dx + r)) * 4;
                const lum = (data[idx] + data[idx + 1] + data[idx + 2]) / 3;
                gx += lum * dx;
                gy += lum * dy;
            }
        }
        return Math.sqrt(gx * gx + gy * gy) / (r * r * 255);
    }

