    // --- 1. Generic Filter Modal with Slider ---
    function showFilterModal(title, label, min, max, initial, onApply) {
        return new Promise(resolve => {
            const wrapper = document.createElement('div');
            const slider = document.createElement('input');
            slider.type = 'range';
            slider.min = min;
            slider.max = max;
            slider.value = initial;
            slider.className = 'modal-input';
            slider.style.cssText = 'width:100%;margin-top:8px;';
            const valLabel = document.createElement('div');
            valLabel.style.cssText = 'text-align:center;font-size:12px;color:#fff;margin-top:4px;';
            valLabel.textContent = initial;
            slider.addEventListener('input', () => { valLabel.textContent = slider.value; });
            wrapper.appendChild(document.createElement('p')).textContent = label;
            wrapper.appendChild(slider);
            wrapper.appendChild(valLabel);

            let snapshot = null;
            const layer = getActiveLayer();
            if (layer) {
                snapshot = document.createElement('canvas');
                snapshot.width = layer.canvas.width;
                snapshot.height = layer.canvas.height;
                snapshot.getContext('2d').drawImage(layer.canvas, 0, 0);
            }

            const modal = showModal({
                title,
                body: wrapper,
                buttons: [
                    { label: 'Cancelar', value: false },
                    { label: 'Aplicar', class: 'primary', value: true }
                ],
                onClose: (v) => {
                    if (v && layer && snapshot) {
                        onApply(layer, parseInt(slider.value));
                        saveState();
                        compositeDirty = true;
                        renderComposite();
                    } else if (!v && layer && snapshot) {
                        layer.ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
                        layer.ctx.drawImage(snapshot, 0, 0);
                        compositeDirty = true;
                        renderComposite();
                    }
                    resolve(v);
                }
            });

            slider.addEventListener('input', () => {
                if (layer && snapshot) {
                    layer.ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
                    layer.ctx.drawImage(snapshot, 0, 0);
                    onApply(layer, parseInt(slider.value));
                    compositeDirty = true;
                    renderComposite();
                }
            });
        });
    }

    // --- 2. Sharpen Filter ---
    function applySharpen(ctx, amount) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const a = amount / 100;
        const kernel = [0, -a, 0, -a, 1 + 4 * a, -a, 0, -a, 0];
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                for (let c = 0; c < 3; c++) {
                    let val = 0, ki = 0;
                    for (let dy = -1; dy <= 1; dy++) {
                        for (let dx = -1; dx <= 1; dx++) {
                            const sx = Math.min(w - 1, Math.max(0, x + dx));
                            const sy = Math.min(h - 1, Math.max(0, y + dy));
                            val += sd[(sy * w + sx) * 4 + c] * kernel[ki++];
                        }
                    }
                    dd[(y * w + x) * 4 + c] = Math.max(0, Math.min(255, val));
                }
                dd[(y * w + x) * 4 + 3] = sd[(y * w + x) * 4 + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    btnSharpen = document.getElementById('btn-sharpen');
    if (btnSharpen) btnSharpen.addEventListener('click', async () => {
        await showFilterModal('Sharpen', 'Intensidad (0-100):', 0, 100, 50, (layer, val) => {
            applySharpen(layer.ctx, val);
        });
    });

