    // --- 11. Layer Stroke/Outline Effect ---
    function applyLayerStroke(ctx, width, color) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const r = parseInt(color.substr(1, 2), 16);
        const g = parseInt(color.substr(3, 2), 16);
        const b = parseInt(color.substr(5, 2), 16);

        // Create alpha mask
        const alpha = new Uint8Array(w * h);
        for (let i = 0; i < w * h; i++) {
            alpha[i] = sd[i * 4 + 3] > 128 ? 1 : 0;
        }

        // Dilate alpha to create stroke
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let hit = false;
                for (let dy = -width; dy <= width && !hit; dy++) {
                    for (let dx = -width; dx <= width && !hit; dx++) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                            if (alpha[ny * w + nx]) hit = true;
                        }
                    }
                }
                const di = (y * w + x) * 4;
                if (hit && !alpha[y * w + x]) {
                    // Stroke pixel (outside original shape)
                    dd[di] = r; dd[di + 1] = g; dd[di + 2] = b; dd[di + 3] = 255;
                } else {
                    // Original pixel
                    dd[di] = sd[di]; dd[di + 1] = sd[di + 1]; dd[di + 2] = sd[di + 2]; dd[di + 3] = sd[di + 3];
                }
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    btnLayerStroke = document.getElementById('btn-layer-stroke');
    if (btnLayerStroke) btnLayerStroke.addEventListener('click', async () => {
        const layer = getActiveLayer();
        if (layer) {
            const w = await showPrompt('Stroke', 'Ancho del trazo (1-20):', '3');
            if (w !== null) {
                const c = await showPrompt('Stroke', 'Color del trazo (hex):', '#000000');
                if (c) {
                    applyLayerStroke(layer.ctx, parseInt(w), c);
                    compositeDirty = true; renderComposite(); saveState();
                }
            }
        }
    });

    // ======================================================================
    //  BATCH 13: PROFESSIONAL FEATURES (Brush Import, Ref Layer, Presets, etc.)
    // ======================================================================

    // --- 1. Brush Import/Export (.brush JSON format) ---
    function exportCurrentBrush() {
        const settings = brushStudio[currentBrush] || {};
        const brushData = {
            version: 1,
            name: currentBrush,
            type: currentBrush,
            size: brushSize,
            opacity: brushOpacity,
            color: brushColor,
            spacing: settings.spacing || 4,
            scatter: settings.scatter || 0,
            jitter: settings.jitter || 0,
            rotation: settings.rotation || 0,
            dirRotation: settings.dirRotation || 0,
            colorDynamics: settings.colorDynamics || 0,
            wetMix: settings.wetMix || 0,
            dual: settings.dual || false,
            dualType: settings.dualType || 'airbrush',
            textureIntensity: brushTextureIntensity || 0,
            textureScale: brushTextureScale || 100,
            taperEnabled: brushTaperEnabled || false,
            timestamp: Date.now()
        };
        // Include texture as base64 if exists
        if (brushTextureImage && brushTextureImage.src) {
            try {
                const tc = document.createElement('canvas');
                tc.width = brushTextureImage.naturalWidth || 64;
                tc.height = brushTextureImage.naturalHeight || 64;
                tc.getContext('2d').drawImage(brushTextureImage, 0, 0);
                brushData.textureImage = tc.toDataURL('image/png');
            } catch (e) { }
        }
        const blob = new Blob([JSON.stringify(brushData, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `brush-${currentBrush}-${Date.now()}.brush`;
        a.click();
        URL.revokeObjectURL(url);
        announceToScreenReader(`Pincel "${currentBrush}" exportado`);
    }

    function importBrushFile(file) {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = JSON.parse(e.target.result);
                    if (!data.type || !brushStudio[data.type]) {
                        // Custom brush type - add to brushStudio
                        brushStudio[data.type] = {
                            spacing: data.spacing || 4,
                            scatter: data.scatter || 0,
                            jitter: data.jitter || 0,
                            rotation: data.rotation || 0,
                            dirRotation: data.dirRotation || 0,
                            colorDynamics: data.colorDynamics || 0,
                            wetMix: data.wetMix || 0,
                            dual: data.dual || false,
                            dualType: data.dualType || 'airbrush'
                        };
                        // Add to brush type selector if not exists
                        const brushTypeSelect = document.getElementById('brush-type-select');
                        if (brushTypeSelect && !brushTypeSelect.querySelector(`option[value="${data.type}"]`)) {
                            const opt = document.createElement('option');
                            opt.value = data.type;
                            opt.textContent = data.name || data.type;
                            brushTypeSelect.appendChild(opt);
                        }
                    }
                    // Apply brush settings
                    currentBrush = data.type;
                    if (data.size) { brushSize = data.size; sizeSlider.value = data.size; }
                    if (data.opacity != null) { brushOpacity = data.opacity; opacitySlider.value = data.opacity * 100; }
                    if (data.color) brushColor = data.color;
                    // Apply to brushStudio
                    const bs = brushStudio[data.type];
                    if (bs) {
                        Object.keys(data).forEach(k => {
                            if (k in bs && k !== 'textureImage') bs[k] = data[k];
                        });
                    }
                    // Load texture if included
                    if (data.textureImage) {
                        const img = new Image();
                        img.onload = () => { brushTextureImage = img; };
                        img.src = data.textureImage;
                    }
                    if (data.taperEnabled != null) brushTaperEnabled = data.taperEnabled;
                    announceToScreenReader(`Pincel "${data.name || data.type}" importado`);
                    resolve(data);
                } catch (err) { reject(err); }
            };
            reader.onerror = reject;
            reader.readAsText(file);
        });
    }

    // Brush export button
    btnExportBrush = document.getElementById('btn-export-brush');
    if (btnExportBrush) btnExportBrush.addEventListener('click', () => exportCurrentBrush());

    // Brush import button
    btnImportBrush = document.getElementById('btn-import-brush');
    if (btnImportBrush) btnImportBrush.addEventListener('click', () => {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.brush,.json';
        input.onchange = async (e) => {
            const file = e.target.files[0];
            if (file) {
                try { await importBrushFile(file); }
                catch (err) { await showAlert('Error', 'No se pudo importar el pincel: ' + err.message); }
            }
        };
        input.click();
    });

    // --- Brush Preset Library ---
    let savedBrushPresets = JSON.parse(localStorage.getItem('procreate-lite-brush-presets') || '[]');
    function showBrushLibrary() {
        const existing = document.getElementById('brush-library-panel');
        if (existing) { existing.remove(); return; }
        const panel = document.createElement('div');
        panel.id = 'brush-library-panel';
        panel.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:var(--toolbar-bg);border:1px solid var(--border-color);border-radius:12px;padding:16px;z-index:10001;min-width:350px;max-width:500px;max-height:70vh;overflow-y:auto;';
        let html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;"><span style="font-weight:bold;font-size:14px;">Biblioteca de pinceles</span><div style="display:flex;gap:6px;"><button class="tool-btn small" id="brush-lib-save" title="Guardar pincel actual"><i class="ri-add-line"></i></button><button class="tool-btn small" id="brush-lib-close"><i class="ri-close-line"></i></button></div></div>';
        html += '<div id="brush-lib-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:8px;">';
        if (savedBrushPresets.length === 0) {
            html += '<div style="grid-column:1/-1;text-align:center;color:var(--text-secondary);padding:20px;font-size:12px;">No hay pinceles guardados</div>';
        }
        savedBrushPresets.forEach((p, idx) => {
            html += `<div class="brush-lib-item" data-idx="${idx}" style="background:var(--canvas-bg);border-radius:8px;border:1px solid var(--border-color);padding:8px;cursor:pointer;text-align:center;transition:transform 0.1s;">`;
            html += `<canvas class="brush-lib-thumb" width="60" height="60" style="border-radius:4px;background:#1a1a1a;margin-bottom:4px;"></canvas>`;
            html += `<div style="font-size:10px;color:var(--text-color);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${p.name || p.type}</div>`;
            html += `<div style="font-size:9px;color:var(--text-secondary);">T:${p.type} S:${p.spacing || 4}</div>`;
            html += `<button class="tool-btn small brush-lib-delete" data-idx="${idx}" style="margin-top:4px;"><i class="ri-delete-bin-line"></i></button>`;
            html += '</div>';
        });
        html += '</div>';
        panel.innerHTML = html;
        document.body.appendChild(panel);
        // Draw thumbnails
        panel.querySelectorAll('.brush-lib-thumb').forEach((canvas, idx) => {
            const p = savedBrushPresets[idx];
            if (!p) return;
            const ctx = canvas.getContext('2d');
            ctx.fillStyle = '#1a1a1a';
            ctx.fillRect(0, 0, 60, 60);
            ctx.fillStyle = p.color || '#ffffff';
            ctx.globalAlpha = 0.8;
            const size = 8 + (p.spacing || 4) * 2;
            for (let i = 0; i < 5; i++) {
                ctx.beginPath();
                ctx.arc(10 + i * 10, 30 + Math.sin(i * 0.8) * 8, size / 2, 0, Math.PI * 2);
                ctx.fill();
            }
            ctx.globalAlpha = 1;
        });
        panel.querySelector('#brush-lib-close').onclick = () => panel.remove();
        panel.querySelector('#brush-lib-save').onclick = () => {
            const settings = brushStudio[currentBrush] || {};
            const preset = {
                name: currentBrush + ' ' + (savedBrushPresets.length + 1),
                type: currentBrush, spacing: settings.spacing, scatter: settings.scatter,
                jitter: settings.jitter, rotation: settings.rotation, dirRotation: settings.dirRotation,
                colorDynamics: settings.colorDynamics, wetMix: settings.wetMix, color: brushColor,
                size: brushSize, opacity: brushOpacity, timestamp: Date.now()
            };
            savedBrushPresets.push(preset);
            localStorage.setItem('procreate-lite-brush-presets', JSON.stringify(savedBrushPresets));
            panel.remove();
            showBrushLibrary();
        };
        panel.querySelectorAll('.brush-lib-item').forEach(item => {
            item.onclick = (e) => {
                if (e.target.closest('.brush-lib-delete')) return;
                const idx = parseInt(item.dataset.idx);
                const p = savedBrushPresets[idx];
                if (!p) return;
                currentBrush = p.type;
                brushSize = p.size || 10;
                brushOpacity = p.opacity || 1;
                brushColor = p.color || brushColor;
                if (brushStudio[p.type]) {
                    Object.assign(brushStudio[p.type], { spacing: p.spacing, scatter: p.scatter, jitter: p.jitter, rotation: p.rotation, dirRotation: p.dirRotation, colorDynamics: p.colorDynamics, wetMix: p.wetMix });
                }
                panel.remove();
                showToast(`Pincel "${p.type}" cargado`);
            };
        });
        panel.querySelectorAll('.brush-lib-delete').forEach(btn => {
            btn.onclick = (e) => {
                e.stopPropagation();
                const idx = parseInt(btn.dataset.idx);
                savedBrushPresets.splice(idx, 1);
                localStorage.setItem('procreate-lite-brush-presets', JSON.stringify(savedBrushPresets));
                panel.remove();
                showBrushLibrary();
            };
        });
    }

    // --- 2. Reference Layer Eyedropper ---
    function pickColorFromReference(x, y) {
        const refLayer = getReferenceLayer();
        if (!refLayer) return pickColor(x, y);
        const ctx = refLayer.ctx;
        const px = Math.floor(x * dpr);
        const py = Math.floor(y * dpr);
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const pixel = ctx.getImageData(px, py, 1, 1).data;
        ctx.restore();
        if (pixel[3] === 0) return pickColor(x, y); // fallback if transparent
        const hex = '#' + [pixel[0], pixel[1], pixel[2]].map(c => c.toString(16).padStart(2, '0')).join('');
        brushColor = hex;
        addRecentColor(hex);
        colorIndicator.style.backgroundColor = hex;
        colorPreviewSwatch.style.backgroundColor = hex;
        hexInput.value = hex;
        if (typeof renderHarmony === 'function') renderHarmony();
        const hsb = rgbToHsb(pixel[0], pixel[1], pixel[2]);
        currentHue = hsb.h;
        currentSat = hsb.s;
        currentBri = hsb.b;
        drawHueWheel();
        drawSBSquare();
        announceToScreenReader(`Color picked from reference layer: ${hex}`);
    }

    // Override pickColor to use reference layer when available
    const _origPickColor = pickColor;
    pickColor = function (x, y) {
        const refLayer = getReferenceLayer();
        if (refLayer) {
            pickColorFromReference(x, y);
        } else {
            _origPickColor(x, y);
        }
    };

