    function resizeCanvas(newW, newH) {
        if (newW < 64 || newW > 8192 || newH < 64 || newH > 8192) {
            showAlert('Canvas', 'Dimensiones deben ser entre 64 y 8192 px');
            return;
        }
        // Save current state
        const oldW = logicalWidth, oldH = logicalHeight;
        logicalWidth = newW;
        logicalHeight = newH;
        // Resize all layers
        layers.forEach(l => {
            const tempCanvas = document.createElement('canvas');
            tempCanvas.width = l.canvas.width;
            tempCanvas.height = l.canvas.height;
            tempCanvas.getContext('2d').drawImage(l.canvas, 0, 0);
            l.canvas.width = newW * dpr;
            l.canvas.height = newH * dpr;
            l.canvas.style.width = newW + 'px';
            l.canvas.style.height = newH + 'px';
            l.ctx.setTransform(1, 0, 0, 1, 0, 0);
            l.ctx.scale(dpr, dpr);
            l.ctx.drawImage(tempCanvas, 0, 0, oldW * dpr, oldH * dpr, 0, 0, newW * dpr, newH * dpr);
        });
        resizeHelperCanvases();
        saveState();
        announceToScreenReader(`Canvas redimensionado a ${newW}×${newH}`);
    }

