    // --- 6. Selection Refine Edge (Smooth) ---
    function refineSelectionEdge(smoothAmount) {
        if (!selectionData) return;
        const w = selectionData.width, h = selectionData.height;
        const src = new Uint8ClampedArray(selectionData.data);
        const dst = selectionData.data;

        // Box blur for smoothing
        const radius = Math.max(1, Math.min(smoothAmount, 10));
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let sum = 0, count = 0;
                for (let dy = -radius; dy <= radius; dy++) {
                    for (let dx = -radius; dx <= radius; dx++) {
                        const nx = Math.max(0, Math.min(w - 1, x + dx));
                        const ny = Math.max(0, Math.min(h - 1, y + dy));
                        sum += src[(ny * w + nx) * 4 + 3];
                        count++;
                    }
                }
                dst[(y * w + x) * 4 + 3] = Math.round(sum / count);
            }
        }
        compositeDirty = true;
        renderComposite();
        announceToScreenReader(`Selección suavizada: ${smoothAmount}px`);
    }

    btnRefineEdge = document.getElementById('btn-refine-edge');
