    // --- Smart Fill: Edge-aware flood fill ---
    let smartFillTolerance = 32;
    function smartFillAtPoint(x, y, targetColor = brushColor) {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const sx = Math.floor(x * dpr), sy = Math.floor(y * dpr);
        if (sx < 0 || sx >= w || sy < 0 || sy >= h) return;
        
        const src = layer.ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        const seedR = sd[(sy * w + sx) * 4], seedG = sd[(sy * w + sx) * 4 + 1], seedB = sd[(sy * w + sx) * 4 + 2];
        
        const visited = new Uint8Array(w * h);
        const stack = [{ x: sx, y: sy }];
        const result = new Uint8ClampedArray(sd.length);
        
        const targetRgb = hexToRgb(targetColor);
        
        while (stack.length > 0) {
            const { x: cx, y: cy } = stack.pop();
            const ci = cy * w + cx;
            if (cx < 0 || cx >= w || cy < 0 || cy >= h || visited[ci]) continue;
            const i = ci * 4;
            const dr = sd[i] - seedR, dg = sd[i + 1] - seedG, db = sd[i + 2] - seedB;
            const edge = Math.sqrt(dr * dr + dg * dg + db * db);
            if (edge > smartFillTolerance) continue;
            visited[ci] = 1;
            result[i] = targetRgb.r;
            result[i + 1] = targetRgb.g;
            result[i + 2] = targetRgb.b;
            result[i + 3] = 255;
            stack.push({ x: cx + 1, y: cy }, { x: cx - 1, y: cy }, { x: cx, y: cy + 1 }, { x: cx, y: cy - 1 });
        }
        
        layer.ctx.putImageData(new ImageData(result, w, h), 0, 0);
        compositeDirty = true;
        renderComposite();
        saveState();
    }
    
