    // --- B. Save/Load Selections as Channels ---
    let savedSelectionChannels = JSON.parse(localStorage.getItem('procreate-lite-channels') || '[]');

    function saveSelectionAsChannel(name) {
        if (!selectionData) { showToast('No hay selección activa'); return; }
        savedSelectionChannels.push({
            name: name || `Selección ${savedSelectionChannels.length + 1}`,
            data: Array.from(selectionData.data),
            width: selectionData.width,
            height: selectionData.height,
            timestamp: Date.now()
        });
        try { localStorage.setItem('procreate-lite-channels', JSON.stringify(savedSelectionChannels)); } catch (e) { }
        showToast(`Selección guardada como "${name}"`);
    }

    function loadSelectionChannel(index) {
        if (index < 0 || index >= savedSelectionChannels.length) return;
        const ch = savedSelectionChannels[index];
        selectionData = new ImageData(new Uint8ClampedArray(ch.data), ch.width, ch.height);
        selectionActive = true;
        selectionType = 'freeform';
        selectionRect = { x: 0, y: 0, w: ch.width / dpr, h: ch.height / dpr };
        selectionOverlay.classList.remove('hidden');
        drawSelectionOverlay();
        copySelectionPixels();
        showToast(`Selección "${ch.name}" cargada`);
    }

    function deleteSelectionChannel(index) {
        savedSelectionChannels.splice(index, 1);
        try { localStorage.setItem('procreate-lite-channels', JSON.stringify(savedSelectionChannels)); } catch (e) { }
    }

