    // --- C. Healing Brush (Pincel Corrector) ---
    function healingBrushStroke(x, y, size) {
        const layer = getActiveLayer();
        if (!layer) return;
        const ctx = layer.ctx;
        const r = Math.max(1, Math.floor(size * dpr / 2));
        const px = Math.floor(x * dpr), py = Math.floor(y * dpr);
        const w = layer.canvas.width, h = layer.canvas.height;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const srcData = ctx.getImageData(0, 0, w, h);
        const sd = srcData.data;
        const sampleDist = Math.max(r * 2, 10);
        let srcX = Math.min(w - 1, Math.max(0, px + sampleDist));
        let srcY = Math.min(h - 1, Math.max(0, py));
        let sumR = 0, sumG = 0, sumB = 0, count = 0;
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                if (dx * dx + dy * dy > r * r) continue;
                const sx2 = srcX + dx, sy2 = srcY + dy;
                if (sx2 >= 0 && sx2 < w && sy2 >= 0 && sy2 < h) {
                    const si = (sy2 * w + sx2) * 4;
                    sumR += sd[si]; sumG += sd[si + 1]; sumB += sd[si + 2];
                    count++;
                }
            }
        }
        if (count === 0) { ctx.restore(); return; }
        const avgR = sumR / count, avgG = sumG / count, avgB = sumB / count;
        let destSumR = 0, destSumG = 0, destSumB = 0, destCount = 0;
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                if (dx * dx + dy * dy > r * r) continue;
                const nx = px + dx, ny = py + dy;
                if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                    const ni = (ny * w + nx) * 4;
                    destSumR += sd[ni]; destSumG += sd[ni + 1]; destSumB += sd[ni + 2];
                    destCount++;
                }
            }
        }
        if (destCount === 0) { ctx.restore(); return; }
        const dAvgR = destSumR / destCount, dAvgG = destSumG / destCount, dAvgB = destSumB / destCount;
        for (let dy = -r; dy <= r; dy++) {
            for (let dx = -r; dx <= r; dx++) {
                if (dx * dx + dy * dy > r * r) continue;
                const nx = px + dx, ny = py + dy;
                if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                    const ni = (ny * w + nx) * 4;
                    const si = (Math.min(h - 1, Math.max(0, py + dy)) * w + Math.min(w - 1, Math.max(0, px + dx + sampleDist))) * 4;
                    const srcPixel = [sd[si], sd[si + 1], sd[si + 2]];
                    const destPixel = [sd[ni], sd[ni + 1], sd[ni + 2]];
                    const diff = [srcPixel[0] - avgR, srcPixel[1] - avgG, srcPixel[2] - avgB];
                    sd[ni] = Math.max(0, Math.min(255, destPixel[0] + diff[0] * brushOpacity));
                    sd[ni + 1] = Math.max(0, Math.min(255, destPixel[1] + diff[1] * brushOpacity));
                    sd[ni + 2] = Math.max(0, Math.min(255, destPixel[2] + diff[2] * brushOpacity));
                }
            }
        }
        ctx.putImageData(srcData, 0, 0);
        ctx.restore();
    }

    // --- D. Content-Aware Fill ---
    function contentAwareFill() {
        if (!selectionRect || !selectionData) { showToast('Selecciona un área primero'); return; }
        const layer = getActiveLayer();
        if (!layer) return;
        const ctx = layer.ctx;
        const w = layer.canvas.width, h = layer.canvas.height;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const srcData = ctx.getImageData(0, 0, w, h);
        const sd = srcData.data;
        const rx = Math.max(0, Math.floor(selectionRect.x * dpr));
        const ry = Math.max(0, Math.floor(selectionRect.y * dpr));
        const rw = Math.min(w - rx, Math.floor(selectionRect.w * dpr));
        const rh = Math.min(h - ry, Math.floor(selectionRect.h * dpr));
        const borderSamples = [];
        const bSize = 3;
        for (let bx = rx - bSize; bx < rx + rw + bSize; bx++) {
            for (let by = ry - bSize; by < ry; by++) {
                if (bx >= 0 && bx < w && by >= 0 && by < h) {
                    const i = (by * w + bx) * 4;
                    borderSamples.push([sd[i], sd[i + 1], sd[i + 2]]);
                }
            }
            for (let by = ry + rh; by < ry + rh + bSize; by++) {
                if (bx >= 0 && bx < w && by >= 0 && by < h) {
                    const i = (by * w + bx) * 4;
                    borderSamples.push([sd[i], sd[i + 1], sd[i + 2]]);
                }
            }
        }
        for (let by = ry; by < ry + rh; by++) {
            for (let bx = rx - bSize; bx < rx; bx++) {
                if (bx >= 0 && bx < w && by >= 0 && by < h) {
                    const i = (by * w + bx) * 4;
                    borderSamples.push([sd[i], sd[i + 1], sd[i + 2]]);
                }
            }
            for (let bx = rx + rw; bx < rx + rw + bSize; bx++) {
                if (bx >= 0 && bx < w && by >= 0 && by < h) {
                    const i = (by * w + bx) * 4;
                    borderSamples.push([sd[i], sd[i + 1], sd[i + 2]]);
                }
            }
        }
        for (let dy = 0; dy < rh; dy++) {
            for (let dx = 0; dx < rw; dx++) {
                const nx = rx + dx, ny = ry + dy;
                if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                    const i = (ny * w + nx) * 4;
                    if (sd[i + 3] > 0) {
                        const sample = borderSamples[(dx * 7 + dy * 13) % borderSamples.length];
                        const blend = 0.6 + Math.random() * 0.4;
                        sd[i] = Math.floor(sd[i] * (1 - blend) + sample[0] * blend);
                        sd[i + 1] = Math.floor(sd[i + 1] * (1 - blend) + sample[1] * blend);
                        sd[i + 2] = Math.floor(sd[i + 2] * (1 - blend) + sample[2] * blend);
                    }
                }
            }
        }
        ctx.putImageData(srcData, 0, 0);
        ctx.restore();
        compositeDirty = true; renderComposite(); saveState();
        showToast('Relleno con contenido aplicado');
    }

    // --- E. Patch Tool ---
    let patchSource = null;
    let patchDest = null;
    let patchDragging = false;

    function patchToolCopy() {
        if (!selectionRect || !selectionData) { showToast('Selecciona un área para parchear'); return; }
        patchSource = { ...selectionRect, data: ctx.getImageData(selectionRect.x * dpr, selectionRect.y * dpr, selectionRect.w * dpr, selectionRect.h * dpr) };
        showToast('Área de origen copiada. Selecciona destino y pega.');
    }

    function patchToolPaste() {
        if (!patchSource || !selectionRect) return;
        const layer = getActiveLayer();
        if (!layer) return;
        const ctx = layer.ctx;
        ctx.save();
        ctx.globalAlpha = 0.7;
        ctx.drawImage(patchSource.data, selectionRect.x * dpr, selectionRect.y * dpr, selectionRect.w * dpr, selectionRect.h * dpr);
        ctx.restore();
        compositeDirty = true; renderComposite(); saveState();
        patchSource = null;
        showToast('Parche aplicado');
    }

    // --- F. Color Grading (LUTs) ---
    const colorGradingPresets = [
        { name: 'Cinematic', lut: (r, g, b) => [r * 0.9, g * 0.95, b * 1.1] },
        { name: 'Warm', lut: (r, g, b) => [r * 1.1, g * 1.02, b * 0.85] },
        { name: 'Cool', lut: (r, g, b) => [r * 0.85, g * 0.95, b * 1.15] },
        { name: 'Vintage', lut: (r, g, b) => [r * 1.05 + 10, g * 0.98, b * 0.9 - 5] },
        { name: 'Dramatic', lut: (r, g, b) => [r * 0.8, g * 0.8, b * 0.85].map(v => Math.max(0, Math.min(255, v + (v - 128) * 0.3))) },
        { name: 'Faded', lut: (r, g, b) => [r * 0.85 + 30, g * 0.85 + 25, b * 0.85 + 35] },
        { name: 'Film Noir', lut: (r, g, b) => { const gray = r * 0.3 + g * 0.59 + b * 0.11; return [gray * 1.1, gray, gray * 0.95]; } },
        { name: 'Sunset', lut: (r, g, b) => [r * 1.15, g * 0.9, b * 0.75] },
        { name: 'Ocean', lut: (r, g, b) => [r * 0.75, g * 0.9, b * 1.2] },
        { name: 'Forest', lut: (r, g, b) => [r * 0.85, g * 1.1, b * 0.8] }
    ];

    function applyColorGrading(presetIndex) {
        const layer = getActiveLayer();
        if (!layer || presetIndex < 0 || presetIndex >= colorGradingPresets.length) return;
        const preset = colorGradingPresets[presetIndex];
        const ctx = layer.ctx;
        const w = layer.canvas.width, h = layer.canvas.height;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        for (let i = 0; i < sd.length; i += 4) {
            const [nr, ng, nb] = preset.lut(sd[i], sd[i + 1], sd[i + 2]);
            sd[i] = Math.max(0, Math.min(255, nr));
            sd[i + 1] = Math.max(0, Math.min(255, ng));
            sd[i + 2] = Math.max(0, Math.min(255, nb));
        }
        ctx.putImageData(src, 0, 0);
        ctx.restore();
        compositeDirty = true; renderComposite(); saveState();
        showToast(`Color grading: ${preset.name}`);
    }

    function showColorGradingModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;';
        const grid = document.createElement('div');
        grid.style.cssText = 'display:grid;grid-template-columns:repeat(5,1fr);gap:6px;';
        colorGradingPresets.forEach((preset, i) => {
            const btn = document.createElement('button');
            btn.className = 'modal-btn';
            btn.style.cssText = 'font-size:9px;padding:8px 4px;text-align:center;';
            btn.textContent = preset.name;
            btn.addEventListener('click', () => { applyColorGrading(i); });
            grid.appendChild(btn);
        });
        wrapper.appendChild(grid);
        showModal({ title: 'Color Grading (LUTs)', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    // --- G. CMYK Proof ---
    function rgbToCmyk(r, g, b) {
        if (r === 0 && g === 0 && b === 0) return { c: 0, m: 0, y: 0, k: 100 };
        const c = (1 - r / 255) * 100;
        const m = (1 - g / 255) * 100;
        const y = (1 - b / 255) * 100;
        const k = Math.min(c, m, y);
        return { c: Math.round(c - k), m: Math.round(m - k), y: Math.round(y - k), k: Math.round(k) };
    }

    function showCMYKProof() {
        const layer = getActiveLayer();
        if (!layer) return;
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;';
        const previewCanvas = document.createElement('canvas');
        previewCanvas.width = 250; previewCanvas.height = 180;
        previewCanvas.style.cssText = 'width:100%;border-radius:8px;border:1px solid var(--border-color);background:#1a1a1a;';
        const prevCtx = previewCanvas.getContext('2d');
        prevCtx.drawImage(layer.canvas, 0, 0, 250, 180);
        const imgData = prevCtx.getImageData(0, 0, 250, 180);
        const sd = imgData.data;
        for (let i = 0; i < sd.length; i += 4) {
            const cmyk = rgbToCmyk(sd[i], sd[i + 1], sd[i + 2]);
            const factor = 1 - cmyk.k / 100;
            sd[i] = Math.min(255, sd[i] * factor + cmyk.c * 1.5);
            sd[i + 1] = Math.min(255, sd[i + 1] * factor + cmyk.m * 1.5);
            sd[i + 2] = Math.min(255, sd[i + 2] * factor + cmyk.y * 1.5);
        }
        prevCtx.putImageData(imgData, 0, 0);
        wrapper.appendChild(previewCanvas);
        const info = document.createElement('div');
        info.style.cssText = 'font-size:9px;color:var(--text-secondary);line-height:1.5;';
        info.innerHTML = 'Vista previa de impresión CMYK. Los colores se ajustan para simular la gamut de impresión.';
        wrapper.appendChild(info);
        showModal({ title: 'Prueba de Color CMYK', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    // --- H. ICC Profile Support ---
    let currentICCProfile = 'sRGB';
    const iccProfiles = {
        'sRGB': { name: 'sRGB IEC61966-2.1', description: 'Perfil estándar para web', gamma: 2.2 },
        'adobeRGB': { name: 'Adobe RGB (1998)', description: 'Gama amplia para impresión', gamma: 2.2 },
        'displayP3': { name: 'Display P3', description: 'Pantallas Apple modernas', gamma: 2.2 },
        'proPhoto': { name: 'ProPhoto RGB', description: 'Gama más amplia para fotografía', gamma: 1.8 },
        'printCMYK': { name: 'CMYK (Impresión)', description: 'Simulación de gamut de impresión', gamma: 1.4 }
    };

    function showICCProfileModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:6px;';
        Object.entries(iccProfiles).forEach(([key, profile]) => {
            const row = document.createElement('div');
            row.style.cssText = `display:flex;align-items:center;gap:8px;padding:8px;border-radius:6px;border:1px solid ${currentICCProfile === key ? 'var(--accent-color)' : 'var(--border-color)'};cursor:pointer;background:${currentICCProfile === key ? 'rgba(var(--accent-color-rgb),0.1)' : 'var(--canvas-bg)'};`;
            const radio = document.createElement('div');
            radio.style.cssText = `width:16px;height:16px;border-radius:50%;border:2px solid ${currentICCProfile === key ? 'var(--accent-color)' : 'var(--border-color)'};display:flex;align-items:center;justify-content:center;`;
            if (currentICCProfile === key) {
                radio.innerHTML = '<div style="width:8px;height:8px;border-radius:50%;background:var(--accent-color);"></div>';
            }
            row.appendChild(radio);
            const info = document.createElement('div');
            info.style.cssText = 'flex:1;';
            const name = document.createElement('div');
            name.style.cssText = 'font-size:11px;color:var(--text-color);font-weight:600;';
            name.textContent = profile.name;
            const desc = document.createElement('div');
            desc.style.cssText = 'font-size:9px;color:var(--text-secondary);';
            desc.textContent = profile.description;
            info.appendChild(name); info.appendChild(desc);
            row.appendChild(info);
            row.addEventListener('click', () => { currentICCProfile = key; wrapper.querySelectorAll('div[style*="border-radius:6px"]').forEach(r => r.remove()); renderProfileList(); });
            wrapper.appendChild(row);
        });
        function renderProfileList() {
            wrapper.innerHTML = '';
            Object.entries(iccProfiles).forEach(([key, profile]) => {
                const row = document.createElement('div');
                row.style.cssText = `display:flex;align-items:center;gap:8px;padding:8px;border-radius:6px;border:1px solid ${currentICCProfile === key ? 'var(--accent-color)' : 'var(--border-color)'};cursor:pointer;background:${currentICCProfile === key ? 'rgba(var(--accent-color-rgb),0.1)' : 'var(--canvas-bg)'};`;
                const radio = document.createElement('div');
                radio.style.cssText = `width:16px;height:16px;border-radius:50%;border:2px solid ${currentICCProfile === key ? 'var(--accent-color)' : 'var(--border-color)'};display:flex;align-items:center;justify-content:center;`;
                if (currentICCProfile === key) radio.innerHTML = '<div style="width:8px;height:8px;border-radius:50%;background:var(--accent-color);"></div>';
                row.appendChild(radio);
                const info = document.createElement('div'); info.style.cssText = 'flex:1;';
                const name = document.createElement('div'); name.style.cssText = 'font-size:11px;color:var(--text-color);font-weight:600;'; name.textContent = profile.name;
                const desc = document.createElement('div'); desc.style.cssText = 'font-size:9px;color:var(--text-secondary);'; desc.textContent = profile.description;
                info.appendChild(name); info.appendChild(desc);
                row.appendChild(info);
                row.addEventListener('click', () => { currentICCProfile = key; renderProfileList(); });
                wrapper.appendChild(row);
            });
        }
        showModal({ title: 'Perfil ICC', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    // --- I. Texture Cache ---
    const textureCache = new Map();
    const TEXTURE_CACHE_MAX = 50;
    function getTextureFromCache(key) { return textureCache.get(key) || null; }
    function setTextureCache(key, texture) {
        if (textureCache.size >= TEXTURE_CACHE_MAX) {
            const firstKey = textureCache.keys().next().value;
            textureCache.delete(firstKey);
        }
        textureCache.set(key, texture);
    }
    function clearTextureCache() { textureCache.clear(); }

    // --- J. Batch Processing ---
    function showBatchProcessingModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;max-height:60vh;overflow-y:auto;';

        const fileInput = document.createElement('input');
        fileInput.type = 'file'; fileInput.multiple = true; fileInput.accept = 'image/*';
        fileInput.style.cssText = 'display:none;';
        wrapper.appendChild(fileInput);

        const dropZone = document.createElement('div');
        dropZone.style.cssText = 'border:2px dashed var(--border-color);border-radius:10px;padding:24px;text-align:center;cursor:pointer;transition:border-color 0.2s;';
        dropZone.innerHTML = '<div style="font-size:11px;color:var(--text-secondary);">Arrastra imágenes aquí o haz clic para seleccionar</div>';
        dropZone.addEventListener('click', () => fileInput.click());
        dropZone.addEventListener('dragover', (e) => { e.preventDefault(); dropZone.style.borderColor = 'var(--accent-color)'; });
        dropZone.addEventListener('dragleave', () => { dropZone.style.borderColor = 'var(--border-color)'; });
        dropZone.addEventListener('drop', (e) => {
            e.preventDefault(); dropZone.style.borderColor = 'var(--border-color)';
            const files = Array.from(e.dataTransfer.files).filter(f => f.type.startsWith('image/'));
            if (files.length) showBatchFileList(files);
        });
        wrapper.appendChild(dropZone);

        const fileListDiv = document.createElement('div');
        fileListDiv.style.cssText = 'display:flex;flex-direction:column;gap:4px;';
        wrapper.appendChild(fileListDiv);

        const filterSelect = document.createElement('select');
        filterSelect.style.cssText = 'width:100%;background:var(--canvas-bg);color:var(--text-color);border:1px solid var(--border-color);border-radius:6px;padding:6px 8px;font-size:11px;';
        ['Ninguno', 'Grayscale', 'Sepia', 'Blur', 'Sharpen', 'Invert', 'Brightness +20', 'Contrast +20'].forEach(opt => {
            const option = document.createElement('option');
            option.value = opt.toLowerCase().replace(/[^a-z]/g, '');
            option.textContent = opt;
            filterSelect.appendChild(option);
        });
        wrapper.appendChild(filterSelect);

        const formatSelect = document.createElement('select');
        formatSelect.style.cssText = 'width:100%;background:var(--canvas-bg);color:var(--text-color);border:1px solid var(--border-color);border-radius:6px;padding:6px 8px;font-size:11px;';
        ['PNG', 'JPEG', 'WebP'].forEach(fmt => {
            const option = document.createElement('option');
            option.value = fmt.toLowerCase();
            option.textContent = fmt;
            formatSelect.appendChild(option);
        });
        wrapper.appendChild(formatSelect);

        let batchFiles = [];
        function showBatchFileList(files) {
            batchFiles = files;
            fileListDiv.innerHTML = '';
            files.forEach((f, i) => {
                const row = document.createElement('div');
                row.style.cssText = 'display:flex;align-items:center;gap:4px;font-size:9px;color:var(--text-secondary);';
                const num = document.createElement('span');
                num.style.cssText = 'min-width:20px;';
                num.textContent = `${i + 1}.`;
                const name = document.createElement('span');
                name.style.cssText = 'flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
                name.textContent = f.name;
                const size = document.createElement('span');
                size.textContent = `${Math.round(f.size / 1024)}KB`;
                row.appendChild(num); row.appendChild(name); row.appendChild(size);
                fileListDiv.appendChild(row);
            });
        }

        fileInput.addEventListener('change', () => {
            const files = Array.from(fileInput.files).filter(f => f.type.startsWith('image/'));
            if (files.length) showBatchFileList(files);
        });

        const progressDiv = document.createElement('div');
        progressDiv.style.cssText = 'font-size:10px;color:var(--text-secondary);text-align:center;min-height:16px;';
        wrapper.appendChild(progressDiv);

        showModal({
            title: 'Procesamiento por Lotes',
            body: wrapper,
            buttons: [
                { label: 'Cancelar', value: false },
                {
                    label: 'Procesar', class: 'primary', value: true, action: async () => {
                        if (batchFiles.length === 0) { showToast('Selecciona archivos primero'); return; }
                        const filter = filterSelect.value;
                        const format = formatSelect.value;
                        for (let i = 0; i < batchFiles.length; i++) {
                            progressDiv.textContent = `Procesando ${i + 1}/${batchFiles.length}...`;
                            const file = batchFiles[i];
                            const img = new Image();
                            await new Promise((resolve) => {
                                img.onload = () => {
                                    const c = document.createElement('canvas');
                                    c.width = img.width; c.height = img.height;
                                    const ctx = c.getContext('2d');
                                    ctx.drawImage(img, 0, 0);
                                    if (filter !== 'ninguno') {
                                        const w = c.width, h = c.height;
                                        const imageData = ctx.getImageData(0, 0, w, h);
                                        applyFilterToImageData(imageData, filter);
                                        ctx.putImageData(imageData, 0, 0);
                                    }
                                    const mimeType = format === 'jpeg' ? 'image/jpeg' : format === 'webp' ? 'image/webp' : 'image/png';
                                    c.toBlob((blob) => {
                                        const url = URL.createObjectURL(blob);
                                        const a = document.createElement('a');
                                        a.href = url;
                                        a.download = `${file.name.replace(/\.[^.]+$/, '')}-processed.${format}`;
                                        a.click();
                                        URL.revokeObjectURL(url);
                                        resolve();
                                    }, mimeType, 0.9);
                                };
                                img.src = URL.createObjectURL(file);
                            });
                            await new Promise(r => setTimeout(r, 100));
                        }
                        progressDiv.textContent = `${batchFiles.length} archivos procesados`;
                        showToast(`${batchFiles.length} archivos procesados y descargados`);
                    }
                }
            ]
        });

        function applyFilterToImageData(imageData, filter) {
            const d = imageData.data;
            for (let i = 0; i < d.length; i += 4) {
                if (filter === 'grayscale') {
                    const gray = d[i] * 0.3 + d[i + 1] * 0.59 + d[i + 2] * 0.11;
                    d[i] = d[i + 1] = d[i + 2] = gray;
                } else if (filter === 'sepia') {
                    const r = d[i], g = d[i + 1], b = d[i + 2];
                    d[i] = Math.min(255, r * 0.393 + g * 0.769 + b * 0.189);
                    d[i + 1] = Math.min(255, r * 0.349 + g * 0.686 + b * 0.168);
                    d[i + 2] = Math.min(255, r * 0.272 + g * 0.534 + b * 0.131);
                } else if (filter === 'invert') {
                    d[i] = 255 - d[i]; d[i + 1] = 255 - d[i + 1]; d[i + 2] = 255 - d[i + 2];
                } else if (filter === 'brightness20') {
                    d[i] = Math.min(255, d[i] + 20); d[i + 1] = Math.min(255, d[i + 1] + 20); d[i + 2] = Math.min(255, d[i + 2] + 20);
                } else if (filter === 'contrast20') {
                    const f = 1.2;
                    d[i] = Math.min(255, Math.max(0, (d[i] - 128) * f + 128));
                    d[i + 1] = Math.min(255, Math.max(0, (d[i + 1] - 128) * f + 128));
                    d[i + 2] = Math.min(255, Math.max(0, (d[i + 2] - 128) * f + 128));
                }
            }
        }
    }

    // --- K. Actions with Keyboard Shortcuts ---
    function showActionsShortcutModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:6px;max-height:60vh;overflow-y:auto;';
        const desc = document.createElement('div');
        desc.style.cssText = 'font-size:9px;color:var(--text-secondary);padding:4px 8px;';
        desc.textContent = 'Asigna atajos de teclado a macros guardadas. Selecciona una macro y presiona una tecla.';
        wrapper.appendChild(desc);
        if (savedMacros.length === 0) {
            const empty = document.createElement('div');
            empty.style.cssText = 'font-size:10px;color:var(--text-secondary);text-align:center;padding:12px;';
            empty.textContent = 'No hay macros guardadas.';
            wrapper.appendChild(empty);
        }
        const macroShortcuts = JSON.parse(localStorage.getItem('procreate-lite-macro-shortcuts') || '{}');
        savedMacros.forEach((macro, i) => {
            const row = document.createElement('div');
            row.style.cssText = 'display:flex;align-items:center;gap:6px;background:var(--canvas-bg);border-radius:6px;padding:6px 8px;border:1px solid var(--border-color);';
            const lbl = document.createElement('span');
            lbl.style.cssText = 'flex:1;font-size:10px;color:var(--text-color);';
            lbl.textContent = macro.name;
            row.appendChild(lbl);
            const keyBtn = document.createElement('button');
            keyBtn.className = 'tool-btn small';
            keyBtn.style.cssText = 'font-size:9px;min-width:40px;';
            keyBtn.textContent = macroShortcuts[i] || 'Asignar';
            keyBtn.addEventListener('click', () => {
                keyBtn.textContent = 'Presiona...';
                const handler = (e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    const key = e.key.length === 1 ? e.key.toUpperCase() : e.key;
                    macroShortcuts[i] = key;
                    try { localStorage.setItem('procreate-lite-macro-shortcuts', JSON.stringify(macroShortcuts)); } catch (e) { }
                    keyBtn.textContent = key;
                    document.removeEventListener('keydown', handler, true);
                    showToast(`Macro "${macro.name}" asignada a ${key}`);
                };
                document.addEventListener('keydown', handler, true);
            });
            row.appendChild(keyBtn);
            wrapper.appendChild(row);
        });
        showModal({ title: 'Atajos de Macros', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    // --- Brush Stabilization ---
    let brushStabilization = 0; // 0=none, 1-5=strength
    let strokeBuffer = [];
    function openBrushStabilizationPanel() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:12px;';
        const label = document.createElement('label');
        label.style.cssText = 'font-size:12px;color:var(--text-color);';
        label.textContent = 'Estabilización de trazo:';
        const slider = document.createElement('input');
        slider.type = 'range';
        slider.min = '0';
        slider.max = '5';
        slider.value = brushStabilization;
        slider.style.cssText = 'width:100%;';
        const value = document.createElement('span');
        value.style.cssText = 'font-size:10px;color:var(--text-secondary);text-align:center;';
        value.textContent = brushStabilization === 0 ? 'Desactivado' : `Nivel ${brushStabilization}`;
        slider.addEventListener('input', () => {
            brushStabilization = parseInt(slider.value);
            value.textContent = brushStabilization === 0 ? 'Desactivado' : `Nivel ${brushStabilization}`;
            strokeBuffer = [];
        });
        wrapper.appendChild(label);
        wrapper.appendChild(slider);
        wrapper.appendChild(value);
        showModal({ title: 'Estabilización', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }
    function getStabilizedPoint(x, y) {
        if (brushStabilization === 0) return { x, y };
        strokeBuffer.push({ x, y });
        if (strokeBuffer.length > brushStabilization + 2) strokeBuffer.shift();
        const smooth = strokeBuffer.length;
        let sumX = 0, sumY = 0;
        for (let i = 0; i < strokeBuffer.length; i++) {
            sumX += strokeBuffer[strokeBuffer.length - 1 - i].x;
            sumY += strokeBuffer[strokeBuffer.length - 1 - i].y;
        }
        return { x: sumX / smooth, y: sumY / smooth };
    }

    // --- L. Reference Panel Enhancement ---
    let refPanelImages = [];
    function showEnhancedReferencePanel() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;max-height:60vh;overflow-y:auto;';
        const addRow = document.createElement('div');
        addRow.style.cssText = 'display:flex;gap:4px;';
        const addBtn = document.createElement('button');
        addBtn.className = 'modal-btn primary';
        addBtn.style.cssText = 'flex:1;font-size:10px;padding:6px;';
        addBtn.textContent = '+ Agregar imagen de referencia';
        addBtn.addEventListener('click', () => {
            const input = document.createElement('input');
            input.type = 'file'; input.accept = 'image/*';
            input.addEventListener('change', () => {
                const file = input.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                    refPanelImages.push({ src: ev.target.result, name: file.name, opacity: 0.5, x: 100, y: 100, w: 200, h: 150 });
                    renderRefList();
                };
                reader.readAsDataURL(file);
            });
            input.click();
        });
        addRow.appendChild(addBtn);
        wrapper.appendChild(addRow);
        const listDiv = document.createElement('div');
        listDiv.style.cssText = 'display:flex;flex-direction:column;gap:4px;';
        function renderRefList() {
            listDiv.innerHTML = '';
            refPanelImages.forEach((ref, i) => {
                const row = document.createElement('div');
                row.style.cssText = 'display:flex;align-items:center;gap:4px;background:var(--canvas-bg);border-radius:6px;padding:6px 8px;border:1px solid var(--border-color);';
                const thumb = document.createElement('img');
                thumb.src = ref.src;
                thumb.style.cssText = 'width:32px;height:32px;border-radius:4px;object-fit:cover;border:1px solid var(--border-color);';
                row.appendChild(thumb);
                const name = document.createElement('span');
                name.style.cssText = 'flex:1;font-size:9px;color:var(--text-color);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
                name.textContent = ref.name;
                row.appendChild(name);
                const showBtn = document.createElement('button');
                showBtn.className = 'tool-btn small';
                showBtn.innerHTML = '<i class="ri-eye-line"></i>';
                showBtn.title = 'Mostrar/Ocultar';
showBtn.addEventListener('click', () => {
                     const overlay = document.getElementById('ref-image-overlay');
                     const imgEl = document.getElementById('ref-image-el');
                     if (imgEl.src === ref.src && !overlay.classList.contains('hidden')) {
                         overlay.classList.add('hidden');
                     } else {
                         imgEl.src = ref.src;
                         overlay.classList.remove('hidden');
                         overlay.style.opacity = ref.opacity;
                         overlay.style.left = ref.x + 'px';
                         overlay.style.top = ref.y + 'px';
                         overlay.style.width = ref.w + 'px';
                         overlay.style.height = ref.h + 'px';
                         // Enable dragging
                         let dragStart = null;
                         let startW = ref.w, startH = ref.h;
                         overlay.onmousedown = (e) => {
                             if (e.target === imgEl) {
                                 dragStart = { x: e.clientX, y: e.clientY, startX: ref.x, startY: ref.y };
                                 document.addEventListener('mousemove', dragMove);
                                 document.addEventListener('mouseup', dragEnd);
                             }
                         };
                         function dragMove(e) {
                             if (dragStart) {
                                 ref.x = dragStart.startX + (e.clientX - dragStart.x);
                                 ref.y = dragStart.startY + (e.clientY - dragStart.y);
                                 overlay.style.left = ref.x + 'px';
                                 overlay.style.top = ref.y + 'px';
                             }
                         }
                         function dragEnd() {
                             dragStart = null;
                             document.removeEventListener('mousemove', dragMove);
                             document.removeEventListener('mouseup', dragEnd);
                         }
                     }
                 });
                row.appendChild(showBtn);
                const delBtn = document.createElement('button');
                delBtn.className = 'tool-btn small';
                delBtn.innerHTML = '<i class="ri-delete-bin-line"></i>';
                delBtn.title = 'Eliminar';
                delBtn.addEventListener('click', () => { refPanelImages.splice(i, 1); renderRefList(); });
                row.appendChild(delBtn);
                // Opacity control
                const opacitySlider = document.createElement('input');
                opacitySlider.type = 'range';
                opacitySlider.min = '10';
                opacitySlider.max = '100';
                opacitySlider.value = Math.round(ref.opacity * 100);
                opacitySlider.style.cssText = 'width:40px;height:12px;';
                opacitySlider.title = 'Opacidad';
                opacitySlider.addEventListener('input', (e) => {
                    ref.opacity = parseInt(e.target.value) / 100;
                    const overlay = document.getElementById('ref-image-overlay');
                    if (overlay && !overlay.classList.contains('hidden')) {
                        overlay.style.opacity = ref.opacity;
                    }
                });
                row.appendChild(opacitySlider);
                listDiv.appendChild(row);
            });
        }
        renderRefList();
        wrapper.appendChild(listDiv);
        showModal({ title: 'Panel de Referencias', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    // --- M. PDF with Layers ---
    async function exportPDFWithLayers() {
        if (layers.length === 0) { showToast('No hay capas para exportar'); return; }
        try {
            await loadScript('https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.2/jspdf.umd.min.js');
        } catch (e) {
            showToast('No se pudo cargar jsPDF. Verifica tu conexión.');
            return;
        }
        showToast('Generando PDF con capas...');
        await new Promise(r => setTimeout(r, 50));

        const { jsPDF } = window.jspdf;
        const orientation = logicalWidth > logicalHeight ? 'landscape' : 'portrait';
        const pdf = new jsPDF({ orientation, unit: 'px', format: [logicalWidth, logicalHeight] });

        // Set PDF metadata
        pdf.setProperties({
            title: `${projectName || 'Procreate Lite'} - Capas`,
            subject: 'Exportación con capas desde Procreate Lite',
            author: 'Procreate Lite',
            creator: 'Procreate Lite Web'
        });

        let pageNum = 0;
        const visibleLayers = layers.filter(l => l.visible);

        for (let i = 0; i < visibleLayers.length; i++) {
            const layer = visibleLayers[i];
            pageNum++;

            if (pageNum > 1) pdf.addPage();

            // White background
            pdf.setFillColor(255, 255, 255);
            pdf.rect(0, 0, logicalWidth, logicalHeight, 'F');

            // Render layer
            const tempCanvas = document.createElement('canvas');
            tempCanvas.width = logicalWidth * dpr;
            tempCanvas.height = logicalHeight * dpr;
            const tempCtx = tempCanvas.getContext('2d');
            tempCtx.drawImage(layer.canvas, 0, 0);

            const imgData = tempCanvas.toDataURL('image/png');
            pdf.addImage(imgData, 'PNG', 0, 0, logicalWidth, logicalHeight);

            // Add layer info text
            pdf.setFontSize(8);
            pdf.setTextColor(100, 100, 100);
            pdf.text(`Capa: ${layer.name} | Opacidad: ${Math.round(layer.opacity * 100)}% | Modo: ${layer.blendMode}`, 10, logicalHeight - 10);
            pdf.text(`Página ${pageNum} de ${visibleLayers.length}`, logicalWidth - 80, logicalHeight - 10);
        }

        pdf.save(`${projectName || 'procreate-lite'}-capas.pdf`);
        showToast(`PDF con ${visibleLayers.length} páginas exportado`);
    }

    // --- N. Animated SVG ---
    function exportAnimatedSVG() {
        if (layers.length < 2) { showToast('Necesitas al menos 2 capas para SVG animado'); return; }
        const svgLayers = [];
        layers.forEach((layer, i) => {
            if (!layer.visible) return;
            const dataUrl = layer.canvas.toDataURL('image/png');
            svgLayers.push(`<image href="${dataUrl}" x="0" y="0" width="${logicalWidth}" height="${logicalHeight}" opacity="${layer.opacity}"><animate attributeName="opacity" values="0;${layer.opacity};${layer.opacity};0" dur="${2 + i}s" begin="${i * 0.5}s" repeatCount="indefinite"/></image>`);
        });
        const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${logicalWidth} ${logicalHeight}" width="${logicalWidth}" height="${logicalHeight}">${svgLayers.join('')}</svg>`;
        const blob = new Blob([svg], { type: 'image/svg+xml' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = `${projectName || 'procreate-lite'}-animated.svg`; a.click();
        URL.revokeObjectURL(url);
        showToast('SVG animado exportado');
    }

    // --- O. Smart Upscaling ---
    function smartUpscale() {
        const layer = getActiveLayer();
        if (!layer) return;
        const newW = Math.min(4096, layer.canvas.width * 2);
        const newH = Math.min(4096, layer.canvas.height * 2);
        const tempCanvas = document.createElement('canvas');
        tempCanvas.width = newW; tempCanvas.height = newH;
        const tempCtx = tempCanvas.getContext('2d');
        tempCtx.imageSmoothingEnabled = true;
        tempCtx.imageSmoothingQuality = 'high';
        tempCtx.drawImage(layer.canvas, 0, 0, newW, newH);
        const srcData = tempCtx.getImageData(0, 0, newW, newH);
        const sd = srcData.data;
        for (let y = 1; y < newH - 1; y++) {
            for (let x = 1; x < newW - 1; x++) {
                const i = (y * newW + x) * 4;
                for (let c = 0; c < 3; c++) {
                    const gx = sd[i + c - 4] + sd[i + c + 4] - sd[(y - 1) * newW + x + c - 4] + sd[(y - 1) * newW + x + c + 4];
                    const gy = sd[i + c - newW * 4] + sd[i + c + newW * 4];
                    const edge = Math.abs(gx) + Math.abs(gy);
                    if (edge > 50) {
                        const avg = (sd[i + c - 4] + sd[i + c + 4] + sd[i + c - newW * 4] + sd[i + c + newW * 4]) / 4;
                        sd[i + c] = Math.round(sd[i + c] * 0.7 + avg * 0.3);
                    }
                }
            }
        }
        tempCtx.putImageData(srcData, 0, 0);
        layer.canvas.width = newW; layer.canvas.height = newH;
        layer.ctx.drawImage(tempCanvas, 0, 0);
        logicalWidth = newW / dpr; logicalHeight = newH / dpr;
        compositeDirty = true; renderComposite(); saveState();
        showToast(`Canvas upscaled a ${Math.round(newW / dpr)}x${Math.round(newH / dpr)}`);
    }

    // --- P. Background Removal ---
    function removeBackground() {
        const layer = getActiveLayer();
        if (!layer) return;
        const ctx = layer.ctx;
        const w = layer.canvas.width, h = layer.canvas.height;
        ctx.save();
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        let bgR = 0, bgG = 0, bgB = 0, bgCount = 0;
        const sampleSize = Math.min(10, Math.floor(w * 0.05));
        for (let y = 0; y < sampleSize; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                bgR += sd[i]; bgG += sd[i + 1]; bgB += sd[i + 2]; bgCount++;
            }
        }
        for (let y = h - sampleSize; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                bgR += sd[i]; bgG += sd[i + 1]; bgB += sd[i + 2]; bgCount++;
            }
        }
        for (let x = 0; x < sampleSize; x++) {
            for (let y = 0; y < h; y++) {
                const i = (y * w + x) * 4;
                bgR += sd[i]; bgG += sd[i + 1]; bgB += sd[i + 2]; bgCount++;
            }
        }
        for (let x = w - sampleSize; x < w; x++) {
            for (let y = 0; y < h; y++) {
                const i = (y * w + x) * 4;
                bgR += sd[i]; bgG += sd[i + 1]; bgB += sd[i + 2]; bgCount++;
            }
        }
        bgR = Math.round(bgR / bgCount); bgG = Math.round(bgG / bgCount); bgB = Math.round(bgB / bgCount);
        const tolerance = 60;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                const dist = Math.sqrt((sd[i] - bgR) ** 2 + (sd[i + 1] - bgG) ** 2 + (sd[i + 2] - bgB) ** 2);
                if (dist < tolerance) {
                    sd[i + 3] = Math.max(0, Math.round((dist / tolerance) * 255));
                }
            }
        }
        ctx.putImageData(src, 0, 0);
        ctx.restore();
        compositeDirty = true; renderComposite(); saveState();
        showToast('Fondo eliminado (basado en color de borde)');
    }

    // --- Q. Color Suggestions ---
    function suggestColors() {
        const layer = getActiveLayer();
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const scale = Math.min(1, 100 / Math.max(w, h));
        const sw = Math.max(2, Math.floor(w * scale));
        const sh = Math.max(2, Math.floor(h * scale));
        const tmpCanvas = document.createElement('canvas');
        tmpCanvas.width = sw; tmpCanvas.height = sh;
        const tmpCtx = tmpCanvas.getContext('2d');
        tmpCtx.drawImage(layer.canvas, 0, 0, sw, sh);
        const imgData = tmpCtx.getImageData(0, 0, sw, sh).data;
        const colorBuckets = new Map();
        for (let i = 0; i < imgData.length; i += 4) {
            if (imgData[i + 3] < 128) continue;
            const r = Math.round(imgData[i] / 32) * 32;
            const g = Math.round(imgData[i + 1] / 32) * 32;
            const b = Math.round(imgData[i + 2] / 32) * 32;
            const key = `${r},${g},${b}`;
            colorBuckets.set(key, (colorBuckets.get(key) || 0) + 1);
        }
        const sorted = [...colorBuckets.entries()].sort((a, b) => b[1] - a[1]).slice(0, 8);
        const dominantColors = sorted.map(([key]) => {
            const [r, g, b] = key.split(',').map(Number);
            return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`;
        });

        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;';
        const domLabel = document.createElement('div');
        domLabel.style.cssText = 'font-size:10px;color:var(--text-secondary);';
        domLabel.textContent = 'Colores dominantes:';
        wrapper.appendChild(domLabel);
        const domRow = document.createElement('div');
        domRow.style.cssText = 'display:flex;gap:4px;flex-wrap:wrap;';
        dominantColors.forEach(c => {
            const swatch = document.createElement('div');
            swatch.style.cssText = `width:32px;height:32px;border-radius:6px;background:${c};cursor:pointer;border:2px solid var(--border-color);transition:border-color 0.15s;`;
            swatch.addEventListener('mouseenter', () => { swatch.style.borderColor = 'var(--accent-color)'; });
            swatch.addEventListener('mouseleave', () => { swatch.style.borderColor = 'var(--border-color)'; });
            swatch.addEventListener('click', () => {
                const rgb = hexToRgb(c);
                const hsb = rgbToHsb(rgb.r, rgb.g, rgb.b);
                currentHue = hsb.h; currentSat = hsb.s; currentBri = hsb.b;
                updateColorFromHSB();
            });
            domRow.appendChild(swatch);
        });
        wrapper.appendChild(domRow);

        const complementLabel = document.createElement('div');
        complementLabel.style.cssText = 'font-size:10px;color:var(--text-secondary);';
        complementLabel.textContent = 'Sugerencias de armonía:';
        wrapper.appendChild(complementLabel);

        const harmonyTypes = ['Complementario', 'Triádico', 'Análogo', 'Split-complementario'];
        harmonyTypes.forEach(type => {
            const baseHsb = rgbToHsb(...Object.values(hexToRgb(dominantColors[0] || '#000000')));
            let suggested = [];
            if (type === 'Complementario') {
                suggested = [(baseHsb.h + 180) % 360].map(h => hsbToHex(h, baseHsb.s, baseHsb.b));
            } else if (type === 'Triádico') {
                suggested = [(baseHsb.h + 120) % 360, (baseHsb.h + 240) % 360].map(h => hsbToHex(h, baseHsb.s, baseHsb.b));
            } else if (type === 'Análogo') {
                suggested = [(baseHsb.h + 30) % 360, (baseHsb.h - 30 + 360) % 360].map(h => hsbToHex(h, baseHsb.s, baseHsb.b));
            } else {
                suggested = [(baseHsb.h + 150) % 360, (baseHsb.h + 210) % 360].map(h => hsbToHex(h, baseHsb.s, baseHsb.b));
            }
            const row = document.createElement('div');
            row.style.cssText = 'display:flex;align-items:center;gap:6px;margin-bottom:4px;';
            const typeName = document.createElement('span');
            typeName.style.cssText = 'font-size:9px;color:var(--text-secondary);min-width:100px;';
            typeName.textContent = type;
            row.appendChild(typeName);
            suggested.forEach(c => {
                const swatch = document.createElement('div');
                swatch.style.cssText = `width:24px;height:24px;border-radius:4px;background:${c};cursor:pointer;border:2px solid var(--border-color);`;
                swatch.addEventListener('click', () => {
                    const rgb = hexToRgb(c);
                    const hsb = rgbToHsb(rgb.r, rgb.g, rgb.b);
                    currentHue = hsb.h; currentSat = hsb.s; currentBri = hsb.b;
                    updateColorFromHSB();
                });
                row.appendChild(swatch);
            });
            wrapper.appendChild(row);
        });

        showModal({ title: 'Sugerencias de Color', body: wrapper, buttons: [{ label: 'Cerrar', class: '' }] });
    }

    function hsbToHex(h, s, b) {
        h = ((h % 360) + 360) % 360;
        s = Math.max(0, Math.min(100, s)) / 100;
        b = Math.max(0, Math.min(100, b)) / 100;
        const c = b * s;
        const x = c * (1 - Math.abs((h / 60) % 2 - 1));
        const m = b - c;
        let r, g, bl;
        if (h < 60) { r = c; g = x; bl = 0; }
        else if (h < 120) { r = x; g = c; bl = 0; }
        else if (h < 180) { r = 0; g = c; bl = x; }
        else if (h < 240) { r = 0; g = x; bl = c; }
        else if (h < 300) { r = x; g = 0; bl = c; }
        else { r = c; g = 0; bl = x; }
        const toHex = v => Math.round((v + m) * 255).toString(16).padStart(2, '0');
        return '#' + toHex(r) + toHex(g) + toHex(bl);
    }

