    if (btnRemoveBg) btnRemoveBg.addEventListener('click', removeBackground);

    const btnColorSuggest = document.getElementById('btn-color-suggest');
    if (btnColorSuggest) btnColorSuggest.addEventListener('click', suggestColors);

    // --- Patch tool into draw() for healing brush ---
    const _origDrawHealing = draw;
    const _origDrawHealingFn = draw;
    // Monkey-patch the draw function to add healing brush support
    const _origApplyBrush = applyBrush;
    applyBrush = function (ctx, e, isStart) {
        if (btnHealingBrush && btnHealingBrush.classList.contains('active')) {
            const pos = getCanvasPos(e);
            healingBrushStroke(pos.x, pos.y, brushSize);
            return;
        }
        return _origApplyBrush.apply(this, arguments);
    };

    // =====================================================================
    // BATCH 21: DRAWING TOOLS, EFFECTS, TEXTURES, COMPOSITING, AUTOMATION
    // =====================================================================

    // --- A. Pencil with Paper Texture ---
    let pencilPaperTexture = 'grain'; // 'grain', 'smooth', 'rough', 'canvas'
    const paperTextures = {
        grain: { name: 'Grano fino', intensity: 0.15, scale: 2 },
        smooth: { name: 'Liso', intensity: 0.05, scale: 1 },
        rough: { name: 'Rugoso', intensity: 0.3, scale: 4 },
        canvas: { name: 'Lienzo', intensity: 0.2, scale: 3 }
    };

    function generatePaperTexture(type, w, h) {
        const c = document.createElement('canvas');
        c.width = w; c.height = h;
        const ctx = c.getContext('2d');
        const settings = paperTextures[type] || paperTextures.grain;
        const imgData = ctx.createImageData(w, h);
        const d = imgData.data;
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const i = (y * w + x) * 4;
                const noise1 = Math.sin(x * 0.1 * settings.scale + y * 0.07) * 0.5 + 0.5;
                const noise2 = Math.sin(x * 0.05 + y * 0.12 * settings.scale) * 0.5 + 0.5;
                const combined = (noise1 + noise2) / 2;
                const val = Math.floor(128 + (combined - 0.5) * 255 * settings.intensity);
                d[i] = d[i + 1] = d[i + 2] = val;
                d[i + 3] = 255;
            }
        }
        ctx.putImageData(imgData, 0, 0);
        return c;
    }

    function drawPencilStroke(ctx, points, pressure, size, color) {
        if (points.length < 2) return;
        const paperCanvas = generatePaperTexture(pencilPaperTexture, Math.ceil(size * 2), Math.ceil(size * 2));
        ctx.save();
        for (let i = 0; i < points.length - 1; i++) {
            const p1 = points[i], p2 = points[i + 1];
            const dx = p2.x - p1.x, dy = p2.y - p1.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const steps = Math.max(1, Math.ceil(dist / 2));
            for (let s = 0; s < steps; s++) {
                const t = s / steps;
                const x = p1.x + dx * t;
                const y = p1.y + dy * t;
                const p = pressure * (0.5 + 0.5 * Math.sin(i * 0.3));
                const currentSize = Math.max(1, size * (0.3 + 0.7 * p));
                const paperX = Math.floor(Math.random() * paperCanvas.width);
                const paperY = Math.floor(Math.random() * paperCanvas.height);
                const paperCtx = paperCanvas.getContext('2d');
                const paperPixel = paperCtx.getImageData(paperX, paperY, 1, 1).data;
                const paperFactor = paperPixel[0] / 255;
                ctx.globalAlpha = brushOpacity * p * (0.7 + paperFactor * 0.3);
                ctx.fillStyle = color;
                ctx.beginPath();
                ctx.arc(x, y, currentSize / 2, 0, Math.PI * 2);
                ctx.fill();
            }
        }
        ctx.restore();
    }

    // --- B. Watercolor Brush with Wet Mix ---
    let watercolorWetness = 0.6;
    let watercolorBleed = 0.3;
    const watercolorBuffer = [];

    function drawWatercolorStroke(ctx, points, pressure, size, color) {
        if (points.length < 2) return;
        const rgb = hexToRgb(color);
        ctx.save();
        for (let i = 0; i < points.length - 1; i++) {
            const p1 = points[i], p2 = points[i + 1];
            const dx = p2.x - p1.x, dy = p2.y - p1.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const steps = Math.max(1, Math.ceil(dist / 3));
            for (let s = 0; s <= steps; s++) {
                const t = s / steps;
                const x = p1.x + dx * t;
                const y = p1.y + dy * t;
                const p = pressure * (0.6 + 0.4 * Math.sin(i * 0.2));
                const currentSize = size * (0.5 + 0.5 * p);
                const bleedX = x + (Math.random() - 0.5) * currentSize * watercolorBleed;
                const bleedY = y + (Math.random() - 0.5) * currentSize * watercolorBleed;
                ctx.globalAlpha = brushOpacity * p * watercolorWetness * 0.3;
                const gradient = ctx.createRadialGradient(bleedX, bleedY, 0, bleedX, bleedY, currentSize / 2);
                gradient.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},0.4)`);
                gradient.addColorStop(0.5, `rgba(${rgb.r},${rgb.g},${rgb.b},0.2)`);
                gradient.addColorStop(1, `rgba(${rgb.r},${rgb.g},${rgb.b},0)`);
                ctx.fillStyle = gradient;
                ctx.beginPath();
                ctx.arc(bleedX, bleedY, currentSize / 2, 0, Math.PI * 2);
                ctx.fill();
                watercolorBuffer.push({ x: bleedX, y: bleedY, size: currentSize * 0.8, color: `rgba(${rgb.r},${rgb.g},${rgb.b},0.1)` });
            }
        }
        watercolorBuffer.forEach(drop => {
            ctx.globalAlpha = 0.05;
            ctx.fillStyle = drop.color;
            ctx.beginPath();
            ctx.arc(drop.x + (Math.random() - 0.5) * 4, drop.y + (Math.random() - 0.5) * 4, drop.size / 2, 0, Math.PI * 2);
            ctx.fill();
        });
        watercolorBuffer.length = 0;
        ctx.restore();
    }

    // --- C. Spray with Particles ---
    let sprayDensity = 50;
    let sprayRadius = 30;
    let sprayFadeRate = 0.02;

    function drawSprayStroke(ctx, x, y, size, color, pressure) {
        const rgb = hexToRgb(color);
        ctx.save();
        const particles = Math.floor(sprayDensity * pressure);
        for (let i = 0; i < particles; i++) {
            const angle = Math.random() * Math.PI * 2;
            const radius = Math.random() * sprayRadius * (size / 20);
            const px = x + Math.cos(angle) * radius;
            const py = y + Math.sin(angle) * radius;
            const particleSize = 0.5 + Math.random() * 2;
            const alpha = brushOpacity * (1 - radius / (sprayRadius * size / 20)) * 0.6;
            ctx.globalAlpha = alpha;
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.arc(px, py, particleSize, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    // --- D. Speed Line ---
    let speedLineMinWidth = 1;
    let speedLineMaxWidth = 15;
    let speedLineSmoothing = 0.3;

    function drawSpeedLine(ctx, points, pressure, size, color) {
        if (points.length < 2) return;
        ctx.save();
        ctx.strokeStyle = color;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        let prevVelocity = 0;
        for (let i = 1; i < points.length; i++) {
            const p1 = points[i - 1], p2 = points[i];
            const dx = p2.x - p1.x, dy = p2.y - p1.y;
            const velocity = Math.sqrt(dx * dx + dy * dy);
            const smoothedVelocity = prevVelocity * (1 - speedLineSmoothing) + velocity * speedLineSmoothing;
            const widthFactor = Math.min(1, smoothedVelocity / 20);
            const lineWidth = speedLineMinWidth + (speedLineMaxWidth - speedLineMinWidth) * widthFactor * pressure;
            ctx.globalAlpha = brushOpacity * (0.3 + 0.7 * widthFactor);
            ctx.lineWidth = lineWidth;
            ctx.beginPath();
            ctx.moveTo(p1.x, p1.y);
            ctx.lineTo(p2.x, p2.y);
            ctx.stroke();
            prevVelocity = smoothedVelocity;
        }
        ctx.restore();
    }

    // --- E. Lens Blur (Bokeh) ---
    function applyLensBlur(ctx, radius, brightness) {
        radius = radius || 5;
        brightness = brightness || 1.2;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const r = Math.ceil(radius);
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                let sumR = 0, sumG = 0, sumB = 0, count = 0;
                for (let dy = -r; dy <= r; dy++) {
                    for (let dx = -r; dx <= r; dx++) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                            const dist = Math.sqrt(dx * dx + dy * dy);
                            if (dist <= radius) {
                                const weight = 1 - dist / radius;
                                const ni = (ny * w + nx) * 4;
                                sumR += sd[ni] * weight;
                                sumG += sd[ni + 1] * weight;
                                sumB += sd[ni + 2] * weight;
                                count += weight;
                            }
                        }
                    }
                }
                const i = (y * w + x) * 4;
                if (count > 0) {
                    dd[i] = Math.min(255, sumR / count * brightness);
                    dd[i + 1] = Math.min(255, sumG / count * brightness);
                    dd[i + 2] = Math.min(255, sumB / count * brightness);
                } else {
                    dd[i] = sd[i]; dd[i + 1] = sd[i + 1]; dd[i + 2] = sd[i + 2];
                }
                dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- F. Adjustable Vignette ---
    function applyVignette(ctx, intensity, color, feather) {
        intensity = intensity || 0.4;
        color = color || '#000000';
        feather = feather || 0.3;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const cx = w / 2, cy = h / 2;
        const maxDist = Math.sqrt(cx * cx + cy * cy);
        const rgb = hexToRgb(color);
        ctx.save();
        const gradient = ctx.createRadialGradient(cx, cy, maxDist * (1 - feather), cx, cy, maxDist);
        gradient.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},0)`);
        gradient.addColorStop(1, `rgba(${rgb.r},${rgb.g},${rgb.b},${intensity})`);
        ctx.fillStyle = gradient;
        ctx.fillRect(0, 0, w, h);
        ctx.restore();
    }

    // --- G. Film Grain ---
    function applyFilmGrain(ctx, intensity, size) {
        intensity = intensity || 0.1;
        size = size || 2;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        for (let y = 0; y < h; y += size) {
            for (let x = 0; x < w; x += size) {
                const grain = (Math.random() - 0.5) * 255 * intensity;
                for (let dy = 0; dy < size && y + dy < h; dy++) {
                    for (let dx = 0; dx < size && x + dx < w; dx++) {
                        const i = ((y + dy) * w + (x + dx)) * 4;
                        sd[i] = Math.max(0, Math.min(255, sd[i] + grain));
                        sd[i + 1] = Math.max(0, Math.min(255, sd[i + 1] + grain));
                        sd[i + 2] = Math.max(0, Math.min(255, sd[i + 2] + grain));
                    }
                }
            }
        }
        ctx.putImageData(src, 0, 0);
    }

    // --- H. HDR Effect ---
    function applyHDREffect(ctx, strength) {
        strength = strength || 0.5;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        let minR = 255, maxR = 0, minG = 255, maxG = 0, minB = 255, maxB = 0;
        for (let i = 0; i < sd.length; i += 4) {
            if (sd[i] < minR) minR = sd[i]; if (sd[i] > maxR) maxR = sd[i];
            if (sd[i + 1] < minG) minG = sd[i + 1]; if (sd[i + 1] > maxG) maxG = sd[i + 1];
            if (sd[i + 2] < minB) minB = sd[i + 2]; if (sd[i + 2] > maxB) maxB = sd[i + 2];
        }
        const rangeR = maxR - minR || 1, rangeG = maxG - minG || 1, rangeB = maxB - minB || 1;
        for (let i = 0; i < sd.length; i += 4) {
            const tR = ((sd[i] - minR) / rangeR - 0.5) * strength;
            const tG = ((sd[i + 1] - minG) / rangeG - 0.5) * strength;
            const tB = ((sd[i + 2] - minB) / rangeB - 0.5) * strength;
            sd[i] = Math.max(0, Math.min(255, sd[i] + tR * 128));
            sd[i + 1] = Math.max(0, Math.min(255, sd[i + 1] + tG * 128));
            sd[i + 2] = Math.max(0, Math.min(255, sd[i + 2] + tB * 128));
        }
        ctx.putImageData(src, 0, 0);
    }

    // --- I. Glitch Art ---
    function applyGlitchArt(ctx, intensity) {
        intensity = intensity || 0.3;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        dd.set(sd);
        const slices = Math.floor(5 + Math.random() * 10);
        for (let s = 0; s < slices; s++) {
            const sliceY = Math.floor(Math.random() * h);
            const sliceH = Math.floor(Math.random() * h * 0.1) + 1;
            const offset = Math.floor((Math.random() - 0.5) * w * intensity);
            for (let y = sliceY; y < Math.min(h, sliceY + sliceH); y++) {
                for (let x = 0; x < w; x++) {
                    const srcX = (x + offset + w) % w;
                    const srcI = (y * w + srcX) * 4;
                    const dstI = (y * w + x) * 4;
                    dd[dstI] = sd[srcI];
                    dd[dstI + 1] = sd[srcI + 1];
                    dd[dstI + 2] = sd[srcI + 2];
                }
            }
        }
        if (Math.random() < intensity) {
            const channel = Math.floor(Math.random() * 3);
            const shift = Math.floor((Math.random() - 0.5) * 20);
            for (let y = 0; y < h; y++) {
                for (let x = 0; x < w; x++) {
                    const srcX = (x + shift + w) % w;
                    const srcI = (y * w + srcX) * 4;
                    const dstI = (y * w + x) * 4;
                    dd[dstI + channel] = sd[srcI + channel];
                }
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- J. Paper Textures ---
    function applyPaperTexture(ctx, type, opacity) {
        type = type || 'grain';
        opacity = opacity || 0.1;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const paper = generatePaperTexture(type, w, h);
        ctx.save();
        ctx.globalAlpha = opacity;
        ctx.globalCompositeOperation = 'overlay';
        ctx.drawImage(paper, 0, 0);
        ctx.restore();
    }

    // --- K. Decorative Patterns ---
    function applyDecorativePattern(ctx, type, size, opacity) {
        type = type || 'dots';
        size = size || 10;
        opacity = opacity || 0.1;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        ctx.save();
        ctx.globalAlpha = opacity;
        ctx.fillStyle = brushColor;
        if (type === 'dots') {
            for (let y = 0; y < h; y += size) {
                for (let x = 0; x < w; x += size) {
                    ctx.beginPath();
                    ctx.arc(x, y, size / 4, 0, Math.PI * 2);
                    ctx.fill();
                }
            }
        } else if (type === 'lines') {
            ctx.lineWidth = 1;
            ctx.strokeStyle = brushColor;
            for (let y = 0; y < h; y += size) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(w, y);
                ctx.stroke();
            }
        } else if (type === 'grid') {
            ctx.lineWidth = 1;
            ctx.strokeStyle = brushColor;
            for (let y = 0; y < h; y += size) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(w, y);
                ctx.stroke();
            }
            for (let x = 0; x < w; x += size) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, h);
                ctx.stroke();
            }
        } else if (type === 'diagonal') {
            ctx.lineWidth = 1;
            ctx.strokeStyle = brushColor;
            for (let d = -h; d < w + h; d += size) {
                ctx.beginPath();
                ctx.moveTo(d, 0);
                ctx.lineTo(d + h, h);
                ctx.stroke();
            }
        }
        ctx.restore();
    }

    // --- L. Custom Brush Textures ---
    function generateBrushTexture(type) {
        const size = 64;
        const c = document.createElement('canvas');
        c.width = size; c.height = size;
        const ctx = c.getContext('2d');
        const imgData = ctx.createImageData(size, size);
        const d = imgData.data;
        for (let y = 0; y < size; y++) {
            for (let x = 0; x < size; x++) {
                const i = (y * size + x) * 4;
                const cx = x - size / 2, cy = y - size / 2;
                const dist = Math.sqrt(cx * cx + cy * cy);
                if (type === 'spray') {
                    d[i + 3] = Math.random() < (1 - dist / (size / 2)) ? 255 : 0;
                } else if (type === 'stipple') {
                    d[i + 3] = Math.random() > 0.5 ? 255 : 0;
                } else if (type === 'hash') {
                    d[i + 3] = ((x + y) % 4 < 2) ? 255 : 0;
                } else if (type === 'cross') {
                    d[i + 3] = ((x % 4 < 2) || (y % 4 < 2)) ? 255 : 0;
                }
                d[i] = d[i + 1] = d[i + 2] = 255;
            }
        }
        ctx.putImageData(imgData, 0, 0);
        return c;
    }

    // --- M. Bump Map ---
    function applyBumpMap(ctx, height, angle) {
        height = height || 10;
        angle = angle || 45;
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const dst = ctx.createImageData(w, h);
        const sd = src.data, dd = dst.data;
        const rad = angle * Math.PI / 180;
        const dx = Math.cos(rad) * height;
        const dy = Math.sin(rad) * height;
        for (let y = 1; y < h - 1; y++) {
            for (let x = 1; x < w - 1; x++) {
                const i = (y * w + x) * 4;
                const left = ((y) * w + (x - 1)) * 4;
                const right = ((y) * w + (x + 1)) * 4;
                const top = ((y - 1) * w + x) * 4;
                const bottom = ((y + 1) * w + x) * 4;
                const heightL = (sd[left] + sd[left + 1] + sd[left + 2]) / 3;
                const heightR = (sd[right] + sd[right + 1] + sd[right + 2]) / 3;
                const heightT = (sd[top] + sd[top + 1] + sd[top + 2]) / 3;
                const heightB = (sd[bottom] + sd[bottom + 1] + sd[bottom + 2]) / 3;
                const nx = heightL - heightR;
                const ny = heightT - heightB;
                const nz = 2;
                const len = Math.sqrt(nx * nx + ny * ny + nz * nz);
                const lightX = Math.cos(rad), lightY = Math.sin(rad), lightZ = 0.5;
                const dot = (nx * lightX + ny * lightY + nz * lightZ) / len;
                const factor = Math.max(0, dot);
                dd[i] = Math.min(255, sd[i] * factor * 1.5);
                dd[i + 1] = Math.min(255, sd[i + 1] * factor * 1.5);
                dd[i + 2] = Math.min(255, sd[i + 2] * factor * 1.5);
                dd[i + 3] = sd[i + 3];
            }
        }
        ctx.putImageData(dst, 0, 0);
    }

    // --- N. Luminosity Masking ---
    function createLuminosityMask(layer, threshold, invert) {
        if (!layer) return;
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        const mask = new ImageData(w, h);
        const sd = src.data, md = mask.data;
        for (let i = 0; i < sd.length; i += 4) {
            const lum = sd[i] * 0.299 + sd[i + 1] * 0.587 + sd[i + 2] * 0.114;
            let selected = lum >= threshold[0] && lum <= threshold[1];
            if (invert) selected = !selected;
            md[i + 3] = selected ? 255 : 0;
        }
        mask.width = w; mask.height = h;
        return mask;
    }

    // --- O. Color Masking ---
    function createColorMask(layer, targetColor, tolerance) {
        if (!layer || !targetColor) return;
        const tc = hexToRgb(targetColor);
        const w = layer.canvas.width, h = layer.canvas.height;
        const src = layer.ctx.getImageData(0, 0, w, h);
        const mask = new ImageData(w, h);
        const sd = src.data, md = mask.data;
        for (let i = 0; i < sd.length; i += 4) {
            const dist = Math.sqrt((sd[i] - tc.r) ** 2 + (sd[i + 1] - tc.g) ** 2 + (sd[i + 2] - tc.b) ** 2);
            md[i + 3] = dist <= tolerance ? 255 : 0;
        }
        mask.width = w; mask.height = h;
        return mask;
    }

    // --- P. Advanced Blend Modes ---
    const advancedBlendModes = {
        'hard-mix': (a, b) => (a + b >= 255) ? 255 : 0,
        'pin-light': (a, b) => (b < 128) ? Math.min(a, 2 * b) : Math.max(a, 2 * (b - 128)),
        'vivid-light': (a, b) => (b < 128) ? a / (2 * (255 - b) / 255) : a + (2 * (b - 128)) * (255 - a) / 255,
        'linear-light': (a, b) => Math.max(0, Math.min(255, a + 2 * b - 255)),
        'darker-color': (a, b, a2, b2) => (a2 + b2) < (a + b) ? a2 : b,
        'lighter-color': (a, b, a2, b2) => (a2 + b2) > (a + b) ? a2 : b,
        'subtraction': (a, b) => Math.max(0, a - b),
        'division': (a, b) => (b === 0) ? 255 : Math.min(255, (a / b) * 255)
    };

    function applyAdvancedBlend(ctx, blendCanvas, mode) {
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const base = ctx.getImageData(0, 0, w, h);
        const blend = blendCanvas.getContext('2d').getImageData(0, 0, w, h);
        const bd = base.data, ld = blend.data;
        const blendFn = advancedBlendModes[mode];
        if (!blendFn) return;
        for (let i = 0; i < bd.length; i += 4) {
            bd[i] = blendFn(bd[i], ld[i], bd[i + 1], ld[i + 1]);
            bd[i + 1] = blendFn(bd[i + 1], ld[i + 1], bd[i], ld[i]);
            bd[i + 2] = blendFn(bd[i + 2], ld[i + 2], bd[i], ld[i]);
        }
        ctx.putImageData(base, 0, 0);
    }

    // --- Q. Curves Adjustment ---
    function applyCurvesAdjustment(ctx, points) {
        if (!points || points.length < 2) return;
        const lut = new Uint8Array(256);
        for (let i = 0; i < 256; i++) {
            let val = i;
            for (let j = 0; j < points.length - 1; j++) {
                if (i >= points[j].x && i <= points[j + 1].x) {
                    const t = (i - points[j].x) / (points[j + 1].x - points[j].x || 1);
                    val = points[j].y + (points[j + 1].y - points[j].y) * t;
                    break;
                }
            }
            lut[i] = Math.max(0, Math.min(255, val));
        }
        const w = ctx.canvas.width, h = ctx.canvas.height;
        const src = ctx.getImageData(0, 0, w, h);
        const sd = src.data;
        for (let i = 0; i < sd.length; i += 4) {
            sd[i] = lut[sd[i]];
            sd[i + 1] = lut[sd[i + 1]];
            sd[i + 2] = lut[sd[i + 2]];
        }
        ctx.putImageData(src, 0, 0);
    }

    function showCurvesModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;';
        const canvas = document.createElement('canvas');
        canvas.width = 200; canvas.height = 200;
        canvas.style.cssText = 'width:100%;border-radius:8px;border:1px solid var(--border-color);background:#1a1a1a;cursor:crosshair;';
        const ctx = canvas.getContext('2d');
        let curvePoints = [{ x: 0, y: 0 }, { x: 255, y: 255 }];

        function drawCurve() {
            ctx.clearRect(0, 0, 200, 200);
            ctx.strokeStyle = '#333'; ctx.lineWidth = 1;
            ctx.beginPath(); ctx.moveTo(0, 200); ctx.lineTo(200, 0); ctx.stroke();
            ctx.strokeStyle = '#fff'; ctx.lineWidth = 2;
            ctx.beginPath();
            curvePoints.forEach((p, i) => {
                const px = p.x / 255 * 200, py = 200 - p.y / 255 * 200;
                if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
            });
            ctx.stroke();
            curvePoints.forEach(p => {
                const px = p.x / 255 * 200, py = 200 - p.y / 255 * 200;
                ctx.fillStyle = '#fff';
                ctx.beginPath(); ctx.arc(px, py, 4, 0, Math.PI * 2); ctx.fill();
            });
        }
        drawCurve();

        canvas.addEventListener('click', (e) => {
            const rect = canvas.getBoundingClientRect();
            const x = Math.round((e.clientX - rect.left) / rect.width * 255);
            const y = Math.round(255 - (e.clientY - rect.top) / rect.height * 255);
            curvePoints.push({ x, y });
            curvePoints.sort((a, b) => a.x - b.x);
            drawCurve();
        });

        wrapper.appendChild(canvas);
        const info = document.createElement('div');
        info.style.cssText = 'font-size:9px;color:var(--text-secondary);';
        info.textContent = 'Haz clic para agregar puntos de curva.';
        wrapper.appendChild(info);

        showModal({
            title: 'Ajuste de Curvas',
            body: wrapper,
            buttons: [
                { label: 'Cancelar', value: false },
                {
                    label: 'Aplicar', class: 'primary', value: true, action: () => {
                        const layer = getActiveLayer();
                        if (layer) {
                            applyCurvesAdjustment(layer.ctx, curvePoints);
                            compositeDirty = true; renderComposite(); saveState();
                        }
                    }
                }
            ]
        });
    }

    // --- R. Batch Actions ---
    function showBatchActionsModal() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;max-height:60vh;overflow-y:auto;';

        const fileInput = document.createElement('input');
        fileInput.type = 'file'; fileInput.multiple = true; fileInput.accept = 'image/*';
        fileInput.style.cssText = 'display:none;';
        wrapper.appendChild(fileInput);

        const dropZone = document.createElement('div');
        dropZone.style.cssText = 'border:2px dashed var(--border-color);border-radius:10px;padding:20px;text-align:center;cursor:pointer;';
        dropZone.innerHTML = '<div style="font-size:10px;color:var(--text-secondary);">Arrastra imágenes para aplicar acciones en lote</div>';
        dropZone.addEventListener('click', () => fileInput.click());
        wrapper.appendChild(dropZone);

        const actionSelect = document.createElement('select');
        actionSelect.style.cssText = 'width:100%;background:var(--canvas-bg);color:var(--text-color);border:1px solid var(--border-color);border-radius:6px;padding:6px;font-size:10px;';
        ['Grayscale', 'Sepia', 'Invert', 'Blur', 'Sharpen', 'Brightness', 'Contrast', 'Vintage', 'Cinematic', 'Cool'].forEach(opt => {
            const option = document.createElement('option');
            option.value = opt.toLowerCase();
            option.textContent = opt;
            actionSelect.appendChild(option);
        });
        wrapper.appendChild(actionSelect);

        const progressDiv = document.createElement('div');
        progressDiv.style.cssText = 'font-size:9px;color:var(--text-secondary);min-height:14px;';
        wrapper.appendChild(progressDiv);

        let batchFiles = [];
        fileInput.addEventListener('change', () => { batchFiles = Array.from(fileInput.files); progressDiv.textContent = `${batchFiles.length} archivos seleccionados`; });

        showModal({
            title: 'Acciones por Lotes',
            body: wrapper,
            buttons: [
                { label: 'Cancelar', value: false },
                {
                    label: 'Ejecutar', class: 'primary', value: true, action: async () => {
                        if (batchFiles.length === 0) { showToast('Selecciona archivos'); return; }
                        const action = actionSelect.value;
                        for (let i = 0; i < batchFiles.length; i++) {
                            progressDiv.textContent = `Procesando ${i + 1}/${batchFiles.length}...`;
                            const file = batchFiles[i];
                            const img = new Image();
                            await new Promise(resolve => {
                                img.onload = () => {
                                    const c = document.createElement('canvas');
                                    c.width = img.width; c.height = img.height;
                                    const ctx = c.getContext('2d');
                                    ctx.drawImage(img, 0, 0);
                                    applyBatchAction(ctx, action);
                                    c.toBlob(blob => {
                                        const url = URL.createObjectURL(blob);
                                        const a = document.createElement('a');
                                        a.href = url; a.download = `${file.name.replace(/\.[^.]+$/, '')}-${action}.png`;
                                        a.click(); URL.revokeObjectURL(url); resolve();
                                    }, 'image/png');
                                };
                                img.src = URL.createObjectURL(file);
                            });
                            await new Promise(r => setTimeout(r, 50));
                        }
                        showToast(`${batchFiles.length} archivos procesados`);
                    }
                }
            ]
        });

        function applyBatchAction(ctx, action) {
            const w = ctx.canvas.width, h = ctx.canvas.height;
            const src = ctx.getImageData(0, 0, w, h);
            const d = src.data;
            if (action === 'grayscale') {
                for (let i = 0; i < d.length; i += 4) {
                    const g = d[i] * 0.3 + d[i + 1] * 0.59 + d[i + 2] * 0.11;
                    d[i] = d[i + 1] = d[i + 2] = g;
                }
            } else if (action === 'sepia') {
                for (let i = 0; i < d.length; i += 4) {
                    const r = d[i], g = d[i + 1], b = d[i + 2];
                    d[i] = Math.min(255, r * 0.393 + g * 0.769 + b * 0.189);
                    d[i + 1] = Math.min(255, r * 0.349 + g * 0.686 + b * 0.168);
                    d[i + 2] = Math.min(255, r * 0.272 + g * 0.534 + b * 0.131);
                }
            } else if (action === 'invert') {
                for (let i = 0; i < d.length; i += 4) { d[i] = 255 - d[i]; d[i + 1] = 255 - d[i + 1]; d[i + 2] = 255 - d[i + 2]; }
            } else if (action === 'vintage') {
                for (let i = 0; i < d.length; i += 4) {
                    d[i] = Math.min(255, d[i] * 1.1 + 10);
                    d[i + 1] = Math.min(255, d[i + 1] * 0.95);
                    d[i + 2] = Math.min(255, d[i + 2] * 0.85);
                }
            } else if (action === 'cinematic') {
                for (let i = 0; i < d.length; i += 4) {
                    d[i] = d[i] * 0.9; d[i + 1] = d[i + 1] * 0.95; d[i + 2] = Math.min(255, d[i + 2] * 1.1);
                }
            } else if (action === 'cool') {
                for (let i = 0; i < d.length; i += 4) {
                    d[i] = d[i] * 0.85; d[i + 1] = d[i + 1] * 0.95; d[i + 2] = Math.min(255, d[i + 2] * 1.15);
                }
            }
            ctx.putImageData(src, 0, 0);
        }
    }

    // --- S. Custom Scripts ---
    function showScriptEditor() {
        const wrapper = document.createElement('div');
        wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;';
        const textarea = document.createElement('textarea');
        textarea.style.cssText = 'width:100%;height:200px;background:var(--canvas-bg);color:var(--text-color);border:1px solid var(--border-color);border-radius:6px;padding:8px;font-family:monospace;font-size:11px;resize:vertical;';
        textarea.value = `// Script personalizado\n// Variables disponibles: ctx, layer, w, h, dpr\n// Ejemplo: invertir colores\nconst src = ctx.getImageData(0, 0, w, h);\nconst d = src.data;\nfor (let i = 0; i < d.length; i += 4) {\n  d[i] = 255 - d[i];\n  d[i+1] = 255 - d[i+1];\n  d[i+2] = 255 - d[i+2];\n}\nctx.putImageData(src, 0, 0);`;
        wrapper.appendChild(textarea);
        const info = document.createElement('div');
        info.style.cssText = 'font-size:9px;color:var(--text-secondary);line-height:1.5;';
        info.innerHTML = 'Variables: <code>ctx</code>, <code>layer</code>, <code>w</code>, <code>h</code>, <code>dpr</code>, <code>brushColor</code>, <code>brushSize</code>';
        wrapper.appendChild(info);

        const savedScripts = JSON.parse(localStorage.getItem('procreate-lite-scripts') || '[]');
        const scriptList = document.createElement('div');
        scriptList.style.cssText = 'display:flex;flex-direction:column;gap:4px;max-height:100px;overflow-y:auto;';
        function renderScripts() {
            scriptList.innerHTML = '';
            savedScripts.forEach((script, i) => {
                const row = document.createElement('div');
                row.style.cssText = 'display:flex;align-items:center;gap:4px;font-size:9px;';
                const name = document.createElement('span');
                name.style.cssText = 'flex:1;color:var(--text-secondary);';
                name.textContent = script.name;
                row.appendChild(name);
                const runBtn = document.createElement('button');
                runBtn.className = 'tool-btn small';
                runBtn.innerHTML = '<i class="ri-play-fill"></i>';
                runBtn.onclick = () => { textarea.value = script.code; };
                row.appendChild(runBtn);
                const delBtn = document.createElement('button');
                delBtn.className = 'tool-btn small';
                delBtn.innerHTML = '<i class="ri-delete-bin-line"></i>';
                delBtn.onclick = () => { savedScripts.splice(i, 1); localStorage.setItem('procreate-lite-scripts', JSON.stringify(savedScripts)); renderScripts(); };
                row.appendChild(delBtn);
                scriptList.appendChild(row);
            });
        }
        renderScripts();
        wrapper.appendChild(scriptList);

        showModal({
            title: 'Editor de Scripts',
            body: wrapper,
            buttons: [
                {
                    label: 'Guardar', value: 'save', action: async () => {
                        const name = await showPrompt('Script', 'Nombre:', `Script ${savedScripts.length + 1}`);
                        if (name) { savedScripts.push({ name, code: textarea.value }); localStorage.setItem('procreate-lite-scripts', JSON.stringify(savedScripts)); renderScripts(); }
                    }
                },
                {
                    label: 'Ejecutar', class: 'primary', value: 'run', action: () => {
                        const layer = getActiveLayer();
                        if (!layer) { showToast('No hay capa activa'); return; }
                        try {
                            const ctx = layer.ctx;
                            const w = layer.canvas.width, h = layer.canvas.height;
                            const dprLocal = dpr;
                            eval(textarea.value);
                            compositeDirty = true; renderComposite(); saveState();
                            showToast('Script ejecutado');
                        } catch (e) { showToast('Error: ' + e.message); }
                    }
                },
                { label: 'Cerrar', value: null }
            ]
        });
    }

