    // --- U. Low-Resolution Preview Canvas ---
    let lowResPreviewEnabled = false;
    let lowResScale = 0.25;
    let lowResCanvas = null;

    function createLowResPreview() {
        if (lowResCanvas) lowResCanvas.remove();
        lowResCanvas = document.createElement('canvas');
        lowResCanvas.style.cssText = 'position:fixed;bottom:10px;right:10px;border:1px solid var(--border-color);border-radius:6px;z-index:9999;background:#1a1a1a;';
        lowResCanvas.width = Math.floor(logicalWidth * lowResScale);
        lowResCanvas.height = Math.floor(logicalHeight * lowResScale);
        document.body.appendChild(lowResCanvas);
        updateLowResPreview();
    }

    function updateLowResPreview() {
        if (!lowResCanvas || !lowResPreviewEnabled) return;
        const ctx = lowResCanvas.getContext('2d');
        ctx.clearRect(0, 0, lowResCanvas.width, lowResCanvas.height);
        ctx.drawImage(compositeCanvas, 0, 0, lowResCanvas.width, lowResCanvas.height);
    }

    function toggleLowResPreview() {
        lowResPreviewEnabled = !lowResPreviewEnabled;
        if (lowResPreviewEnabled) {
            createLowResPreview();
            showToast('Preview de baja resolución activado');
        } else {
            if (lowResCanvas) { lowResCanvas.remove(); lowResCanvas = null; }
            showToast('Preview de baja resolución desactivado');
        }
    }

    // --- V. Progressive Rendering ---
    let progressiveRenderEnabled = false;
    let progressiveChunkSize = 256;

    function progressiveRender(ctx, w, h, renderFn) {
        if (!progressiveRenderEnabled) { renderFn(ctx, 0, 0, w, h); return; }
        let y = 0;
        function renderChunk() {
            const chunkH = Math.min(progressiveChunkSize, h - y);
            if (chunkH <= 0) return;
            renderFn(ctx, 0, y, w, chunkH);
            y += chunkH;
            if (y < h) requestAnimationFrame(renderChunk);
        }
        renderChunk();
    }

    // --- W. Memory Optimization ---
    function optimizeLayerMemory() {
        let saved = 0;
        layers.forEach((layer, i) => {
            if (i === activeLayerIndex) return;
            const ctx = layer.ctx;
            const data = ctx.getImageData(0, 0, layer.canvas.width, layer.canvas.height);
            let transparentRows = 0;
            for (let y = 0; y < layer.canvas.height; y++) {
                let allTransparent = true;
                for (let x = 0; x < layer.canvas.width; x++) {
                    if (data.data[(y * layer.canvas.width + x) * 4 + 3] > 0) { allTransparent = false; break; }
                }
                if (allTransparent) transparentRows++;
            }
            saved += transparentRows * layer.canvas.width * 4;
        });
        showToast(`Optimización de memoria completada`);
    }

