// Hook text-on-path into pointer events
      let textOnPathIsDrawing = false;
      canvasContainer.addEventListener('pointerdown', (e) => {
          if (textOnPathMode && e.target === canvasContainer) {
              textOnPathIsDrawing = true;
              const pos = getCanvasPos(e);
              textOnPathPoints = [{ x: pos.x, y: pos.y }];
              drawTextPathPreview();
              e.preventDefault();
              e.stopPropagation();
          }
      });

      canvasContainer.addEventListener('pointermove', (e) => {
          if (textOnPathMode && textOnPathIsDrawing) {
              const pos = getCanvasPos(e);
              const last = textOnPathPoints[textOnPathPoints.length - 1];
              if (Math.hypot(pos.x - last.x, pos.y - last.y) > 3) {
                  textOnPathPoints.push({ x: pos.x, y: pos.y });
                  drawTextPathPreview();
              }
              e.preventDefault();
              e.stopPropagation();
          }
      });

      canvasContainer.addEventListener('pointerup', (e) => {
          if (textOnPathMode && textOnPathIsDrawing && textOnPathPoints.length >= 2) {
              textOnPathIsDrawing = false;
              const text = prompt('Texto en curva', 'Hola Mundo');
              if (text) {
                  const layer = getActiveLayer();
                  if (layer) {
                      layer.ctx.save();
                      layer.ctx.setTransform(1, 0, 0, 1, 0, 0);
                      drawTextOnPath(layer.ctx, text, textOnPathPoints);
                      layer.ctx.restore();
                  }
              }
              textOnPathMode = false;
              textOnPathPoints = [];
              hideTextOnPathPreview();
              compositeDirty = true;
              renderComposite();
              saveState();
          }
      });

      // Cancel text-on-path with Escape or clicking outside
      document.addEventListener('keydown', (e) => {
          if (e.key === 'Escape' && textOnPathMode) {
              textOnPathMode = false;
              textOnPathIsDrawing = false;
              textOnPathPoints = [];
              hideTextOnPathPreview();
              showToast('Cancelado');
          }
      });

